#include "utils/numeric.h"

PG_FUNCTION_INFO_V1(numeric_fac);

Datum
numeric_fac(PG_FUNCTION_ARGS)
{
    int32       arg = PG_GETARG_INT32(0);
    Numeric     result;
    Numeric     factor;
    int         i;

    if (arg < 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_ARGUMENT_FOR_POWER_FUNCTION),
                 errmsg("factorial of a negative number is not defined")));

    if (arg == 0 || arg == 1)
        PG_RETURN_NUMERIC(int64_to_numeric(1));

    result = int64_to_numeric(1);
    for (i = 2; i <= arg; i++)
    {
        factor = int64_to_numeric(i);
        result = DatumGetNumeric(DirectFunctionCall2(numeric_mul,
                                                    NumericGetDatum(result),
                                                    NumericGetDatum(factor)));
    }

    PG_RETURN_NUMERIC(result);
}

