PG_FUNCTION_INFO_V1(gcd_int);

Datum
gcd_int(PG_FUNCTION_ARGS)
{
    int32 arg1 = PG_GETARG_INT32(0);
    int32 arg2 = PG_GETARG_INT32(1);

    if (arg1 == 0 && arg2 == 0)
        PG_RETURN_INT32(0);

    while (arg2 != 0)
    {
        int32 temp = arg2;
        arg2 = arg1 % arg2;
        arg1 = temp;
    }

    PG_RETURN_INT32(abs(arg1));
}

