Datum
lcm(PG_FUNCTION_ARGS)
{
    Datum        arg1 = PG_GETARG_DATUM(0);
    Datum        arg2 = PG_GETARG_DATUM(1);
    Oid            arg1_type = get_fn_expr_argtype(fcinfo->flinfo, 0);
    Oid            arg2_type = get_fn_expr_argtype(fcinfo->flinfo, 1);

    if (arg1_type == INT4OID && arg2_type == INT4OID)
    {
        int32        a = DatumGetInt32(arg1);
        int32        b = DatumGetInt32(arg2);

        if (a == 0 || b == 0)
            PG_RETURN_INT32(0);

        /* handle negative inputs by working with absolute values */
        a = Abs(a);
        b = Abs(b);

        /* avoid overflow by dividing first */
        int32        gcd_val = DatumGetInt32(DirectFunctionCall2(gcd, Int32GetDatum(a), Int32GetDatum(b)));
        int32        lcm_val = (a / gcd_val) * b;

        PG_RETURN_INT32(lcm_val);
    }
    else if (arg1_type == INT8OID && arg2_type == INT8OID)
    {
        int64        a = DatumGetInt64(arg1);
        int64        b = DatumGetInt64(arg2);

        if (a == 0 || b == 0)
            PG_RETURN_INT64(0);

        /* handle negative inputs by working with absolute values */
        a = Abs(a);
        b = Abs(b);

        /* avoid overflow by dividing first */
        int64        gcd_val = DatumGetInt64(DirectFunctionCall2(gcd, Int64GetDatum(a), Int64GetDatum(b)));
        int64        lcm_val = (a / gcd_val) * b;

        PG_RETURN_INT64(lcm_val);
    }
    else if (arg1_type == NUMERICOID && arg2_type == NUMERICOID)
    {
        Numeric        num1 = DatumGetNumeric(arg1);
        Numeric        num2 = DatumGetNumeric(arg2);
        Numeric        zero = DatumGetNumeric(DirectFunctionCall1(int4_numeric, Int32GetDatum(0)));
        Numeric        gcd_val;
        Numeric        lcm_val;

        if (DatumGetBool(DirectFunctionCall2(numeric_eq, NumericGetDatum(num1), NumericGetDatum(zero))) ||
            DatumGetBool(DirectFunctionCall2(numeric_eq, NumericGetDatum(num2), NumericGetDatum(zero))))
            PG_RETURN_NUMERIC(zero);

        /* handle negative inputs by working with absolute values */
        num1 = DatumGetNumeric(DirectFunctionCall1(numeric_abs, NumericGetDatum(num1)));
        num2 = DatumGetNumeric(DirectFunctionCall1(numeric_abs, NumericGetDatum(num2)));

        gcd_val = DatumGetNumeric(DirectFunctionCall2(numeric_gcd, NumericGetDatum(num1), NumericGetDatum(num2)));
        lcm_val = DatumGetNumeric(DirectFunctionCall2(numeric_div, NumericGetDatum(num1), NumericGetDatum(gcd_val)));
        lcm_val = DatumGetNumeric(DirectFunctionCall2(numeric_mul, NumericGetDatum(lcm_val), NumericGetDatum(num2)));

        PG_RETURN_NUMERIC(lcm_val);
    }
    else
    {
        ereport(ERROR,
                (errcode(ERRCODE_DATATYPE_MISMATCH),
                 errmsg("function lcm does not support input types %s and %s",
                        format_type_be(arg1_type), format_type_be(arg2_type))));
        PG_RETURN_NULL();
    }
}

