Datum
min_scale(PG_FUNCTION_ARGS)
{
    Numeric num = PG_GETARG_NUMERIC(0);
    int16 dscale;
    int16 typmod;
    int16 min_scale;

    /* Get the display scale of the numeric value */
    dscale = NUMERIC_DSCALE(num);

    /* Get the typmod (if any) to determine declared scale */
    typmod = NUMERIC_TYPMOD(num);

    /* Calculate minimum scale needed */
    if (NUMERIC_IS_NAN(num))
        PG_RETURN_NULL();

    if (NUMERIC_IS_POSINF(num) || NUMERIC_IS_NEGINF(num))
        PG_RETURN_NULL();

    /* Count trailing zeros in the fractional part */
    min_scale = 0;
    if (dscale > 0)
    {
        NumericDigit *digits = NUMERIC_DIGITS(num);
        int ndigits = NUMERIC_NDIGITS(num);
        int weight = NUMERIC_WEIGHT(num);
        int i;

        /* Start from the last digit in the fractional part */
        for (i = ndigits - 1; i >= 0 && min_scale < dscale; i--)
        {
            NumericDigit d = digits[i];
            int j;

            /* For digits in the fractional part */
            if (i <= weight)
                break;

            /* Check each digit in the NumericDigit */
            for (j = 0; j < DEC_DIGITS && min_scale < dscale; j++)
            {
                if (d % 10 != 0)
                    break;
                d /= 10;
                min_scale++;
            }
        }

        min_scale = dscale - min_scale;
    }

    PG_RETURN_INT16(min_scale);
}

