Datum
dpow(PG_FUNCTION_ARGS)
{
    Numeric num1 = PG_GETARG_NUMERIC(0);
    Numeric num2 = PG_GETARG_NUMERIC(1);
    Numeric res;
    int cmp;

    /* Check if the exponent is zero */
    cmp = cmp_var(NUMERIC_DIGITS(num2), NUMERIC_NDIGITS(num2), NUMERIC_DIGITS(&const_zero), NUMERIC_NDIGITS(&const_zero));
    if (cmp == 0)
    {
        res = make_result(&const_one);
        PG_RETURN_NUMERIC(res);
    }

    /* Check if the base is zero */
    cmp = cmp_var(NUMERIC_DIGITS(num1), NUMERIC_NDIGITS(num1), NUMERIC_DIGITS(&const_zero), NUMERIC_NDIGITS(&const_zero));
    if (cmp == 0)
    {
        res = make_result(&const_zero);
        PG_RETURN_NUMERIC(res);
    }

    /* Check if the exponent is one */
    cmp = cmp_var(NUMERIC_DIGITS(num2), NUMERIC_NDIGITS(num2), NUMERIC_DIGITS(&const_one), NUMERIC_NDIGITS(&const_one));
    if (cmp == 0)
    {
        res = numeric_dup(num1);
        PG_RETURN_NUMERIC(res);
    }

    /* Check if the base is one */
    cmp = cmp_var(NUMERIC_DIGITS(num1), NUMERIC_NDIGITS(num1), NUMERIC_DIGITS(&const_one), NUMERIC_NDIGITS(&const_one));
    if (cmp == 0)
    {
        res = numeric_dup(num1);
        PG_RETURN_NUMERIC(res);
    }

    /* Handle negative exponents */
    if (NUMERIC_SIGN(num2) == NUMERIC_NEG)
    {
        Numeric abs_num2 = numeric_abs(num2);
        res = numeric_power_internal(num1, abs_num2);
        res = numeric_div(&const_one, res);
        PG_RETURN_NUMERIC(res);
    }

    res = numeric_power_internal(num1, num2);
    PG_RETURN_NUMERIC(res);
}

