static Numeric
numeric_power_internal(Numeric num1, Numeric num2)
{
    Numeric res;
    Numeric ln_num1;
    Numeric product;

    /* Compute natural logarithm of num1 */
    ln_num1 = numeric_ln(num1);

    /* Multiply by num2 */
    product = numeric_mul(ln_num1, num2);

    /* Compute e^product */
    res = numeric_exp(product);

    return res;
}

