Datum
width_bucket_float8(PG_FUNCTION_ARGS)
{
    float8 operand = PG_GETARG_FLOAT8(0);
    float8 low = PG_GETARG_FLOAT8(1);
    float8 high = PG_GETARG_FLOAT8(2);
    int32 count = PG_GETARG_INT32(3);
    int32 result;

    if (count <= 0)
        PG_RETURN_INT32(0);

    if (high == low)
        PG_RETURN_INT32(0);

    if (operand < low)
        PG_RETURN_INT32(0);

    if (operand >= high)
        PG_RETURN_INT32(count + 1);

    result = (int32) ((operand - low) * count / (high - low)) + 1;

    PG_RETURN_INT32(result);
}

Datum
width_bucket_array(PG_FUNCTION_ARGS)
{
    Datum operand = PG_GETARG_DATUM(0);
    ArrayType *thresholds = PG_GETARG_ARRAYTYPE_P(1);
    Oid elemtype = ARR_ELEMTYPE(thresholds);
    int16 typlen;
    bool typbyval;
    char typalign;
    Datum *elems;
    bool *nulls;
    int nelems;
    int result = 0;

    get_typlenbyvalalign(elemtype, &typlen, &typbyval, &typalign);
    deconstruct_array(thresholds, elemtype, typlen, typbyval, typalign,
                     &elems, &nulls, &nelems);

    /* Check for NULL elements in array */
    for (int i = 0; i < nelems; i++)
    {
        if (nulls[i])
            ereport(ERROR,
                    (errcode(ERRCODE_NULL_VALUE_NOT_ALLOWED),
                    errmsg("array must not contain nulls"));
    }

    /* Binary search to find the right bucket */
    if (nelems > 0)
    {
        int low = 0;
        int high = nelems - 1;
        int mid;
        int cmp;

        /* First check if operand is below first threshold */
        cmp = DatumGetInt32(DirectFunctionCall2(btcmp, operand, elems[0]));
        if (cmp < 0)
            PG_RETURN_INT32(0);

        /* Then check if operand is above last threshold */
        cmp = DatumGetInt32(DirectFunctionCall2(btcmp, operand, elems[high]));
        if (cmp >= 0)
            PG_RETURN_INT32(nelems + 1);

        /* Binary search to find the right bucket */
        while (low <= high)
        {
            mid = (low + high) / 2;
            cmp = DatumGetInt32(DirectFunctionCall2(btcmp, operand, elems[mid]));

            if (cmp < 0)
                high = mid - 1;
            else if (cmp > 0)
                low = mid + 1;
            else
            {
                result = mid + 1;
                break;
            }
        }

        if (result == 0)
            result = low + 1;
    }

    PG_RETURN_INT32(result);
}

Datum
width_bucket_numeric(PG_FUNCTION_ARGS)
{
    Numeric operand = PG_GETARG_NUMERIC(0);
    Numeric low = PG_GETARG_NUMERIC(1);
    Numeric high = PG_GETARG_NUMERIC(2);
    int32 count = PG_GETARG_INT32(3);
    int32 result;
    Numeric width;
    Numeric diff;
    Numeric val;

    if (count <= 0)
        PG_RETURN_INT32(0);

    if (numeric_eq(high, low))
        PG_RETURN_INT32(0);

    if (numeric_lt(operand, low))
        PG_RETURN_INT32(0);

    if (numeric_ge(operand, high))
        PG_RETURN_INT32(count + 1);

    diff = numeric_sub(high, low);
    width = numeric_div(diff, Int32GetDatum(count));
    val = numeric_sub(operand, low);
    result = DatumGetInt32(DirectFunctionCall2(numeric_div,
                                              NumericGetDatum(val),
                                              NumericGetDatum(width)));
    result += 1;

    PG_RETURN_INT32(result);
}

