PG_FUNCTION_INFO_V1(drandom);

Datum
drandom(PG_FUNCTION_ARGS)
{
    if (PG_NARGS() == 0)
    {
        PG_RETURN_FLOAT8(pg_erand48(random()));
    }
    else if (PG_NARGS() == 2)
    {
        Datum min = PG_GETARG_DATUM(0);
        Datum max = PG_GETARG_DATUM(1);

        if (numeric_is_nan(DatumGetNumeric(min)) || numeric_is_nan(DatumGetNumeric(max)))
            PG_RETURN_NUMERIC(make_result(&const_nan));

        double min_val = DatumGetFloat8(min);
        double max_val = DatumGetFloat8(max);
        double rand_val = min_val + (max_val - min_val) * pg_erand48(random());

        PG_RETURN_FLOAT8(rand_val);
    }
    else
    {
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid number of arguments")));
        PG_RETURN_NULL();
    }
}

