               *bytesremovedptr;

    bytesptr = VARDATA_ANY(bytes);
    byteslen = VARSIZE_ANY_EXHDR(bytes);
    bytesremovedptr = VARDATA_ANY(bytesremoved);
    bytesremovedlen = VARSIZE_ANY_EXHDR(bytesremoved);

    if (byteslen == 0)
        PG_RETURN_BYTEA_P(bytes);

    start = 0;
    while (start < byteslen)
    {
        match = false;
        for (i = 0; i < bytesremovedlen; i++)
        {
            if (bytesptr[start] == bytesremovedptr[i])
            {
                match = true;
                break;
            }
        }
        if (!match)
            break;
        start++;
    }

    end = byteslen - 1;
    while (end >= start)
    {
        match = false;
        for (i = 0; i < bytesremovedlen; i++)
        {
            if (bytesptr[end] == bytesremovedptr[i])
            {
                match = true;
                break;
            }
        }
        if (!match)
            break;
        end--;
    }

    PG_RETURN_BYTEA_P(datumCopy(bytes, false, end - start + 1 + VARHDRSZ));
