#include "postgres.h"
#include "utils/builtins.h"
#include "mb/pg_wchar.h"

PG_FUNCTION_INFO_V1(lpad);

Datum
lpad(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    int32       len = PG_GETARG_INT32(1);
    text       *fill = PG_GETARG_TEXT_PP(2);
    text       *result;
    char       *ptr,
               *rptr;
    int         slen,
                flen,
                bytelen,
                fillbytelen,
                i,
                nfill;
    bool        is_multibyte = false;

    /* Handle NULL cases */
    if (len < 0)
        PG_RETURN_NULL();

    slen = VARSIZE_ANY_EXHDR(str);
    flen = VARSIZE_ANY_EXHDR(fill);

    /* If input string is already longer than requested length, truncate it */
    if (slen >= len)
    {
        result = (text *) palloc(VARHDRSZ + len);
        SET_VARSIZE(result, VARHDRSZ + len);
        memcpy(VARDATA(result), VARDATA_ANY(str), len);
        PG_RETURN_TEXT_P(result);
    }

    /* Check if we're dealing with a multibyte encoding */
    if (pg_database_encoding_max_length() > 1)
    {
        int            str_charlen = pg_mbstrlen_with_len(VARDATA_ANY(str), slen);
        int            fill_charlen = pg_mbstrlen_with_len(VARDATA_ANY(fill), flen);

        if (str_charlen < 0 || fill_charlen < 0)
            ereport(ERROR,
                    (errcode(ERRCODE_CHARACTER_NOT_IN_REPERTOIRE),
                    errmsg("invalid multibyte character in input"));

        if (str_charlen > len)
        {
            result = (text *) palloc(VARHDRSZ + len);
            SET_VARSIZE(result, VARHDRSZ + len);
            memcpy(VARDATA(result), VARDATA_ANY(str), len);
            PG_RETURN_TEXT_P(result);
        }

        is_multibyte = true;
    }

    /* Calculate how many fill characters we need */
    nfill = len - slen;
    if (nfill <= 0)
        PG_RETURN_TEXT_P(text_copy(str));

    /* Allocate result string */
    bytelen = slen + nfill;
    result = (text *) palloc(VARHDRSZ + bytelen);
    SET_VARSIZE(result, VARHDRSZ + bytelen);
    rptr = VARDATA(result);

    /* Fill with the fill pattern */
    ptr = VARDATA_ANY(fill);
    fillbytelen = flen;
    for (i = 0; i < nfill; i += fillbytelen)
    {
        int            chunk = Min(fillbytelen, nfill - i);
        memcpy(rptr + i, ptr, chunk);
    }

    /* Append the original string */
    memcpy(rptr + nfill, VARDATA_ANY(str), slen);

    PG_RETURN_TEXT_P(result);
}

