/*
 * byteaoverlay - overlay specified bits of a bytea with new bits
 */
Datum
byteaoverlay(PG_FUNCTION_ARGS)
{
    bytea       *targ = PG_GETARG_BYTEA_PP(0);
    bytea       *newsub = PG_GETARG_BYTEA_PP(1);
    int         start = PG_GETARG_INT32(2);
    int         len = PG_GETARG_INT32(3);
    bytea       *result;
    int         targ_len = VARSIZE_ANY_EXHDR(targ);
    int         newsub_len = VARSIZE_ANY_EXHDR(newsub);
    int         end;

    /* Convert start to 0-based */
    start--;

    /* Validate parameters */
    if (start < 0 || start > targ_len * 8)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("start position must be between 1 and %d", targ_len * 8)));

    if (len < 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("length must be non-negative")));

    end = start + len;
    if (end > targ_len * 8)
        end = targ_len * 8;

    /* If newsub is longer than len, truncate it */
    if (newsub_len * 8 > len)
        newsub_len = (len + 7) / 8;

    result = bytea_bit_overlay(targ, newsub, start, len);

    PG_RETURN_BYTEA_P(result);
}

