/*
 * bitposition - Returns first starting index of the specified substring within bits,
 * or zero if it's not present.
 */
Datum
bitposition(PG_FUNCTION_ARGS)
{
    VarBit     *str = PG_GETARG_VARBIT_P(0);
    VarBit     *substr = PG_GETARG_VARBIT_P(1);
    int            substr_len,
                str_len,
                i,
                j;
    bool        match;

    substr_len = VARBITLEN(substr);
    str_len = VARBITLEN(str);

    /* Empty substring always matches at position 1 */
    if (substr_len <= 0)
        PG_RETURN_INT32(1);

    /* Substring longer than string can't match */
    if (substr_len > str_len)
        PG_RETURN_INT32(0);

    /* Brute-force search */
    for (i = 0; i <= str_len - substr_len; i++)
    {
        match = true;
        for (j = 0; j < substr_len; j++)
        {
            if (VARBITBIT(str, i + j) != VARBITBIT(substr, j))
            {
                match = false;
                break;
            }
        }
        if (match)
            PG_RETURN_INT32(i + 1); /* 1-based index */
    }

    PG_RETURN_INT32(0);
}

