#include "postgres.h"
#include "utils/builtins.h"
#include "mb/pg_wchar.h"

PG_FUNCTION_INFO_V1(rpad);

Datum
rpad(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    int32       len = PG_GETARG_INT32(1);
    text       *fill = PG_GETARG_TEXT_PP(2);

    int         str_len = VARSIZE_ANY_EXHDR(str);
    char       *str_data = VARDATA_ANY(str);
    int         fill_len = VARSIZE_ANY_EXHDR(fill);
    char       *fill_data = VARDATA_ANY(fill);

    if (len < 0)
        PG_RETURN_NULL();

    if (fill_len <= 0)
        PG_RETURN_TEXT_P(str);

    int         result_len;
    char       *result;

    if (len <= str_len)
    {
        result_len = len;
        result = (char *) palloc(result_len + VARHDRSZ);
        SET_VARSIZE(result, result_len + VARHDRSZ);
        memcpy(VARDATA(result), str_data, result_len);
    }
    else
    {
        result_len = len;
        result = (char *) palloc(result_len + VARHDRSZ);
        SET_VARSIZE(result, result_len + VARHDRSZ);

        int copied = 0;

        if (str_len > 0)
        {
            memcpy(VARDATA(result), str_data, str_len);
            copied = str_len;
        }

        while (copied < result_len)
        {
            int remaining = result_len - copied;
            int to_copy = (remaining < fill_len) ? remaining : fill_len;

            memcpy(VARDATA(result) + copied, fill_data, to_copy);
            copied += to_copy;
        }
    }

    PG_RETURN_TEXT_P((text *) result);
}

