/*
 * bitsubstr - extracts a substring of bits from a bit string.
 * Similar to text_substr, but operates on bits.
 */
Datum
bitsubstr(PG_FUNCTION_ARGS)
{
    VarBit     *arg = PG_GETARG_VARBIT_P(0);
    int32       start = PG_GETARG_INT32(1);
    int32       count = -1;
    int32       len;
    VarBit     *result;
    bits8      *r;
    bits8      *p;
    int         bitlen,
                rbitlen,
                sbit,
                i;

    /* Check for optional count parameter */
    if (PG_NARGS() > 2 && !PG_ARGISNULL(2))
        count = PG_GETARG_INT32(2);

    bitlen = VARBITLEN(arg);

    /* Validate start position */
    if (start < 1)
        start = 1;
    else if (start > bitlen)
        start = bitlen + 1;

    /* Calculate substring length */
    if (count < 0)
        len = bitlen - start + 1;
    else
        len = Min(count, bitlen - start + 1);

    if (len <= 0)
        PG_RETURN_VARBIT_P(VARBIT_CREATE(0, NULL));

    /* Allocate result */
    rbitlen = VARBITTOTALLEN(len);
    result = (VarBit *) palloc(rbitlen);
    SET_VARSIZE(result, rbitlen);
    VARBITLEN(result) = len;

    /* Copy the bits */
    p = VARBITS(arg);
    r = VARBITS(result);
    sbit = start - 1;

    for (i = 0; i < len; i++)
    {
        if (GETBIT(p, sbit + i))
            SETBIT(r, i);
        else
            CLRBIT(r, i);
    }

    PG_RETURN_VARBIT_P(result);
}

