    if (count < 0)
        len = bytelen - start + 1;
    else
        len = Min(count, bytelen - start + 1);

    if (len <= 0)
        PG_RETURN_BYTEA_P(cstring_to_text_with_len("", 0));

    /* Allocate result */
    result = (bytea *) palloc(VARHDRSZ + len);
    SET_VARSIZE(result, VARHDRSZ + len);

