/*
 * textregexsubstr - extracts a substring matching a POSIX regular expression.
 */
Datum
textregexsubstr(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    pg_re_flags flags;
    Oid         collation = PG_GET_COLLATION();
    regex_t     re;
    regmatch_t  pmatch[2];
    int         so,
                eo;
    text       *result;

    /* Compile the regex */
    RE_compile_and_cache(&re, pattern, &flags, collation);

    /* Execute the regex */
    if (RE_execute(&re, text_to_cstring(str), 1, pmatch))
    {
        so = pmatch[0].rm_so;
        eo = pmatch[0].rm_eo;

        if (so >= 0 && eo >= 0 && eo > so)
        {
            int len = eo - so;
            char *matched = palloc(len + 1);
            memcpy(matched, text_to_cstring(str) + so, len);
            matched[len] = '\0';
            result = cstring_to_text(matched);
            pfree(matched);
            PG_RETURN_TEXT_P(result);
        }
    }

    /* No match */
    PG_RETURN_NULL();
}

