Datum
byteatrim(PG_FUNCTION_ARGS)
{
    bytea       *bytes = PG_GETARG_BYTEA_PP(0);
    bytea       *bytesremoved = PG_GETARG_BYTEA_PP(1);
    text       *direction = PG_GETARG_TEXT_PP(2);
    int         dir = TRIM_BOTH;
    bytea       *result;

    if (PG_NARGS() == 2)
    {
        dir = TRIM_BOTH;
    }
    else
    {
        char       *dirstr = text_to_cstring(direction);

        if (pg_strcasecmp(dirstr, "leading") == 0)
            dir = TRIM_LEADING;
        else if (pg_strcasecmp(dirstr, "trailing") == 0)
            dir = TRIM_TRAILING;
        else if (pg_strcasecmp(dirstr, "both") == 0)
            dir = TRIM_BOTH;
        else
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("invalid trim direction: %s", dirstr),
                     errhint("Valid options are \"leading\", \"trailing\", and \"both\".")));
        pfree(dirstr);
    }

    result = bytea_trim(bytes, bytesremoved, dir);

    PG_RETURN_BYTEA_P(result);
}

static bytea *
bytea_trim(bytea *bytes, bytea *bytesremoved, int dir)
{
    int         bytelen = VARSIZE_ANY_EXHDR(bytes);
    char       *byteptr = VARDATA_ANY(bytes);
    int         bytesremovedlen = VARSIZE_ANY_EXHDR(bytesremoved);
    char       *bytesremovedptr = VARDATA_ANY(bytesremoved);
    int         start = 0;
    int         end = bytelen - 1;
    bool        found;
    int         i;

    if (dir == TRIM_LEADING || dir == TRIM_BOTH)
    {
        for (start = 0; start < bytelen; start++)
        {
            found = false;
            for (i = 0; i < bytesremovedlen; i++)
            {
                if (byteptr[start] == bytesremovedptr[i])
                {
                    found = true;
                    break;
                }
            }
            if (!found)
                break;
        }
    }

    if (dir == TRIM_TRAILING || dir == TRIM_BOTH)
    {
        for (end = bytelen - 1; end >= start; end--)
        {
            found = false;
            for (i = 0; i < bytesremovedlen; i++)
            {
                if (byteptr[end] == bytesremovedptr[i])
                {
                    found = true;
                    break;
                }
            }
            if (!found)
                break;
        }
    }

    return bytea_substring(bytes, start + 1, end - start + 1, false);
}

