Datum
chr(PG_FUNCTION_ARGS)
{
    int32       code = PG_GETARG_INT32(0);
    char        utf8str[5];    /* max length for a single UTF-8 character */
    int         len;

    if (code == 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("null character not permitted")));

    if (GetDatabaseEncoding() == PG_UTF8)
    {
        /* For UTF8, treat the argument as a Unicode code point */
        len = pg_utf8_encode(code, utf8str);
    }
    else
    {
        /* For other encodings, must be ASCII */
        if (code < 0 || code > 127)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("requested character not valid for encoding")));
        utf8str[0] = (char) code;
        len = 1;
    }

    PG_RETURN_TEXT_P(cstring_to_text_with_len(utf8str, len));
}

