    int32       n = PG_GETARG_INT32(1);
    int32       len = VARSIZE_ANY_EXHDR(str);
    int32       result_len;
    text       *result;
    char       *p;

    if (n < 0)
    {
        n = -n;
        result_len = len - n;
        if (result_len < 0)
            result_len = 0;
    }
    else
    {
        result_len = n;
        if (result_len > len)
            result_len = len;
    }

    result = (text *) palloc(VARHDRSZ + result_len);
    SET_VARSIZE(result, VARHDRSZ + result_len);
    p = VARDATA(result);

    memcpy(p, VARDATA_ANY(str), result_len);

    PG_RETURN_TEXT_P(result);
}

