    i = 0;
    foreach(l, names)
    {
        Value      *val = (Value *) lfirst(l);
        char       *str;
        NameData    name;

        if (!IsA(val, String))
            elog(ERROR, "unexpected node type in name list: %d",
                 (int) nodeTag(val));

        str = strVal(val);
        namestrcpy(&name, str);
        astate = accumArrayResult(astate, NameGetDatum(&name),
                                  false, NAMEOID, CurrentMemoryContext);
        i++;
    }

    PG_RETURN_ARRAYTYPE_P(makeArrayResult(astate, CurrentMemoryContext));
}

