#include "postgres.h"
#include "utils/builtins.h"
#include "mb/pg_wchar.h"

PG_FUNCTION_INFO_V1(quote_ident);

Datum
quote_ident(PG_FUNCTION_ARGS)
{
    text       *txt = PG_GETARG_TEXT_PP(0);
    char       *str;
    char       *result;
    bool        need_quotes;
    int         i;
    int         len;
    int         result_len;
    char       *ptr;

    str = text_to_cstring(txt);
    len = strlen(str);

    /* Check if we need to quote the identifier */
    need_quotes = false;

    if (len == 0)
        need_quotes = true;
    else
    {
        /* First character must be a letter or underscore */
        if (!((str[0] >= 'a' && str[0] <= 'z') ||
              (str[0] >= 'A' && str[0] <= 'Z') ||
              str[0] == '_'))
            need_quotes = true;
        else
        {
            /* Subsequent characters must be letters, digits, or underscores */
            for (i = 1; i < len; i++)
            {
                if (!((str[i] >= 'a' && str[i] <= 'z') ||
                      (str[i] >= 'A' && str[i] <= 'Z') ||
                      (str[i] >= '0' && str[i] <= '9') ||
                      str[i] == '_'))
                {
                    need_quotes = true;
                    break;
                }
            }
        }
    }

    if (!need_quotes)
    {
        /* No quoting needed, return the string as-is */
        PG_RETURN_TEXT_P(cstring_to_text(str));
    }

    /* Calculate the length of the quoted string */
    result_len = 2; /* for the opening and closing quotes */
    for (i = 0; i < len; i++)
    {
        if (str[i] == '"')
            result_len += 2; /* double the quote */
        else
            result_len += 1;
    }

    /* Allocate memory for the result */
    result = (char *) palloc(result_len + 1);
    ptr = result;

    *ptr++ = '"';
    for (i = 0; i < len; i++)
    {
        if (str[i] == '"')
            *ptr++ = '"', *ptr++ = '"';
        else
            *ptr++ = str[i];
    }
    *ptr++ = '"';
    *ptr = '\0';

    PG_RETURN_TEXT_P(cstring_to_text(result));
}

