#include "postgres.h"
#include "utils/builtins.h"
#include "mb/pg_wchar.h"
#include "regex/regex.h"

PG_FUNCTION_INFO_V1(regexp_count);

Datum
regexp_count(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    int            start = PG_GETARG_INT32(2);
    int            count = 0;
    pg_re_flags    re_flags;
    regex_t    re;
    regmatch_t pmatch[1];
    int            text_len;
    char       *str_ptr;
    int            str_pos;
    int            pattern_len;
    char       *pattern_str;
    int            utf8_flag;

    /* Parse optional parameters */
    re_flags.cflags = REG_ADVANCED;
    re_flags.glob = false;

    /* Convert input texts to C strings */
    str_ptr = text_to_cstring(str);
    pattern_str = text_to_cstring(pattern);
    text_len = VARSIZE_ANY_EXHDR(str);
    pattern_len = VARSIZE_ANY_EXHDR(pattern);

    /* Check if the string is valid UTF-8 */
    utf8_flag = pg_database_encoding_max_length() > 1;

    /* Compile the regex pattern */
    if (pg_regcomp(&re, pattern_str, re_flags.cflags, utf8_flag ? PG_UTF8 : PG_SQL_ASCII) != 0)
    {
        char        errMsg[100];

        pg_regerror(REG_BADPAT, &re, errMsg, sizeof(errMsg));
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_REGULAR_EXPRESSION),
                 errmsg("invalid regular expression: %s", errMsg)));
    }

    /* Adjust start position (1-based to 0-based) */
    if (start < 1)
        start = 1;
    str_pos = start - 1;

    /* Find all matches */
    while (str_pos <= text_len)
    {
        if (pg_regexec(&re, str_ptr + str_pos, 1, pmatch, 0) == 0)
        {
            if (pmatch[0].rm_so < 0)
                break;  /* no more matches */
            count++;
            str_pos += pmatch[0].rm_eo;
        }
        else
        {
            break;  /* no more matches */
        }
    }

    /* Clean up */
    pg_regfree(&re);
    pfree(str_ptr);
    pfree(pattern_str);

    PG_RETURN_INT32(count);
}

