regexp_like(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    text       *flags = PG_GETARG_TEXT_PP(2);
    pg_re_flags re_flags;
    regex_t    *re;
    int         cflags = 0;
    int         rc;
    bool        result;
    char       *pat;
    char       *str_data;
    int         str_len;

    /* Parse the optional flags argument */
    parse_re_flags(flags, &re_flags);
    cflags = re_flags.cflags;

    /* Compile the regex pattern */
    pat = text_to_cstring(pattern);
    re = RE_compile_and_cache(pat, cflags, DEFAULT_COLLATION_OID);

    /* Prepare the input string */
    str_data = VARDATA_ANY(str);
    str_len = VARSIZE_ANY_EXHDR(str);

    /* Execute the regex match */
    rc = RE_execute(re, str_data, str_len, 0, NULL, 0);

    /* Determine result */
    result = (rc == REG_OKAY);

    PG_RETURN_BOOL(result);
}

