PG_FUNCTION_INFO_V1(regexp_match);

Datum
regexp_match(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    pg_re_flags flags;
    ArrayType  *result;
    regex_t    *re;
    regmatch_t *pmatch;
    int         nmatches;
    int         i;
    int         so,
                eo;
    int         len;
    char       *str_ptr;
    char       *match_ptr;
    Datum      *elems;
    bool       *nulls;
    int         dims[1];
    int         lbs[1];

    /* Compile the regex pattern */
    re = RE_compile_and_cache(pattern, PG_GET_COLLATION(), REG_ADVANCED, &flags);

    /* Get the number of capturing subexpressions */
    nmatches = re->re_nsub + 1;
    pmatch = (regmatch_t *) palloc(nmatches * sizeof(regmatch_t));

    /* Execute the regex */
    str_ptr = text_to_cstring(str);
    if (RE_execute(re, str_ptr, strlen(str_ptr), 0, NULL, nmatches, pmatch) <= 0)
    {
        pfree(pmatch);
        pfree(str_ptr);
        RE_free(re);
        PG_RETURN_NULL();
    }

    /* Prepare the array to return */
    dims[0] = nmatches - 1;  /* exclude the whole match */
    lbs[0] = 1;
    elems = (Datum *) palloc(dims[0] * sizeof(Datum));
    nulls = (bool *) palloc(dims[0] * sizeof(bool));

    /* Extract submatches */
    for (i = 1; i < nmatches; i++)
    {
        so = pmatch[i].rm_so;
        eo = pmatch[i].rm_eo;

        if (so < 0 || eo < 0)
        {
            elems[i - 1] = (Datum) 0;
            nulls[i - 1] = true;
            continue;
        }

        len = eo - so;
        match_ptr = palloc(len + 1);
        memcpy(match_ptr, str_ptr + so, len);
        match_ptr[len] = '\0';
        elems[i - 1] = CStringGetTextDatum(match_ptr);
        nulls[i - 1] = false;
        pfree(match_ptr);
    }

    result = construct_md_array(elems, nulls, 1, dims, lbs,
                               TEXTOID, -1, false, TYPALIGN_INT);

    /* Clean up */
    pfree(pmatch);
    pfree(str_ptr);
    pfree(elems);
    pfree(nulls);
    RE_free(re);

    PG_RETURN_ARRAYTYPE_P(result);
}

