Datum
regexp_matches_no_flags(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    bool        global = false;
    ArrayType  *result;
    regex_t     re;
    regmatch_t *pmatch;
    int         nmatches;
    int         so,
                eo;
    int         i;
    int         start_search;
    int         str_len;
    char       *str_ptr;
    char       *pattern_ptr;
    int         pattern_len;
    int         flags = REG_ADVANCED;
    int         err;
    char        errMsg[100];

    str_ptr = VARDATA_ANY(str);
    str_len = VARSIZE_ANY_EXHDR(str);
    pattern_ptr = VARDATA_ANY(pattern);
    pattern_len = VARSIZE_ANY_EXHDR(pattern);

    err = pg_regcomp(&re, pattern_ptr, pattern_len, flags, DEFAULT_COLLATION_OID);
    if (err != 0)
    {
        pg_regerror(err, &re, errMsg, sizeof(errMsg));
        PG_RETURN_NULL();
    }

    nmatches = re.re_nsub + 1;
    pmatch = (regmatch_t *) palloc(nmatches * sizeof(regmatch_t));

    start_search = 0;
    result = NULL;

    while (start_search <= str_len)
    {
        err = pg_regexec(&re, str_ptr + start_search, nmatches, pmatch, 0);
        if (err == REG_NOMATCH)
            break;

        if (err != 0)
        {
            pg_regerror(err, &re, errMsg, sizeof(errMsg));
            pfree(pmatch);
            pg_regfree(&re);
            PG_RETURN_NULL();
        }

        for (i = 1; i < nmatches; i++)
        {
            if (pmatch[i].rm_so == -1)
                continue;

            so = start_search + pmatch[i].rm_so;
            eo = start_search + pmatch[i].rm_eo;

            if (so < 0 || eo < 0 || so > str_len || eo > str_len)
                continue;

            text *substr = cstring_to_text_with_len(str_ptr + so, eo - so);
            if (result == NULL)
                result = construct_array(&substr, 1, TEXTOID, -1, false, 'i');
            else
                result = array_append(result, substr);
        }

        if (!global)
            break;

        start_search += pmatch[0].rm_eo;
        if (pmatch[0].rm_so == pmatch[0].rm_eo)
            start_search += 1;
    }

    pfree(pmatch);
    pg_regfree(&re);

    if (result == NULL)
        PG_RETURN_NULL();
    else
        PG_RETURN_ARRAYTYPE_P(result);
}

Datum
regexp_matches(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    text       *flags = PG_GETARG_TEXT_PP_IF_EXISTS(2);
    bool        global = false;

    if (flags != NULL)
    {
        char       *flags_ptr = VARDATA_ANY(flags);
        int         flags_len = VARSIZE_ANY_EXHDR(flags);

        for (int i = 0; i < flags_len; i++)
        {
            if (flags_ptr[i] == 'g')
            {
                global = true;
                break;
            }
        }
    }

    if (global)
        PG_RETURN_DATUM(DirectFunctionCall3(regexp_matches_no_flags,
                                           PG_GETARG_DATUM(0),
                                           PG_GETARG_DATUM(1),
                                           PG_GETARG_DATUM(2)));
    else
        PG_RETURN_DATUM(DirectFunctionCall2(regexp_matches_no_flags,
                                           PG_GETARG_DATUM(0),
                                           PG_GETARG_DATUM(1)));
}

