PG_FUNCTION_INFO_V1(regexp_split_to_array_no_flags);
PG_FUNCTION_INFO_V1(regexp_split_to_array);

Datum
regexp_split_to_array_no_flags(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    ArrayType  *result;
    pg_re_flags flags;
    int         cflags = REG_ADVANCED;
    int         i;
    int         nmatches;
    int         pos = 0;
    int         start = 0;
    int         end = 0;
    regex_t     re;
    regmatch_t *pmatch;
    Datum      *elems;
    bool       *nulls;
    int         nelems = 0;
    int         maxelems = 64;

    /* Compile the regex pattern */
    flags.cflags = cflags;
    RE_compile_and_cache(&re, pattern, flags.cflags, 0);

    /* Allocate space for matches */
    pmatch = (regmatch_t *) palloc(sizeof(regmatch_t) * (re.re_nsub + 1));

    /* Allocate initial space for elements */
    elems = (Datum *) palloc(sizeof(Datum) * maxelems);
    nulls = (bool *) palloc(sizeof(bool) * maxelems);
    memset(nulls, false, sizeof(bool) * maxelems);

    /* Split the string */
    while (pos < VARSIZE_ANY_EXHDR(str))
    {
        /* Find next match */
        if (RE_execute(&re,
                       VARDATA_ANY(str),
                       VARSIZE_ANY_EXHDR(str),
                       pos,
                       re.re_nsub + 1,
                       pmatch,
                       0) <= 0)
            break;

        /* Extract substring before match */
        start = pos;
        end = pmatch[0].rm_so;
        if (end >= 0 && start < end)
        {
            text *substr = extract_substr(str, start, end - start);
            if (nelems >= maxelems)
            {
                maxelems *= 2;
                elems = (Datum *) repalloc(elems, sizeof(Datum) * maxelems);
                nulls = (bool *) repalloc(nulls, sizeof(bool) * maxelems);
            }
            elems[nelems] = PointerGetDatum(substr);
            nelems++;
        }

        pos = pmatch[0].rm_eo;
    }

    /* Extract remaining substring */
    if (pos < VARSIZE_ANY_EXHDR(str))
    {
        text *substr = extract_substr(str, pos, VARSIZE_ANY_EXHDR(str) - pos);
        if (nelems >= maxelems)
        {
            maxelems += 1;
            elems = (Datum *) repalloc(elems, sizeof(Datum) * maxelems);
            nulls = (bool *) repalloc(nulls, sizeof(bool) * maxelems);
        }
        elems[nelems] = PointerGetDatum(substr);
        nelems++;
    }

    /* Free regex memory */
    RE_free_cache(&re);
    pfree(pmatch);

    /* Build and return array */
    result = construct_array(elems, nelems, TEXTOID, -1, false, 'i');

    /* Free memory */
    for (i = 0; i < nelems; i++)
        pfree(DatumGetPointer(elems[i]));
    pfree(elems);
    pfree(nulls);

    PG_RETURN_ARRAYTYPE_P(result);
}

Datum
regexp_split_to_array(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    text       *flags = PG_GETARG_TEXT_PP_IF_EXISTS(2, NULL);
    pg_re_flags re_flags;

    /* Parse flags if provided */
    if (flags)
        parse_re_flags(&re_flags, flags);
    else
        re_flags.cflags = REG_ADVANCED;

    /* Call no-flags version with the compiled flags */
    return DirectFunctionCall2(regexp_split_to_array_no_flags,
                              PointerGetDatum(str),
                              PointerGetDatum(pattern));
}

