PG_FUNCTION_INFO_V1(regexp_substr);

Datum
regexp_substr(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *pattern = PG_GETARG_TEXT_PP(1);
    int            start = PG_GETARG_INT32(2);
    int            n = PG_GETARG_INT32(3);
    text       *flags = PG_GETARG_TEXT_PP_IF_EXISTS(4, NULL);
    int            subexpr = PG_GETARG_INT32_IF_EXISTS(5, 0);
    pg_re_flags    re_flags;
    regex_t     *re;
    regmatch_t *pmatch;
    int            nmatch;
    int            str_len;
    char       *str_ptr;
    char       *pattern_str;
    int            errcode;
    char        errmsg[100];
    int            i;
    int            match_start;
    int            match_end;
    text       *result;

    /* Parse the optional flags parameter */
    if (flags)
        parse_re_flags(&re_flags, flags);
    else
        memset(&re_flags, 0, sizeof(pg_re_flags));

    /* Compile the regex pattern */
    pattern_str = text_to_cstring(pattern);
    re = RE_compile_and_cache(pattern_str, re_flags.cflags, PG_GET_COLLATION());

    /* Get the number of parenthesized subexpressions */
    nmatch = re->re_nsub + 1;
    pmatch = (regmatch_t *) palloc(nmatch * sizeof(regmatch_t));

    /* Convert the input string to C string */
    str_len = VARSIZE_ANY_EXHDR(str);
    str_ptr = text_to_cstring(str);

    /* Find the n-th match */
    for (i = 0; i < n; i++)
    {
        errcode = regexec(re, str_ptr + start - 1, nmatch, pmatch, 0);
        if (errcode != 0)
        {
            if (errcode == REG_NOMATCH)
                PG_RETURN_NULL();

            pg_regerror(errcode, re, errmsg, sizeof(errmsg));
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_REGULAR_EXPRESSION),
                     errmsg("regular expression failed: %s", errmsg)));
        }

        if (i < n - 1)
        {
            start += pmatch[0].rm_eo;
            if (start > str_len)
                PG_RETURN_NULL();
        }
    }

    /* Check if the requested subexpression exists */
    if (subexpr >= nmatch || pmatch[subexpr].rm_so == -1)
        PG_RETURN_NULL();

    /* Extract the matched substring */
    match_start = pmatch[subexpr].rm_so + start - 1;
    match_end = pmatch[subexpr].rm_eo + start - 1;

    result = cstring_to_text_with_len(str_ptr + match_start, match_end - match_start);

    pfree(pmatch);
    pfree(str_ptr);

    PG_RETURN_TEXT_P(result);
}

