repeat(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    int32       count = PG_GETARG_INT32(1);
    text       *result;
    char       *ptr;
    int         len,
                result_len;
    int         i;

    if (count < 0)
        count = 0;

    len = VARSIZE_ANY_EXHDR(str);
    result_len = len * count;

    if (result_len <= 0)
        PG_RETURN_TEXT_P(cstring_to_text_with_len("", 0));

    result = palloc(VARHDRSZ + result_len);
    SET_VARSIZE(result, VARHDRSZ + result_len);
    ptr = VARDATA(result);

    for (i = 0; i < count; i++)
    {
        memcpy(ptr, VARDATA_ANY(str), len);
        ptr += len;
    }

    PG_RETURN_TEXT_P(result);
}

