#include "postgres.h"
#include "utils/builtins.h"
#include "utils/varlena.h"

PG_FUNCTION_INFO_V1(split_text);

Datum
split_text(PG_FUNCTION_ARGS)
{
    text       *input_string = PG_GETARG_TEXT_PP(0);
    text       *delimiter = PG_GETARG_TEXT_PP(1);
    int32       field_num = PG_GETARG_INT32(2);
    char       *input_str;
    char       *delim_str;
    char       *start_ptr;
    char       *end_ptr;
    int         delim_len;
    int         input_len;
    int         field_count = 0;
    int         abs_field_num;
    bool        last_field = false;

    input_str = text_to_cstring(input_string);
    delim_str = text_to_cstring(delimiter);
    delim_len = strlen(delim_str);
    input_len = strlen(input_str);
    abs_field_num = Abs(field_num);

    if (delim_len == 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("delimiter cannot be empty")));

    start_ptr = input_str;
    end_ptr = input_str;

    /* Handle negative field numbers by counting total fields first */
    if (field_num < 0)
    {
        int total_fields = 1;
        char *ptr = input_str;

        while ((ptr = strstr(ptr, delim_str)) != NULL)
        {
            total_fields++;
            ptr += delim_len;
        }

        if (abs_field_num > total_fields)
            PG_RETURN_NULL();

        field_num = total_fields - abs_field_num + 1;
    }

    while (1)
    {
        end_ptr = strstr(start_ptr, delim_str);
        if (end_ptr == NULL)
        {
            last_field = true;
            end_ptr = input_str + input_len;
        }

        field_count++;

        if (field_count == field_num)
        {
            text *result = cstring_to_text_with_len(start_ptr, end_ptr - start_ptr);
            PG_RETURN_TEXT_P(result);
        }

        if (last_field)
            break;

        start_ptr = end_ptr + delim_len;
    }

    /* Field number out of range */
    PG_RETURN_NULL();
}

