Datum
text_to_array(PG_FUNCTION_ARGS)
{
    text       *input_string = PG_GETARG_TEXT_PP(0);
    text       *delimiter = PG_GETARG_TEXT_PP(1);
    char       *input_str;
    char       *delim_str;
    int         delim_len;
    int         input_len;
    int         i;
    int         start_pos = 0;
    int         field_count = 1;
    Datum      *elems;
    bool       *nulls;
    ArrayType  *result;

    input_str = text_to_cstring(input_string);
    input_len = strlen(input_str);

    if (PG_ARGISNULL(1))
    {
        /* NULL delimiter: split into individual characters */
        elems = (Datum *) palloc(input_len * sizeof(Datum));
        nulls = (bool *) palloc(input_len * sizeof(bool));

        for (i = 0; i < input_len; i++)
        {
            char        ch[2];

            ch[0] = input_str[i];
            ch[1] = '\0';
            elems[i] = CStringGetTextDatum(ch);
            nulls[i] = false;
        }

        result = construct_md_array(elems, nulls, 1, &input_len, &input_len,
                                   TEXTOID, -1, false, 'i');
    }
    else
    {
        delim_str = text_to_cstring(delimiter);
        delim_len = strlen(delim_str);

        if (delim_len == 0)
        {
            /* empty delimiter: return the whole string as a single element */
            elems = (Datum *) palloc(sizeof(Datum));
            nulls = (bool *) palloc(sizeof(bool));

            elems[0] = CStringGetTextDatum(input_str);
            nulls[0] = false;

            field_count = 1;
            result = construct_md_array(elems, nulls, 1, &field_count, &field_count,
                                       TEXTOID, -1, false, 'i');
        }
        else
        {
            /* count fields */
            for (i = 0; i <= input_len - delim_len; i++)
            {
                if (strncmp(input_str + i, delim_str, delim_len) == 0)
                {
                    field_count++;
                    i += delim_len - 1;
                }
            }

            elems = (Datum *) palloc(field_count * sizeof(Datum));
            nulls = (bool *) palloc(field_count * sizeof(bool));

            field_count = 0;
            for (i = 0; i <= input_len; i++)
            {
                if (i == input_len || strncmp(input_str + i, delim_str, delim_len) == 0)
                {
                    char       *field = (char *) palloc(i - start_pos + 1);

                    memcpy(field, input_str + start_pos, i - start_pos);
                    field[i - start_pos] = '\0';

                    elems[field_count] = CStringGetTextDatum(field);
                    nulls[field_count] = false;
                    field_count++;

                    if (i < input_len)
                        i += delim_len - 1;
                    start_pos = i + 1;
                }
            }

            result = construct_md_array(elems, nulls, 1, &field_count, &field_count,
                                       TEXTOID, -1, false, 'i');
        }
    }

    PG_RETURN_ARRAYTYPE_P(result);
}

