#include "funcapi.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(string_to_table);

Datum
string_to_table(PG_FUNCTION_ARGS)
{
    text       *input_string;
    text       *delimiter;
    text       *null_string = NULL;
    char       *str;
    char       *delim;
    char       *null_str = NULL;
    char       *start_ptr;
    char       *end_ptr;
    bool        delim_is_null;
    bool        null_str_is_null;
    ReturnSetInfo *rsinfo = (ReturnSetInfo *) fcinfo->resultinfo;
    TupleDesc   tupdesc;
    Tuplestorestate *tupstore;
    MemoryContext per_query_ctx;
    MemoryContext oldcontext;
    Datum       values[1];
    bool        nulls[1] = {false};

    if (!PG_ARGISNULL(0))
        input_string = PG_GETARG_TEXT_PP(0);
    else
        PG_RETURN_NULL();

    delim_is_null = PG_ARGISNULL(1);
    if (!delim_is_null)
        delimiter = PG_GETARG_TEXT_PP(1);
    else
        delimiter = NULL;

    null_str_is_null = PG_ARGISNULL(2);
    if (!null_str_is_null)
        null_string = PG_GETARG_TEXT_PP(2);
    else
        null_string = NULL;

    str = text_to_cstring(input_string);
    if (!delim_is_null)
        delim = text_to_cstring(delimiter);
    else
        delim = NULL;
    if (!null_str_is_null)
        null_str = text_to_cstring(null_string);
    else
        null_str = NULL;

    if (rsinfo == NULL || !IsA(rsinfo, ReturnSetInfo))
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                 errmsg("set-valued function called in context that cannot accept a set")));
    if (!(rsinfo->allowedModes & SFRM_Materialize))
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                 errmsg("materialize mode required, but it is not allowed in this context")));

    per_query_ctx = rsinfo->econtext->ecxt_per_query_memory;
    oldcontext = MemoryContextSwitchTo(per_query_ctx);

    tupdesc = CreateTemplateTupleDesc(1);
    TupleDescInitEntry(tupdesc, (AttrNumber) 1, "column", TEXTOID, -1, 0);
    tupstore = tuplestore_begin_heap(true, false, work_mem);
    rsinfo->returnMode = SFRM_Materialize;
    rsinfo->setResult = tupstore;
    rsinfo->setDesc = tupdesc;

    MemoryContextSwitchTo(oldcontext);

    if (delim_is_null)
    {
        /* Split into individual characters */
        for (start_ptr = str; *start_ptr; start_ptr++)
        {
            char        ch[2];

            ch[0] = *start_ptr;
            ch[1] = '\0';

            values[0] = CStringGetTextDatum(ch);
            tuplestore_putvalues(tupstore, tupdesc, values, nulls);
        }
    }
    else if (delim[0] == '\0')
    {
        /* Treat as single field */
        if (null_str != NULL && strcmp(str, null_str) == 0)
            nulls[0] = true;
        else
            values[0] = CStringGetTextDatum(str);
        tuplestore_putvalues(tupstore, tupdesc, values, nulls);
    }
    else
    {
        /* Split by delimiter */
        start_ptr = str;
        while ((end_ptr = strstr(start_ptr, delim)) != NULL)
        {
            char       *field;
            int         field_len = end_ptr - start_ptr;

            field = (char *) palloc(field_len + 1);
            memcpy(field, start_ptr, field_len);
            field[field_len] = '\0';

            if (null_str != NULL && strcmp(field, null_str) == 0)
                nulls[0] = true;
            else
                values[0] = CStringGetTextDatum(field);
            tuplestore_putvalues(tupstore, tupdesc, values, nulls);
            nulls[0] = false;

            pfree(field);
            start_ptr = end_ptr + strlen(delim);
        }

        /* Add the last field */
        if (null_str != NULL && strcmp(start_ptr, null_str) == 0)
            nulls[0] = true;
        else
            values[0] = CStringGetTextDatum(start_ptr);
        tuplestore_putvalues(tupstore, tupdesc, values, nulls);
    }

    pfree(str);
    if (!delim_is_null)
        pfree(delim);
    if (!null_str_is_null)
        pfree(null_str);

    tuplestore_donestoring(tupstore);

    PG_RETURN_NULL();
}

