/*
 * bytea_substr - extracts a substring from a bytea value
 */
Datum
bytea_substr(PG_FUNCTION_ARGS)
{
    bytea       *result;
    bytea       *source = PG_GETARG_BYTEA_PP(0);
    int32       start = PG_GETARG_INT32(1);
    int32       count = PG_GETARG_INT32(2);
    int32       source_len = VARSIZE_ANY_EXHDR(source);
    char       *source_data = VARDATA_ANY(source);
    int32       end;

    /* handle negative start */
    if (start < 0)
    {
        start = source_len + start + 1;
        if (start < 1)
            start = 1;
    }

    /* handle negative count */
    if (count < 0)
        count = 0;

    /* calculate end position */
    end = start + count - 1;
    if (end > source_len)
        end = source_len;

    /* adjust start if needed */
    if (start > source_len)
    {
        start = source_len + 1;
        end = source_len;
    }

    /* empty result if start > end */
    if (start > end)
        PG_RETURN_BYTEA_P(cstring_to_text_with_len("", 0));

    /* extract substring */
    result = (bytea *) palloc(VARHDRSZ + (end - start + 1));
    SET_VARSIZE(result, VARHDRSZ + (end - start + 1));
    memcpy(VARDATA(result), source_data + start - 1, end - start + 1);

    PG_RETURN_BYTEA_P(result);
}

/*
 * bytea_substr_no_len - extracts a substring from a bytea value without length
 */
Datum
bytea_substr_no_len(PG_FUNCTION_ARGS)
{
    bytea       *result;
    bytea       *source = PG_GETARG_BYTEA_PP(0);
    int32       start = PG_GETARG_INT32(1);
    int32       source_len = VARSIZE_ANY_EXHDR(source);
    char       *source_data = VARDATA_ANY(source);
    int32       end;

    /* handle negative start */
    if (start < 0)
    {
        start = source_len + start + 1;
        if (start < 1)
            start = 1;
    }

    /* adjust start if needed */
    if (start > source_len)
        PG_RETURN_BYTEA_P(cstring_to_text_with_len("", 0));

    /* extract substring from start to end */
    end = source_len;

    result = (bytea *) palloc(VARHDRSZ + (end - start + 1));
    SET_VARSIZE(result, VARHDRSZ + (end - start + 1));
    memcpy(VARDATA(result), source_data + start - 1, end - start + 1);

    PG_RETURN_BYTEA_P(result);
}

