static text *
to_ascii_internal(text *str, int encoding)
{
    char       *src;
    char       *dst;
    char       *res;
    int            len;
    text       *ret;

    src = TextDatumGetCString(PointerGetDatum(str));
    len = strlen(src);
    dst = (char *) palloc(len + 1);

    convert_to_ascii(src, dst, len, encoding);

    res = dst;
    ret = cstring_to_text(res);
    pfree(dst);

    return ret;
}

