to_ascii_default(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    int            encoding = GetDatabaseEncoding();

    PG_RETURN_TEXT_P(to_ascii_internal(str, encoding));
}

