to_ascii_encname(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *encname = PG_GETARG_TEXT_PP(1);
    char       *encnamestr;
    int            encoding;

    encnamestr = text_to_cstring(encname);
