#include "utils/builtins.h"

Datum
to_bin(PG_FUNCTION_ARGS)
{
    int32       num = PG_GETARG_INT32(0);
    char        buf[32 + 1];  /* 32 bits + null terminator */
    char       *ptr = buf + sizeof(buf) - 1;
    uint32      unum;
    int         i;

    *ptr = '\0';
    unum = (uint32)num;

    for (i = 0; i < 32; i++)
    {
        *--ptr = (unum & 1) ? '1' : '0';
        unum >>= 1;
    }

    /* Trim leading zeros */
    while (*ptr == '0' && *(ptr + 1) != '\0')
        ptr++;

    PG_RETURN_TEXT_P(cstring_to_text(ptr));
}

