Datum
translate(PG_FUNCTION_ARGS)
{
    text       *str = PG_GETARG_TEXT_PP(0);
    text       *from = PG_GETARG_TEXT_PP(1);
    text       *to = PG_GETARG_TEXT_PP(2);
    int            str_len = VARSIZE_ANY_EXHDR(str);
    int            from_len = VARSIZE_ANY_EXHDR(from);
    int            to_len = VARSIZE_ANY_EXHDR(to);
    char       *str_ptr = VARDATA_ANY(str);
    char       *from_ptr = VARDATA_ANY(from);
    char       *to_ptr = VARDATA_ANY(to);
    text       *result;
    char       *result_ptr;
    int            i, j;
    bool        found;

    result = (text *) palloc(str_len + VARHDRSZ);
    SET_VARSIZE(result, str_len + VARHDRSZ);
    result_ptr = VARDATA(result);

    for (i = 0; i < str_len; i++)
    {
        found = false;
        for (j = 0; j < from_len; j++)
        {
            if (str_ptr[i] == from_ptr[j])
            {
                found = true;
                if (j < to_len)
                    result_ptr[i] = to_ptr[j];
                break;
            }
        }
        if (!found)
            result_ptr[i] = str_ptr[i];
    }

    PG_RETURN_TEXT_P(result);
}

