/*
 * get_bit
 *
 * Returns the n'th bit of a bit string.
 * The leftmost bit is bit 0.
 */
Datum
bitgetbit(PG_FUNCTION_ARGS)
{
    VarBit     *arg = PG_GETARG_VARBIT_P(0);
    int32       n = PG_GETARG_INT32(1);
    int         bitlen;
    int         byteNo,
                bitNo;
    bits8       byteVal;

    bitlen = VARBITLEN(arg);

    /* Check that n is valid */
    if (n < 0 || n >= bitlen)
        PG_RETURN_NULL();

    byteNo = n / BITS_PER_BYTE;
    bitNo = BITS_PER_BYTE - 1 - (n % BITS_PER_BYTE);
    byteVal = VARBITS(arg)[byteNo];

    PG_RETURN_INT32((byteVal >> bitNo) & 1);
}

/*
 * byteaGetBit
 *
 * Returns the n'th bit of a bytea string.
 * The leftmost bit is bit 0.
 */
Datum
byteaGetBit(PG_FUNCTION_ARGS)
{
    bytea       *arg = PG_GETARG_BYTEA_PP(0);
    int32       n = PG_GETARG_INT32(1);
    int         bitlen;
    int         byteNo,
                bitNo;
    bits8       byteVal;

    bitlen = VARBITBYTES(arg) * BITS_PER_BYTE;

    /* Check that n is valid */
    if (n < 0 || n >= bitlen)
        PG_RETURN_NULL();

    byteNo = n / BITS_PER_BYTE;
    bitNo = BITS_PER_BYTE - 1 - (n % BITS_PER_BYTE);
    byteVal = ((bits8 *) VARDATA_ANY(arg))[byteNo];

    PG_RETURN_INT32((byteVal >> bitNo) & 1);
}

