Datum
byteaSetBit(PG_FUNCTION_ARGS)
{
    bytea       *result;
    bytea       *str = PG_GETARG_BYTEA_PP(0);
    int32       n = PG_GETARG_INT32(1);
    int32       newValue = PG_GETARG_INT32(2);
    int         len,
                bitlen,
                byteNo,
                bitNo;
    bits8       *r,
               *p;

    p = (bits8 *) VARDATA_ANY(str);
    len = VARSIZE_ANY_EXHDR(str);
    bitlen = len * 8;

    if (n < 0 || n >= bitlen)
        ereport(ERROR,
                (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                 errmsg("bit index %d out of valid range (0..%d)",
                        n, bitlen - 1)));

    byteNo = n / 8;
    bitNo = n % 8;

    result = (bytea *) palloc(VARSIZE_ANY(str));
    SET_VARSIZE(result, VARSIZE_ANY(str));
    r = (bits8 *) VARDATA(result);

    memcpy(r, p, len);

    if (newValue != 0)
        r[byteNo] |= (1 << (7 - bitNo));
    else
        r[byteNo] &= ~(1 << (7 - bitNo));

    PG_RETURN_BYTEA_P(result);
}

