#include "postgres.h"
#include "fmgr.h"
#include "utils/builtins.h"
#include "utils/bytea.h"
#include "openssl/evp.h"

PG_FUNCTION_INFO_V1(sha384);

Datum
sha384(PG_FUNCTION_ARGS)
{
    bytea       *input = PG_GETARG_BYTEA_PP(0);
    size_t      len = VARSIZE_ANY_EXHDR(input);
    unsigned char *data = (unsigned char *) VARDATA_ANY(input);
    unsigned char buf[EVP_MAX_MD_SIZE];
    unsigned int md_len;
    EVP_MD_CTX *ctx;

    ctx = EVP_MD_CTX_create();
    if (!ctx)
        ereport(ERROR,
                (errcode(ERRCODE_OUT_OF_MEMORY),
                errmsg("OpenSSL: could not create context for SHA-384"));

    if (!EVP_DigestInit_ex(ctx, EVP_sha384(), NULL))
    {
        EVP_MD_CTX_destroy(ctx);
        ereport(ERROR,
                (errcode(ERRCODE_EXTERNAL_ROUTINE_INVOCATION_EXCEPTION),
                errmsg("OpenSSL: could not initialize SHA-384 context"));
    }

    if (!EVP_DigestUpdate(ctx, data, len))
    {
        EVP_MD_CTX_destroy(ctx);
        ereport(ERROR,
                (errcode(ERRCODE_EXTERNAL_ROUTINE_INVOCATION_EXCEPTION),
                errmsg("OpenSSL: could not update SHA-384 context"));
    }

    if (!EVP_DigestFinal_ex(ctx, buf, &md_len))
    {
        EVP_MD_CTX_destroy(ctx);
        ereport(ERROR,
                (errcode(ERRCODE_EXTERNAL_ROUTINE_INVOCATION_EXCEPTION),
                errmsg("OpenSSL: could not finalize SHA-384 context"));
    }

    EVP_MD_CTX_destroy(ctx);

    PG_RETURN_BYTEA_P(cstring_to_text_with_len((char *) buf, md_len));
}

