#include "postgres.h"
#include "fmgr.h"
#include "mb/pg_wchar.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(pg_convert);

Datum
pg_convert(PG_FUNCTION_ARGS)
{
    bytea      *src_text = PG_GETARG_BYTEA_PP(0);
    text       *src_encoding = PG_GETARG_TEXT_PP(1);
    text       *dest_encoding = PG_GETARG_TEXT_PP(2);
    char       *src_encoding_str;
    char       *dest_encoding_str;
    int         src_encoding_id;
    int         dest_encoding_id;
    char       *src_data;
    char       *converted_data;
    int         src_len;
    int         converted_len;
    bytea      *result;

    src_encoding_str = text_to_cstring(src_encoding);
    dest_encoding_str = text_to_cstring(dest_encoding);

    src_encoding_id = pg_char_to_encoding(src_encoding_str);
    dest_encoding_id = pg_char_to_encoding(dest_encoding_str);

    if (src_encoding_id < 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                errmsg("invalid source encoding name: %s", src_encoding_str));

    if (dest_encoding_id < 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                errmsg("invalid destination encoding name: %s", dest_encoding_str));

    src_len = VARSIZE_ANY_EXHDR(src_text);
    src_data = VARDATA_ANY(src_text);

    converted_len = src_len * PG_MAX_ENCODED_CHAR_LEN;
    converted_data = (char *) palloc(converted_len);

    converted_len = pg_do_encoding_conversion((unsigned char *) converted_data,
                                             converted_len,
                                             dest_encoding_id,
                                             src_encoding_id,
                                             (unsigned char *) src_data,
                                             src_len);

    if (converted_len < 0)
        ereport(ERROR,
                (errcode(ERRCODE_CHARACTER_NOT_IN_REPERTOIRE),
                 errmsg("encoding conversion failed")));

    result = (bytea *) palloc(VARHDRSZ + converted_len);
    SET_VARSIZE(result, VARHDRSZ + converted_len);
    memcpy(VARDATA(result), converted_data, converted_len);

    pfree(converted_data);
    pfree(src_encoding_str);
    pfree(dest_encoding_str);

    PG_RETURN_BYTEA_P(result);
}

