        if (r != 0)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("time zone \"%s\" not recognized", zone)));

        tzp = pg_tzset(zone);
        result = timestamp_add_interval(timestamp, interval, tzp);
    }
    else
