#include "postgres.h"
#include "fmgr.h"
#include "utils/date.h"
#include "utils/timestamp.h"

PG_FUNCTION_INFO_V1(date_bin);

Datum
date_bin(PG_FUNCTION_ARGS)
{
    Interval   *bin_size = PG_GETARG_INTERVAL_P(0);
    Timestamp  source = PG_GETARG_TIMESTAMP(1);
    Timestamp  origin = PG_GETARG_TIMESTAMP(2);
    Timestamp  result;
    int64       bin_size_us,
                diff_us,
                bins;

    if (TIMESTAMP_NOT_FINITE(source) || TIMESTAMP_NOT_FINITE(origin))
        PG_RETURN_TIMESTAMP(source);

    /* Convert interval to microseconds */
    bin_size_us = interval_to_usec(bin_size);
    if (bin_size_us <= 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("bin size must be greater than zero")));

    /* Calculate difference between source and origin in microseconds */
    diff_us = (source - origin) / USECS_PER_SEC;

    /* Calculate number of bins */
    bins = diff_us / bin_size_us;

    /* Calculate the bin start time */
    result = origin + (bins * bin_size_us * USECS_PER_SEC);

    PG_RETURN_TIMESTAMP(result);
}

