    if (PG_NARGS() > 2 && !PG_ARGISNULL(2))
    {
        zone_arg = PG_GETARG_TEXT_PP(2);
        zone = text_to_cstring(zone_arg);
    }

    if (zone)
    {
        /* Apply the interval in the specified time zone */
        tz = DetermineTimeZoneOffset(timestamp, zone);
        timestamp -= tz * USECS_PER_SEC;
        result = timestamp - interval->time;
        result += tz * USECS_PER_SEC;
    }
    else
    {
        /* Use current time zone setting */
        result = timestamp - interval->time;
    }

    PG_RETURN_TIMESTAMPTZ(result);
}

