Datum
timestamp_extract(PG_FUNCTION_ARGS)
{
    text       *field = PG_GETARG_TEXT_PP(0);
    Timestamp  timestamp = PG_GETARG_TIMESTAMP(1);
    int         type,
                result;
    char       *lowstr;
    struct pg_tm tt,
               *tm = &tt;
    fsec_t      fsec;

    lowstr = downcase_truncate_identifier(VARDATA_ANY(field),
                                         VARSIZE_ANY_EXHDR(field),
                                         false);

    type = DecodeUnits(0, lowstr, &val);
    if (type == UNKNOWN_FIELD)
        type = DecodeSpecial(0, lowstr, &val);

    if (type == UNITS)
        PG_RETURN_NULL();

    if (TIMESTAMP_NOT_FINITE(timestamp))
        PG_RETURN_NULL();

    if (timestamp2tm(timestamp, NULL, tm, &fsec, NULL, NULL) != 0)
        PG_RETURN_NULL();

    switch (type)
    {
        case DTK_MICROSEC:
            result = tm->tm_sec * 1000000 + fsec;
            break;
        case DTK_MILLISEC:
            result = tm->tm_sec * 1000 + fsec / 1000;
            break;
        case DTK_SECOND:
            result = tm->tm_sec;
            break;
        case DTK_MINUTE:
            result = tm->tm_min;
            break;
        case DTK_HOUR:
            result = tm->tm_hour;
            break;
        case DTK_DAY:
            result = tm->tm_mday;
            break;
        case DTK_MONTH:
            result = tm->tm_mon;
            break;
        case DTK_QUARTER:
            result = (tm->tm_mon - 1) / 3 + 1;
            break;
        case DTK_YEAR:
            result = tm->tm_year;
            break;
        case DTK_DECADE:
            result = tm->tm_year / 10;
            break;
        case DTK_CENTURY:
            result = (tm->tm_year + 99) / 100;
            break;
        case DTK_MILLENNIUM:
            result = (tm->tm_year + 999) / 1000;
            break;
        default:
            PG_RETURN_NULL();
    }

    PG_RETURN_INT32(result);
}

