{
    Interval   *interval = PG_GETARG_INTERVAL_P(0);
    Interval   *result = (Interval *) palloc(sizeof(Interval));
    int64        hours;
    int64        days;

    /* Copy all fields from input interval */
    *result = *interval;

    /* Calculate days from hours */
    hours = result->time / USECS_PER_HOUR;
    days = hours / HOURS_PER_DAY;

    /* Adjust time and day fields */
    result->time -= days * HOURS_PER_DAY * USECS_PER_HOUR;
    result->day += days;

    PG_RETURN_INTERVAL_P(result);
}

