    TimeADT result;
    struct pg_tm tt,
               *tm = &tt;
    fsec_t fsec;

    GetCurrentTime(tm, &fsec);

    /* Limit precision to allowed range (0-6) */
    precision = Min(Max(precision, 0), 6);

    /* Convert to time type */
    result = ((((tm->tm_hour * MINS_PER_HOUR + tm->tm_min) * SECS_PER_MINUTE) + tm->tm_sec) * USECS_PER_SEC) + fsec;

    /* Round to requested precision */
    if (precision < 6)
        result = ((result + (USECS_PER_SEC / pow(10, 6 - precision) / 2)) / 
                 (USECS_PER_SEC / pow(10, 6 - precision))) * 
                (USECS_PER_SEC / pow(10, 6 - precision));

    PG_RETURN_TIMEADT(result);
}

