    result->month += years * MONTHS_PER_YEAR;
    result->month += months;

    result->day += weeks * DAYS_PER_WEEK;
    result->day += days;

    result->time += hours * USECS_PER_HOUR;
    result->time += mins * USECS_PER_MINUTE;
    result->time += (int64) (secs * USECS_PER_SEC);

    PG_RETURN_INTERVAL_P(result);
}

