#include "utils/datetime.h"

TimeADT
make_time(int hour, int minute, double second)
{
    TimeADT    result;
    int64        time;

    /* Validate input ranges */
    if (hour < 0 || hour >= HOURS_PER_DAY)
        ereport(ERROR,
                (errcode(ERRCODE_DATETIME_FIELD_OVERFLOW),
                 errmsg("hour must be between 0 and 23")));
    if (minute < 0 || minute >= MINS_PER_HOUR)
        ereport(ERROR,
                (errcode(ERRCODE_DATETIME_FIELD_OVERFLOW),
                 errmsg("minute must be between 0 and 59")));
    if (second < 0 || second >= SECS_PER_MINUTE)
        ereport(ERROR,
                (errcode(ERRCODE_DATETIME_FIELD_OVERFLOW),
                 errmsg("second must be between 0 and 59.999...")));

    /* Calculate total microseconds */
    time = (int64) hour * USECS_PER_HOUR +
           (int64) minute * USECS_PER_MINUTE +
           (int64) (second * USECS_PER_SEC);

    result = time;

    return result;
}

