make_timestamptz_at_timezone(PG_FUNCTION_ARGS)
{
    int32      year = PG_GETARG_INT32(0);
    int32      month = PG_GETARG_INT32(1);
    int32      day = PG_GETARG_INT32(2);
    int32      hour = PG_GETARG_INT32(3);
    int32      minute = PG_GETARG_INT32(4);
    float8     second = PG_GETARG_FLOAT8(5);
    text       *tz_name = PG_GETARG_TEXT_PP(6);
    TimestampTz result;
    struct pg_tm tm;
    fsec_t     fsec;
    int         tz;
    char        tzname[TZ_STRLEN_MAX + 1];
    pg_tz      *timezone;

    /* Initialize tm with specified values */
    tm.tm_year = year;
    tm.tm_mon = month;
    tm.tm_mday = day;
    tm.tm_hour = hour;
    tm.tm_min = minute;
    tm.tm_sec = (int) second;
    fsec = (second - tm.tm_sec) * 1000000;

    /* Get timezone */
    text_to_cstring_buffer(tz_name, tzname, sizeof(tzname));
    timezone = pg_tzset(tzname);
    if (timezone == NULL)
        PG_RETURN_NULL();

    tz = DetermineTimeZoneOffset(&tm, timezone);

    if (!IS_VALID_TIMESTAMP(year, month, day,
                           hour, minute, tm.tm_sec, fsec))
        PG_RETURN_NULL();

    if (tm2timestamp(&tm, fsec, &tz, &result) != 0)
        PG_RETURN_NULL();

    PG_RETURN_TIMESTAMPTZ(result);
}

