#include "postgres.h"
#include "fmgr.h"
#include "utils/builtins.h"
#include "utils/timestamp.h"

PG_FUNCTION_INFO_V1(timeofday);

Datum
timeofday(PG_FUNCTION_ARGS)
{
    TimestampTz now = GetCurrentTimestamp();
    char       *result;
    struct pg_tm tt,
               *tm = &tt;
    fsec_t      fsec;
    char        buf[MAXDATELEN + 1];
    char        zone[MAXDATELEN + 1];
    int         tz;

    if (timestamp2tm(now, &tz, tm, &fsec, NULL, NULL) != 0)
        ereport(ERROR,
                (errcode(ERRCODE_DATETIME_VALUE_OUT_OF_RANGE),
                 errmsg("timestamp out of range")));

    EncodeDateTime(tm, fsec, true, tz, NULL, DateStyle, buf);

    if (tm->tm_zone != NULL)
        strcpy(zone, tm->tm_zone);
    else
        sprintf(zone, "%+03d", -tz / SECS_PER_HOUR);

    result = palloc(MAXDATELEN + 1);
    snprintf(result, MAXDATELEN, "%s %s", buf, zone);

    PG_RETURN_TEXT_P(cstring_to_text(result));
}

