Datum
enum_first(PG_FUNCTION_ARGS)
{
    Oid            enum_oid = PG_GETARG_OID(0);
    Oid            typoid;
    HeapTuple      enum_tup;
    Form_pg_enum   enum_form;
    Datum          enum_datum;
    bool           is_null;
    ArrayType     *enum_array;
    Datum         *enum_values;
    int            num_elems;
    int16          typlen;
    bool           typbyval;
    char           typalign;

    /* Get the enum type OID */
    typoid = get_base_element_type(enum_oid);
    if (!OidIsValid(typoid))
        PG_RETURN_NULL();

    /* Get all enum values */
    enum_array = construct_array(typoid);
    if (enum_array == NULL)
        PG_RETURN_NULL();

    /* Get the first enum value */
    deconstruct_array(enum_array,
                     typoid,
                     get_typlenbyvalalign(typoid, &typlen, &typbyval, &typalign),
                     &typbyval, &typalign,
                     &enum_values, &is_null, &num_elems);

    if (num_elems < 1)
        PG_RETURN_NULL();

    /* Return the first enum value */
    PG_RETURN_DATUM(enum_values[0]);
}

