Datum
eenum_range_bounds(PG_FUNCTION_ARGS)
{
    Oid            enumtypoid;
    ArrayType  *result;
    Datum       *enum_values;
    int            num_elems;
    int            i;
    int            start_pos = 0;
    int            end_pos;
    Oid            start_oid;
    Oid            end_oid;

    if (PG_ARGISNULL(0) && PG_ARGISNULL(1))
        PG_RETURN_NULL();

    enumtypoid = get_fn_expr_argtype(fcinfo->flinfo, 0);
    if (!OidIsValid(enumtypoid))
        enumtypoid = get_fn_expr_argtype(fcinfo->flinfo, 1);
    if (!OidIsValid(enumtypoid))
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("could not determine input enum type")));

    get_enum_values(enumtypoid, &enum_values, &num_elems);
    end_pos = num_elems - 1;

    if (!PG_ARGISNULL(0))
    {
        start_oid = PG_GETARG_OID(0);
        for (i = 0; i < num_elems; i++)
        {
            if (enum_values[i] == start_oid)
            {
                start_pos = i;
                break;
            }
        }
        if (i == num_elems)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("start enum value not found in enum type")));
    }

    if (!PG_ARGISNULL(1))
    {
        end_oid = PG_GETARG_OID(1);
        for (i = 0; i < num_elems; i++)
        {
            if (enum_values[i] == end_oid)
            {
                end_pos = i;
                break;
            }
        }
        if (i == num_elems)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("end enum value not found in enum type")));
    }

    if (start_pos > end_pos)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("start enum value must not follow end enum value")));

    result = construct_array(enum_values + start_pos, end_pos - start_pos + 1,
                            enumtypoid, sizeof(Oid), true, 'i');

    PG_RETURN_ARRAYTYPE_P(result);
}

Datum
eenum_range_all(PG_FUNCTION_ARGS)
{
    Oid            enumtypoid;
    ArrayType  *result;
    Datum       *enum_values;
    int            num_elems;

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    enumtypoid = get_fn_expr_argtype(fcinfo->flinfo, 0);
    if (!OidIsValid(enumtypoid))
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("could not determine input enum type")));

    get_enum_values(enumtypoid, &enum_values, &num_elems);

    result = construct_array(enum_values, num_elems, enumtypoid, sizeof(Oid), true, 'i');

    PG_RETURN_ARRAYTYPE_P(result);
}

