#include "postgres.h"
#include "utils/geo_decls.h"

/* box_area */
Datum
box_area(PG_FUNCTION_ARGS)
{
    BOX        *box = PG_GETARG_BOX_P(0);
    float8      width,
                height;

    width = box->high.x - box->low.x;
    height = box->high.y - box->low.y;

    PG_RETURN_FLOAT8(width * height);
}

/* path_area */
Datum
path_area(PG_FUNCTION_ARGS)
{
    PATH       *path = PG_GETARG_PATH_P(0);
    int         i;
    float8      area = 0.0;

    if (!path->closed)
        PG_RETURN_NULL();

    for (i = 0; i < path->npts - 1; i++)
    {
        area += (path->p[i].x * path->p[i + 1].y) - (path->p[i].y * path->p[i + 1].x);
    }
    area += (path->p[i].x * path->p[0].y) - (path->p[i].y * path->p[0].x);

    PG_RETURN_FLOAT8(fabs(area) / 2.0);
}

/* circle_area */
Datum
circle_area(PG_FUNCTION_ARGS)
{
    CIRCLE     *circle = PG_GETARG_CIRCLE_P(0);
    float8      area;

    area = M_PI * circle->radius * circle->radius;

    PG_RETURN_FLOAT8(area);
}

/*
 * box_center - return center point of box
 */
Datum
box_center(PG_FUNCTION_ARGS)
{
    BOX        *box = PG_GETARG_BOX_P(0);
    Point      *result;

    result = (Point *) palloc(sizeof(Point));

    result->x = (box->high.x + box->low.x) / 2.0;
    result->y = (box->high.y + box->low.y) / 2.0;

    PG_RETURN_POINT_P(result);
}

/*
 * circle_center - return center point of circle
 */
Datum
circle_center(PG_FUNCTION_ARGS)
{
    CIRCLE     *circle = PG_GETARG_CIRCLE_P(0);
    Point      *result;

    result = (Point *) palloc(sizeof(Point));

    result->x = circle->center.x;
    result->y = circle->center.y;

    PG_RETURN_POINT_P(result);
}

