/*
 * boxes_bound_box - compute bounding box of two boxes
 */
Datum
boxes_bound_box(PG_FUNCTION_ARGS)
{
    BOX        *box1 = PG_GETARG_BOX_P(0);
    BOX        *box2 = PG_GETARG_BOX_P(1);
    BOX        *result;

    result = (BOX *) palloc(sizeof(BOX));

    result->high.x = Max(box1->high.x, box2->high.x);
    result->high.y = Max(box1->high.y, box2->high.y);
    result->low.x = Min(box1->low.x, box2->low.x);
    result->low.y = Min(box1->low.y, box2->low.y);

    PG_RETURN_BOX_P(result);
}

