/*
 * Circle constructors
 */

/* box_circle - convert box to smallest enclosing circle */
Datum
box_circle(PG_FUNCTION_ARGS)
{
    BOX            *box = PG_GETARG_BOX_P(0);
    CIRCLE         *circle;
    Point          *center;
    float8         radius;

    center = (Point *) palloc(sizeof(Point));
    center->x = (box->high.x + box->low.x) / 2.0;
    center->y = (box->high.y + box->low.y) / 2.0;

    radius = point_dt(center, &box->high);

    circle = (CIRCLE *) palloc(sizeof(CIRCLE));
    circle->center = *center;
    circle->radius = radius;

    PG_RETURN_CIRCLE_P(circle);
}

/* cr_circle - construct circle from center point and radius */
Datum
cr_circle(PG_FUNCTION_ARGS)
{
    Point          *center = PG_GETARG_POINT_P(0);
    float8         radius = PG_GETARG_FLOAT8(1);
    CIRCLE         *circle;

    if (radius < 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("cannot have circle with negative radius")));

    circle = (CIRCLE *) palloc(sizeof(CIRCLE));
    circle->center = *center;
    circle->radius = radius;

    PG_RETURN_CIRCLE_P(circle);
}

/* poly_circle - convert polygon to circle */
Datum
poly_circle(PG_FUNCTION_ARGS)
{
    POLYGON        *poly = PG_GETARG_POLYGON_P(0);
    CIRCLE         *circle;
    Point           center;
    float8         radius = 0.0;
    int             i;

    /* Calculate centroid */
    center.x = 0.0;
    center.y = 0.0;
    for (i = 0; i < poly->npts; i++)
    {
        center.x += poly->p[i].x;
        center.y += poly->p[i].y;
    }
    center.x /= poly->npts;
    center.y /= poly->npts;

    /* Calculate average distance */
    for (i = 0; i < poly->npts; i++)
        radius += point_dt(&center, &poly->p[i]);
    radius /= poly->npts;

    circle = (CIRCLE *) palloc(sizeof(CIRCLE));
    circle->center = center;
    circle->radius = radius;

    PG_RETURN_CIRCLE_P(circle);
}

