 * Convert box to 4-point polygon
 */
Datum
box_poly(PG_FUNCTION_ARGS)
{
    BOX        *box = PG_GETARG_BOX_P(0);
    POLYGON    *poly;
    int            i;

    poly = (POLYGON *) palloc0(sizeof(POLYGON));
    SET_VARSIZE(poly, sizeof(POLYGON));
    poly->npts = 4;
    poly->boundbox = *box;

    poly->p = (Point *) palloc(sizeof(Point) * poly->npts);

    poly->p[0].x = box->low.x;
    poly->p[0].y = box->low.y;

    poly->p[1].x = box->low.x;
    poly->p[1].y = box->high.y;

    poly->p[2].x = box->high.x;
    poly->p[2].y = box->high.y;

    poly->p[3].x = box->high.x;
    poly->p[3].y = box->low.y;

    PG_RETURN_POLYGON_P(poly);
}

/*
 * Convert closed path to polygon
 */
Datum
path_poly(PG_FUNCTION_ARGS)
{
    PATH       *path = PG_GETARG_PATH_P(0);
    POLYGON    *poly;
    int            i;

    if (!path->closed)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("open path cannot be converted to polygon")));

    poly = (POLYGON *) palloc0(sizeof(POLYGON));
    SET_VARSIZE(poly, sizeof(POLYGON) + sizeof(Point) * path->npts);
    poly->npts = path->npts;
    memcpy(&poly->boundbox, &path->boundbox, sizeof(BOX));

    poly->p = (Point *) palloc(sizeof(Point) * poly->npts);
    for (i = 0; i < path->npts; i++)
    {
        poly->p[i].x = path->p[i].x;
        poly->p[i].y = path->p[i].y;
    }

    PG_RETURN_POLYGON_P(poly);
}

/*
 * Convert circle to 12-point polygon
 */
Datum
circle_poly(PG_FUNCTION_ARGS)
{
    CIRCLE     *circle = PG_GETARG_CIRCLE_P(0);
    int            numpts = 12;
    POLYGON    *poly;
    int            i;
    double        angle;

    poly = (POLYGON *) palloc0(sizeof(POLYGON));
    SET_VARSIZE(poly, sizeof(POLYGON) + sizeof(Point) * numpts);
    poly->npts = numpts;

    /* Compute bounding box */
    poly->boundbox.high.x = circle->center.x + circle->radius;
    poly->boundbox.high.y = circle->center.y + circle->radius;
    poly->boundbox.low.x = circle->center.x - circle->radius;
    poly->boundbox.low.y = circle->center.y - circle->radius;

    poly->p = (Point *) palloc(sizeof(Point) * poly->npts);

    for (i = 0; i < numpts; i++)
    {
        angle = i * (2.0 * M_PI / numpts);
        poly->p[i].x = circle->center.x + (circle->radius * cos(angle));
        poly->p[i].y = circle->center.y + (circle->radius * sin(angle));
    }

    PG_RETURN_POLYGON_P(poly);
}

