#include "postgres.h"
#include "utils/inet.h"

Datum
network_hostmask(PG_FUNCTION_ARGS)
{
    inet       *ip = PG_GETARG_INET_PP(0);
    inet       *result;
    int         byte;
    int         nbits;
    int         ip_addrsize;
    int         maxbytes;
    unsigned char mask;
    unsigned char *dst;

    ip_addrsize = ip_addrsize(ip);
    maxbytes = (ip_addrsize + 7) / 8;
    nbits = ip_maxbits(ip) - ip_bits(ip);

    result = (inet *) palloc0(VARHDRSZ + maxbytes + 1);
    SET_INET_VARSIZE(result, VARHDRSZ + maxbytes + 1);
    result->family = ip->family;
    result->bits = ip_maxbits(ip);
    result->is_cidr = ip->is_cidr;

    dst = (unsigned char *) result->ipaddr;

    for (byte = 0; byte < maxbytes; byte++)
    {
        if (nbits >= 8)
        {
            mask = 0xFF;
            nbits -= 8;
        }
        else if (nbits > 0)
        {
            mask = (0xFF >> (8 - nbits));
            nbits = 0;
        }
        else
            mask = 0x00;

        dst[byte] = mask;
    }

    PG_RETURN_INET_P(result);
}

