#include "postgres.h"
#include "utils/inet.h"
#include "utils/builtins.h"

Datum
inet_merge(PG_FUNCTION_ARGS)
{
    inet *ip1 = PG_GETARG_INET_PP(0);
    inet *ip2 = PG_GETARG_INET_PP(1);
    int family,
        maxbits,
        bits;
    inet *dst;

    family = ip1->family;
    maxbits = (family == PGSQL_AF_INET) ? 32 : 128;

    /* Verify both inputs are of the same family */
    if (family != ip2->family)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("cannot merge addresses from different families")));

    /* Find the smallest common network */
    bits = bitncommon(ip1->ipaddr, ip2->ipaddr, Min(ip1->bits, ip2->bits));

    /* Allocate result */
    dst = (inet *) palloc0(sizeof(inet));
    SET_INET_VARSIZE(dst);
    dst->family = family;
    dst->bits = bits;

    /* Zero out the bits after the common prefix */
    if (bits > 0)
    {
        if (family == PGSQL_AF_INET6)
            ip_addr_copy_bits(dst->ipaddr, ip1->ipaddr, bits);
        else
            ((uint32 *) dst->ipaddr)[0] = ((uint32 *) ip1->ipaddr)[0] & (~0U << (32 - bits));
    }
    else
    {
        /* If no common bits, return 0.0.0.0/0 or ::/0 */
        MemSet(dst->ipaddr, 0, sizeof(dst->ipaddr));
    }

    PG_RETURN_INET_P(dst);
}

