network_network(PG_FUNCTION_ARGS)
{
    inet *addr = PG_GETARG_INET_PP(0);
    inet *result;
    int bits;

    result = (inet *) palloc0(sizeof(inet));
    *result = *addr;

    bits = ip_addr(&result->inet_data) ? ip_bits(&result->inet_data) : 0;
    if (bits < 0)
        bits = 0;

    if (bits > 0)
    {
        if (ip_family(&result->inet_data) == PGSQL_AF_INET)
        {
            if (bits > 32)
                bits = 32;
            ip_v4_mask(&result->inet_data, bits);
        }
        else
        {
            if (bits > 128)
                bits = 128;
            ip_v6_mask(&result->inet_data, bits);
        }
    }

    PG_RETURN_INET_P(result);
}

