Datum
inet_set_masklen(PG_FUNCTION_ARGS)
{
    inet    *src = PG_GETARG_INET_PP(0);
    int     masklen = PG_GETARG_INT32(1);
    inet    *dst;
    int     maxlen;
    int     byte;
    int     nbits;
    int     i;

    maxlen = ip_addrsize(src) * 8;
    if (masklen < 0 || masklen > maxlen)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid mask length: %d", masklen),
                 errhint("Mask length must be between 0 and %d for type inet.", maxlen)));

    dst = (inet *) palloc0(sizeof(inet));

    /* make sure any unused bits are zeroed */
    *dst = *src;
    SET_INET_VARSIZE(dst);

    /* apply new masklen */
    ip_bits(dst) = masklen;

    PG_RETURN_INET_P(dst);
}

Datum
cidr_set_masklen(PG_FUNCTION_ARGS)
{
    inet    *src = PG_GETARG_INET_PP(0);
    int     masklen = PG_GETARG_INT32(1);
    inet    *dst;
    int     maxlen;
    int     byte;
    int     nbits;
    int     i;

    maxlen = ip_addrsize(src) * 8;
    if (masklen < 0 || masklen > maxlen)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid mask length: %d", masklen),
                 errhint("Mask length must be between 0 and %d for type cidr.", maxlen)));

    dst = (inet *) palloc0(sizeof(inet));

    /* make sure any unused bits are zeroed */
    *dst = *src;
    SET_INET_VARSIZE(dst);

    /* apply new masklen and zero out host bits */
    ip_bits(dst) = masklen;
    byte = masklen / 8;
    nbits = masklen % 8;
    if (nbits > 0)
    {
        dst->ip_addr[byte] &= (0xFF << (8 - nbits));
        byte++;
    }
    for (i = byte; i < ip_addrsize(dst); i++)
        dst->ip_addr[i] = 0;

    PG_RETURN_INET_P(dst);
}

