PG_FUNCTION_INFO_V1(plainto_tsquery_byid);

Datum
plainto_tsquery_byid(PG_FUNCTION_ARGS)
{
    Oid            cfgId = PG_GETARG_OID(0);
    text       *in = PG_GETARG_TEXT_PP(1);
    TSConfigCacheEntry *cfg;
    TSParserCacheEntry *prs;
    TSQuery    query;
    List       *tokens;
    ListCell   *cell;
    ParseQueryNode *root = NULL;
    char       *str;
    int            len;

    cfg = lookup_ts_config_cache(cfgId);
    prs = lookup_ts_parser_cache(cfg->prsId);

    str = text_to_cstring(in);
    len = strlen(str);

    tokens = parsetext(cfg->prsId, str, len);

    foreach(cell, tokens)
    {
        ParsedText *prs = (ParsedText *) lfirst(cell);

        if (prs->type == TSPARSETXT_WORD)
        {
            ParseQueryNode *node = makeNode(ParseQueryNode);

            node->flags = QI_VAL;
            node->val = pnstrdup(prs->word, prs->len);
            node->weight = 0;
            node->prefix = false;

            if (root == NULL)
                root = node;
            else
            {
                ParseQueryNode *and = makeNode(ParseQueryNode);

                and->flags = QI_OPR;
                and->operator.oper = OP_AND;
                and->operator.left = root;
                and->operator.right = node;
                root = and;
            }
        }
    }

    if (root == NULL)
        query = TSQueryInit(false);
    else
        query = parseq(root, cfgId);

    PG_RETURN_TSQUERY(query);
}

