#include "postgres.h"
#include "utils/builtins.h"
#include "utils/regproc.h"
#include "tsearch/ts_utils.h"

PG_FUNCTION_INFO_V1(phraseto_tsquery);

Datum
phraseto_tsquery(PG_FUNCTION_ARGS)
{
    text       *in = PG_GETARG_TEXT_PP(0);
    Oid         cfgId;
    TSQuery     query;
    ParsedText  prs;
    int         count = 0;

    /* Determine the configuration to use */
    if (PG_NARGS() == 2)
        cfgId = get_ts_config_oid(PG_GETARG_TEXT_PP(1), false);
    else
        cfgId = getTSCurrentConfig(true);

    /* Parse the input text */
    parsetext(cfgId, &prs, PG_GETARG_TEXT_PP(0));

    /* Process the parsed text into a phrase query */
    query = phraseto_tsquery_internal(&prs, &count);

    PG_RETURN_TSQUERY(query);
}

static TSQuery
phraseto_tsquery_internal(ParsedText *prs, int *count)
{
    TSQuery     query;
    QueryItem  *ptr;
    int         i,
                len = 0;
    WordEntry  *arr = prs->words;

    *count = prs->curwords;

    /* Calculate total space needed */
    for (i = 0; i < prs->curwords; i++)
    {
        if (arr[i].len == 0)
            continue;
        len += arr[i].len + 1;  /* word + operator */
    }

    /* Allocate and initialize the query */
    query = (TSQuery) palloc0(HDRSIZETQ + len * sizeof(QueryItem));
    SET_VARSIZE(query, HDRSIZETQ + len * sizeof(QueryItem));
    ptr = GETQUERY(query);

    /* Build the query */
    for (i = 0; i < prs->curwords; i++)
    {
        if (arr[i].len == 0)
            continue;

        ptr->type = QI_VAL;
        ptr->qoperand.weight = 0;
        ptr->qoperand.prefix = false;
        ptr->qoperand.length = arr[i].len;
        memcpy(ptr->qoperand.word, arr[i].word, arr[i].len);

        if (i < prs->curwords - 1)
        {
            ptr++;
            ptr->type = QI_OPR;
            ptr->qoperator.oper = OP_PHRASE;
            ptr->qoperator.distance = 1;  /* default distance */
        }

        ptr++;
    }

    return query;
}

