Datum
websearch_to_tsquery(PG_FUNCTION_ARGS)
{
    text       *in = PG_GETARG_TEXT_PP(0);
    Oid         cfgId;
    TSConfigCacheEntry *cfg;
    TSParserCacheEntry *prs;
    TSQuery     query;
    ParseState *pstate;
    char       *str;
    int         len;

    /* Get the configuration */
    if (PG_NARGS() == 2)
        cfgId = get_ts_config_oid(PG_GETARG_TEXT_PP(1), false);
    else
        cfgId = getTSCurrentConfig(true);

    cfg = lookup_ts_config_cache(cfgId);
    prs = lookup_ts_parser_cache(cfg->prsId);

    /* Parse the input string */
    str = text_to_cstring(in);
    len = strlen(str);

    pstate = init_parsestate(prs);
    pstate->addOr = true;  /* recognize 'or' as OR operator */
    pstate->addNot = true; /* recognize '-' as NOT operator */
    pstate->addPhrase = true; /* recognize quoted phrases */

    query = parse_tsquery(pstate, str, len, cfg->cfgId, NULL);

    pfree(str);
    free_parsestate(pstate);

    if (query->size == 0)
        PG_RETURN_TSQUERY(query);

    PG_RETURN_TSQUERY(query);
}

