#include "postgres.h"
#include "utils/builtins.h"
#include "tsearch/ts_utils.h"

PG_FUNCTION_INFO_V1(tsquerytree);

Datum
tsquerytree(PG_FUNCTION_ARGS)
{
    TSQuery    query = PG_GETARG_TSQUERY(0);
    TSQuery    res;
    MemoryContext outercontext = CurrentMemoryContext;
    MemoryContext oldcontext;
    char       *buf;
    text       *result;
    int         len;

    if (query->size == 0)
        PG_RETURN_TEXT_P(cstring_to_text(""));

    oldcontext = MemoryContextSwitchTo(outercontext);

    res = clean_NOT_v2(query, NULL);

    if (res)
    {
        if (res->size == 0 || (res->size == 1 && res->items[0].type == QI_VAL))
        {
            if (res->size == 1)
            {
                buf = get_operand(res->items, res->operand, res->items[0].qoperand.pos, &len);
                result = cstring_to_text_with_len(buf, len);
            }
            else
                result = cstring_to_text("");

            MemoryContextSwitchTo(oldcontext);
            PG_RETURN_TEXT_P(result);
        }
        else
        {
            MemoryContextSwitchTo(oldcontext);
            PG_RETURN_TSQUERY(res);
        }
    }
    else
    {
        MemoryContextSwitchTo(oldcontext);
        PG_RETURN_TEXT_P(cstring_to_text(""));
    }
}

