Datum
tsvector_strip(PG_FUNCTION_ARGS)
{
    TSVector    in = PG_GETARG_TSVECTOR(0);
    TSVector    out;
    WordEntry  *inptr = ARRPTR(in);
    WordEntry  *outptr;
    char       *inwords = STRPTR(in);
    char       *outwords;
    int         i;
    int         len = in->size;
    int         outlen;

    if (in->size == 0)
        PG_RETURN_TSVECTOR(in);

    outlen = CALCDATASIZE(in->size, in->size * (inptr[0].len + 1));
    out = (TSVector) palloc0(outlen);
    SET_VARSIZE(out, outlen);
    out->size = in->size;
    outptr = ARRPTR(out);
    outwords = STRPTR(out);

    for (i = 0; i < len; i++)
    {
        memcpy(outwords, inwords + inptr[i].pos, inptr[i].len);
        outptr[i].haspos = 0;
        outptr[i].len = inptr[i].len;
        outptr[i].pos = outwords - STRPTR(out);
        outwords += inptr[i].len + 1; /* +1 for null terminator */
    }

    PG_RETURN_TSVECTOR(out);
}

