Datum
to_tsvector_byid(PG_FUNCTION_ARGS)
{
    Oid            cfgId = PG_GETARG_OID(0);
    text       *in = PG_GETARG_TEXT_PP(1);
    TSVector    result;
    ParsedText  prs;

    prs.lenwords = 32;
    prs.curwords = 0;
    prs.pos = 0;
    prs.words = (ParsedWord *) palloc(sizeof(ParsedWord) * prs.lenwords);

    parsetext(cfgId, &prs, VARDATA_ANY(in), VARSIZE_ANY_EXHDR(in));

    result = make_tsvector(&prs);
    PG_FREE_IF_COPY(in, 1);

    PG_RETURN_TSVECTOR(result);
}

static void
json_to_tsvector_worker(Oid cfgId, Jsonb *jb, ParsedText *prs, int *pos)
{
    JsonbIterator *it;
    JsonbValue    *val;
    JsonbIteratorToken type;

    it = JsonbIteratorInit(&jb->root);

    while ((type = JsonbIteratorNext(&it, &val, true)) != WJB_DONE)
    {
        if (type == WJB_VALUE && val->type == jbvString)
        {
            parsetext(cfgId, prs, val->val.string.val, val->val.string.len);
            if (prs->curwords > 0)
                (*pos)++;
        }
    }
}

Datum
to_tsvector(PG_FUNCTION_ARGS)
{
    Oid            cfgId = get_ts_config_oid(textToQualifiedNameList(PG_GETARG_TEXT_PP(0)), false);
    text       *in = PG_GETARG_TEXT_PP(1);
    TSVector    result;
    ParsedText  prs;
    int            pos = 1;

    prs.lenwords = 32;
    prs.curwords = 0;
    prs.pos = 0;
    prs.words = (ParsedWord *) palloc(sizeof(ParsedWord) * prs.lenwords);

    if (PG_ARGISNULL(1))
        PG_RETURN_NULL();

    if (PG_ARGISNULL(0))
        cfgId = getTSCurrentConfig(true);

    if (IsA(in, Jsonb))
    {
        json_to_tsvector_worker(cfgId, (Jsonb *) in, &prs, &pos);
    }
    else if (IsA(in, Json))
    {
        Jsonb       *jb = JsonbValueToJsonb(JsonToJsonb(in));
        json_to_tsvector_worker(cfgId, jb, &prs, &pos);
    }
    else
    {
        parsetext(cfgId, &prs, VARDATA_ANY(in), VARSIZE_ANY_EXHDR(in));
    }

    result = make_tsvector(&prs);
    PG_FREE_IF_COPY(in, 1);

    PG_RETURN_TSVECTOR(result);
}

