Datum
tsvector_delete_lexeme(PG_FUNCTION_ARGS)
{
    TSVector    in = PG_GETARG_TSVECTOR(0);
    text       *lexeme = PG_GETARG_TEXT_PP(1);
    TSVector    out;
    WordEntry  *inptr = ARRPTR(in);
    WordEntry  *outptr;
    char       *inlex,
               *outlex;
    int         i,
                outlen = 0,
                lexemelen = VARSIZE_ANY_EXHDR(lexeme);
    char       *lexeme_str = VARDATA_ANY(lexeme);

    /* Check if input is empty */
    if (in->size == 0)
        PG_RETURN_TSVECTOR(in);

    /* First pass: calculate size of output */
    for (i = 0; i < in->size; i++)
    {
        inlex = STRPTR(in) + inptr[i].pos;
        if (!(inptr[i].len == lexemelen &&
              strncmp(inlex, lexeme_str, lexemelen) == 0))
            outlen++;
    }

    /* If no lexemes to remove, return original */
    if (outlen == in->size)
        PG_RETURN_TSVECTOR(in);

    /* Allocate output vector */
    out = (TSVector) palloc0(CALCDATASIZE(outlen, in->len));
    SET_VARSIZE(out, CALCDATASIZE(outlen, in->len));
    out->size = outlen;

    /* Second pass: copy data */
    outptr = ARRPTR(out);
    outlex = STRPTR(out);
    for (i = 0; i < in->size; i++)
    {
        inlex = STRPTR(in) + inptr[i].pos;
        if (!(inptr[i].len == lexemelen &&
              strncmp(inlex, lexeme_str, lexemelen) == 0))
        {
            memcpy(outlex, inlex, inptr[i].len);
            outptr->haspos = inptr[i].haspos;
            outptr->len = inptr[i].len;
            outptr->pos = outlex - STRPTR(out);
            outlex += outptr->len;
            if (outptr->haspos)
            {
                uint16      *inpos = POSDATAPTR(in, inptr + i);
                uint16      *outpos = POSDATAPTR(out, outptr);
                int         npos = POSDATALEN(in, inptr + i);

                memcpy(outpos, inpos, npos * sizeof(uint16) + sizeof(uint16));
                outlex += npos * sizeof(uint16) + sizeof(uint16);
            }
            outptr++;
        }
    }

    PG_RETURN_TSVECTOR(out);
}

PG_FUNCTION_INFO_V1(tsvector_delete_lexemes);

Datum
tsvector_delete_lexemes(PG_FUNCTION_ARGS)
{
    TSVector    in = PG_GETARG_TSVECTOR(0);
    ArrayType  *lexemes = PG_GETARG_ARRAYTYPE_P(1);
    TSVector    out;
    WordEntry  *inptr = ARRPTR(in);
    WordEntry  *outptr;
    char       *inlex,
               *outlex;
    int         i,
                j,
                outlen = 0,
                nlexemes;
    text      **lexeme_list;
    bool       *to_delete;
    bool        skip;

    /* Check if input is empty */
    if (in->size == 0)
        PG_RETURN_TSVECTOR(in);

    /* Deconstruct the array of lexemes */
    deconstruct_array(lexemes, TEXTOID, -1, false, 'i',
                      (void ***) &lexeme_list, NULL, &nlexemes);

    /* Allocate temporary array to mark lexemes to delete */
    to_delete = (bool *) palloc0(sizeof(bool) * in->size);

    /* First pass: identify lexemes to delete */
    for (i = 0; i < in->size; i++)
    {
        inlex = STRPTR(in) + inptr[i].pos;
        for (j = 0; j < nlexemes; j++)
        {
            int         lexemelen = VARSIZE_ANY_EXHDR(lexeme_list[j]);
            char       *lexeme_str = VARDATA_ANY(lexeme_list[j]);

            if (inptr[i].len == lexemelen &&
                strncmp(inlex, lexeme_str, lexemelen) == 0)
            {
                to_delete[i] = true;
                break;
            }
        }
        if (!to_delete[i])
            outlen++;
    }

    /* If no lexemes to remove, return original */
    if (outlen == in->size)
    {
        pfree(to_delete);
        pfree(lexeme_list);
        PG_RETURN_TSVECTOR(in);
    }

    /* Allocate output vector */
    out = (TSVector) palloc0(CALCDATASIZE(outlen, in->len));
    SET_VARSIZE(out, CALCDATASIZE(outlen, in->len));
    out->size = outlen;

    /* Second pass: copy data */
    outptr = ARRPTR(out);
    outlex = STRPTR(out);
    for (i = 0; i < in->size; i++)
    {
        if (!to_delete[i])
        {
            inlex = STRPTR(in) + inptr[i].pos;
            memcpy(outlex, inlex, inptr[i].len);
            outptr->haspos = inptr[i].haspos;
            outptr->len = inptr[i].len;
            outptr->pos = outlex - STRPTR(out);
            outlex += outptr->len;
            if (outptr->haspos)
            {
                uint16      *inpos = POSDATAPTR(in, inptr + i);
                uint16      *outpos = POSDATAPTR(out, outptr);
                int         npos = POSDATALEN(in, inptr + i);

                memcpy(outpos, inpos, npos * sizeof(uint16) + sizeof(uint16));
                outlex += npos * sizeof(uint16) + sizeof(uint16);
            }
            outptr++;
        }
    }

    pfree(to_delete);
    pfree(lexeme_list);
    PG_RETURN_TSVECTOR(out);
}

