#include "postgres.h"
#include "executor/spi.h"
#include "fmgr.h"
#include "tsearch/ts_type.h"
#include "tsearch/ts_utils.h"
#include "utils/builtins.h"

PG_MODULE_MAGIC;

PG_FUNCTION_INFO_V1(tsquery_rewrite);
PG_FUNCTION_INFO_V1(tsquery_rewrite_query);

static TSQuery
do_tsquery_rewrite(TSQuery query, TSQuery target, TSQuery substitute)
{
    QTNode     *qtree,
               *tgt_tree,
               *sub_tree,
               *res_tree;
    MemoryContext outercontext = CurrentMemoryContext;
    MemoryContext oldcontext;

    if (query == NULL || query->size == 0)
        return query;

    if (target == NULL || target->size == 0)
        return query;

    if (substitute == NULL || substitute->size == 0)
        return query;

    oldcontext = MemoryContextSwitchTo(outercontext);

    qtree = QT2QTN(GETQUERY(query), GETOPERAND(query));
    QTNTernary(qtree);
    QTNSort(qtree);

    tgt_tree = QT2QTN(GETQUERY(target), GETOPERAND(target));
    QTNTernary(tgt_tree);
    QTNSort(tgt_tree);

    sub_tree = QT2QTN(GETQUERY(substitute), GETOPERAND(substitute));
    QTNTernary(sub_tree);
    QTNSort(sub_tree);

    res_tree = findsubquery(qtree, tgt_tree, sub_tree, NULL);

    if (res_tree)
    {
        QTNFree(qtree);
        qtree = res_tree;
    }

    QTNFree(tgt_tree);
    QTNFree(sub_tree);

    QTNSort(qtree);

    query = QTN2QT(qtree);

    QTNFree(qtree);
    MemoryContextSwitchTo(oldcontext);

    return query;
}

Datum
tsquery_rewrite(PG_FUNCTION_ARGS)
{
    TSQuery     query = PG_GETARG_TSQUERY(0);
    TSQuery     target = PG_GETARG_TSQUERY(1);
    TSQuery     substitute = PG_GETARG_TSQUERY(2);
    TSQuery     res;

    res = do_tsquery_rewrite(query, target, substitute);

    if (res == query)
        PG_RETURN_TSQUERY(query);
    else
        PG_RETURN_TSQUERY(res);
}

Datum
tsquery_rewrite_query(PG_FUNCTION_ARGS)
{
    TSQuery     query = PG_GETARG_TSQUERY(0);
    text       *sql = PG_GETARG_TEXT_PP(1);
    TSQuery     res = NULL;
    int         ret;
    uint32      i;
    bool        isnull;
    TupleDesc   tupdesc;
    SPIPlanPtr  plan;
    Portal      portal;

    if (query == NULL || query->size == 0)
        PG_RETURN_TSQUERY(query);

    SPI_connect();

    plan = SPI_prepare(text_to_cstring(sql), 0, NULL);
    if (plan == NULL)
        elog(ERROR, "SPI_prepare failed for tsquery rewrite query");

    portal = SPI_cursor_open(NULL, plan, NULL, NULL, true);
    if (portal == NULL)
        elog(ERROR, "SPI_cursor_open failed for tsquery rewrite query");

    ret = SPI_cursor_fetch(portal, true, 100);
    if (ret != SPI_OK_FETCH)
        elog(ERROR, "SPI_cursor_fetch failed for tsquery rewrite query");

    tupdesc = SPI_tuptable->tupdesc;
    if (tupdesc->natts != 2)
        elog(ERROR, "tsquery rewrite query must return two columns");

    for (i = 0; i < SPI_processed; i++)
    {
        HeapTuple   tuple = SPI_tuptable->vals[i];
        Datum       t_datum,
                    s_datum;
        TSQuery     target,
                    substitute;

        t_datum = SPI_getbinval(tuple, tupdesc, 1, &isnull);
        if (isnull)
            elog(ERROR, "tsquery rewrite target cannot be NULL");
        target = DatumGetTSQuery(t_datum);

        s_datum = SPI_getbinval(tuple, tupdesc, 2, &isnull);
        if (isnull)
            elog(ERROR, "tsquery rewrite substitute cannot be NULL");
        substitute = DatumGetTSQuery(s_datum);

        if (res == NULL)
            res = do_tsquery_rewrite(query, target, substitute);
        else
            res = do_tsquery_rewrite(res, target, substitute);
    }

    SPI_cursor_close(portal);
    SPI_finish();

    if (res == NULL)
        PG_RETURN_TSQUERY(query);
    else
        PG_RETURN_TSQUERY(res);
}

