    TSVector    result;
    ParsedText *prs;
    TSParserCacheEntry *prsId;
    TSCfgInfo   *cfgInfo;
    int            type,
                len;
    char       *token;
    HeapTuple    tuple;
    TupleDesc    tupdesc;
    Datum        values[6];
    bool        nulls[6] = {false, false, false, false, false, false};
    ArrayType  *arr;
    int            i;
    MemoryContext oldcontext;

    /* Setup output tuple descriptor */
    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    /* Get the configuration */
    if (PG_NARGS() == 1)
    {
        cfgId = getTSCurrentConfig(true);
        in_text = PG_GETARG_TEXT_PP(0);
    }
    else
    {
        text       *cfgname = PG_GETARG_TEXT_PP(0);

        cfgId = get_ts_config_oid(textToQualifiedNameList(cfgname), false);
        in_text = PG_GETARG_TEXT_PP(1);
    }

    cfgInfo = lookup_ts_config_cache(cfgId);
    prsId = lookup_ts_parser_cache(cfgInfo->prsId);

    /* Parse the input text */
    prs = (ParsedText *) palloc(sizeof(ParsedText));
    parsetext(cfgInfo->prsId, prs, text_to_cstring(in_text), cfgInfo->cfgId);

    /* Prepare output array */
    oldcontext = MemoryContextSwitchTo(fcinfo->flinfo->fn_mcxt);
    arr = construct_empty_array(TEXTOID);
    MemoryContextSwitchTo(oldcontext);

    /* Build and return the result tuple */
    for (i = 0; i < prs->curwords; i++)
    {
        values[0] = CStringGetTextDump(prsId->tokenTypes[prs->words[i].type].name);
        values[1] = CStringGetTextDump(prsId->tokenTypes[prs->words[i].type].descr);
        values[2] = CStringGetTextDump(prs->words[i].word);
        values[3] = ObjectIdGetDatum(cfgInfo->dictIds[0]);  /* Assume single dictionary for simplicity */
        values[4] = CStringGetTextDump(get_dict_name(cfgInfo->dictIds[0]));
        values[5] = PointerGetDatum(arr);

        tuple = heap_form_tuple(tupdesc, values, nulls);
        SRF_RETURN_NEXT(fcinfo, HeapTupleGetDatum(tuple));
    }

    SRF_RETURN_DONE(fcinfo);
}

