Datum
ts_lexize(PG_FUNCTION_ARGS)
{
    Oid         dictId = PG_GETARG_OID(0);
    text       *in = PG_GETARG_TEXT_PP(1);
    TSDictionaryCacheEntry *dict;
    TSLexeme   *res;
    ArrayType  *array;
    Datum      *elems;
    int         nelems = 0;
    int         i;
    char       *word;

    dict = lookup_ts_dictionary_cache(dictId);

    word = text_to_cstring(in);

    res = (TSLexeme *) DatumGetPointer(FunctionCall4(&dict->lexize,
                                                  PointerGetDatum(dict->dictData),
                                                  PointerGetDatum(word),
                                                  Int32GetDatum(strlen(word)),
                                                  PointerGetDatum(NULL)));

    if (res == NULL)
        PG_RETURN_NULL();

    if (res->lexeme == NULL)
    {
        pfree(res);
        PG_RETURN_NULL();
    }

    for (i = 0; res[i].lexeme != NULL; i++)
    {
        if (res[i].flags & TSL_FILTER)
            nelems++;
    }

    if (nelems == 0)
    {
        pfree(res);
        PG_RETURN_NULL();
    }

    elems = (Datum *) palloc(nelems * sizeof(Datum));
    for (i = 0, nelems = 0; res[i].lexeme != NULL; i++)
    {
        if (res[i].flags & TSL_FILTER)
            elems[nelems++] = CStringGetTextDatum(res[i].lexeme);
    }

    array = construct_array(elems, nelems,
                          TEXTOID, -1, false, 'i');

    pfree(elems);
    pfree(res);
    PG_RETURN_ARRAYTYPE_P(array);
}

