typedef struct
{
    char       *lexeme;
    int32       ndoc;
    int32       nentry;
} LexemeStat;

static int
lexeme_stat_compare(const void *a, const void *b)
{
    const LexemeStat *la = (const LexemeStat *) a;
    const LexemeStat *lb = (const LexemeStat *) b;

    return strcmp(la->lexeme, lb->lexeme);
}

static void
compute_tsvector_stats(TSVector vector, LexemeStat **stats, int *nstats)
{
    WordEntry  *ptr = ARRPTR(vector);
    int         i;
    int         len = vector->size;
    LexemeStat *newstats;
    int         n = *nstats;

    for (i = 0; i < len; i++)
    {
        char       *lexeme = STRPTR(vector) + ptr[i].pos;
        int         lexemelen = ptr[i].len;
        bool        found = false;
        int         j;

        for (j = 0; j < n; j++)
        {
            if (strncmp((*stats)[j].lexeme, lexeme, lexemelen) == 0 &&
                (*stats)[j].lexeme[lexemelen] == '\0')
            {
                (*stats)[j].ndoc++;
                (*stats)[j].nentry += ptr[i].haspos ? POSDATALEN(vector, &ptr[i]) : 1;
                found = true;
                break;
            }
        }

        if (!found)
        {
            newstats = (LexemeStat *) repalloc(*stats, (n + 1) * sizeof(LexemeStat));
            *stats = newstats;
            (*stats)[n].lexeme = palloc(lexemelen + 1);
            memcpy((*stats)[n].lexeme, lexeme, lexemelen);
            (*stats)[n].lexeme[lexemelen] = '\0';
            (*stats)[n].ndoc = 1;
            (*stats)[n].nentry = ptr[i].haspos ? POSDATALEN(vector, &ptr[i]) : 1;
            n++;
        }
    }

    *nstats = n;
}

