#include "postgres.h"
#include "fmgr.h"
#include "utils/jsonapi.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(to_json);

Datum
to_json(PG_FUNCTION_ARGS)
{
    Datum       val = PG_GETARG_DATUM(0);
    Oid         valtype = get_fn_expr_argtype(fcinfo->flinfo, 0);
    Oid         json_oid = JSONOID;
    Oid         jsonb_oid = JSONBOID;

    if (valtype == InvalidOid)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                errmsg("could not determine input data type"));

    /* If input is already json/jsonb, just return it */
    if (valtype == json_oid || valtype == jsonb_oid)
        PG_RETURN_DATUM(val);

    /* Try to use existing cast to json if available */
    if (OidIsValid(valtype) && find_coercion_pathway(json_oid, valtype, COERCION_EXPLICIT, NULL))
    {
        Datum result = DirectFunctionCall1(valtypeout, val);
        text *json_text = DatumGetTextP(result);
        PG_RETURN_TEXT_P(json_text);
    }

    /* Otherwise produce a scalar JSON value */
    if (valtype == BOOLOID || valtype == INT2OID || valtype == INT4OID || 
        valtype == INT8OID || valtype == FLOAT4OID || valtype == FLOAT8OID || 
        valtype == NUMERICOID)
    {
        /* Numeric types and booleans can be directly represented in JSON */
        PG_RETURN_DATUM(val);
    }
    else if (valtype == TEXTOID || valtype == VARCHAROID || valtype == BPCHAROID)
    {
        /* Text types need to be properly escaped */
        text *in_text = DatumGetTextPP(val);
        text *out_text = cstring_to_text(escape_json(TextDatumGetCString(in_text)));
        PG_RETURN_TEXT_P(out_text);
    }
    else if (valtype == UNKNOWNOID)
    {
        /* Unknown type treated as text */
        text *in_text = DatumGetTextPP(val);
        text *out_text = cstring_to_text(escape_json(TextDatumGetCString(in_text)));
        PG_RETURN_TEXT_P(out_text);
    }
    else
    {
        /* For all other types, use their text representation */
        Oid outfunc;
        bool isVarlena;
        getTypeOutputInfo(valtype, &outfunc, &isVarlena);
        char *str = OidOutputFunctionCall(outfunc, val);
        text *out_text = cstring_to_text(escape_json(str));
        PG_RETURN_TEXT_P(out_text);
    }
}

