PG_FUNCTION_INFO_V1(json_build_object_noargs);

Datum
json_build_object(PG_FUNCTION_ARGS)
{
    JsonParseErrorType result;
    JsonLexContext *lex = NULL;
    JsonLexContext *lex_res = NULL;
    StringInfoData str;
    int         nargs;
    int         i;

    if (PG_NARGS() == 0)
        PG_RETURN_NULL();

    if (PG_NARGS() % 2 != 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid number of arguments: expected even number of key/value pairs")));

    nargs = PG_NARGS();

    initStringInfo(&str);
    appendStringInfoChar(&str, '{');

    for (i = 0; i < nargs; i += 2)
    {
        Datum       key_datum = PG_GETARG_DATUM(i);
        Datum       val_datum = PG_GETARG_DATUM(i + 1);
        text       *key_text;
        JsonValue    val_json;
        char       *key_str;
        char       *val_str;

        if (i > 0)
            appendStringInfoChar(&str, ',');

        /* Convert key to text */
        key_text = DatumGetTextPP(key_datum);
        key_str = text_to_cstring(key_text);

        /* Convert value to JSON */
        val_json = DatumToJsonValue(val_datum);
        val_str = JsonValueToCString(NULL, &val_json);

        appendStringInfo(&str, "\"%s\":%s", key_str, val_str);

        pfree(key_str);
        pfree(val_str);
    }

    appendStringInfoChar(&str, '}');

    lex = makeJsonLexContextCstringLen(str.data, str.len, true);
    result = pg_parse_json(lex, &lex_res);

    if (result != JSON_SUCCESS)
        json_ereport_error(result, lex);

    PG_RETURN_TEXT_P(cstring_to_text(str.data));
}

