Datum
json_object(PG_FUNCTION_ARGS)
{
    ArrayType  *arr = PG_GETARG_ARRAYTYPE_P(0);
    Oid         arr_typeid = ARR_ELEMTYPE(arr);
    Datum      *elem_values;
    bool       *elem_nulls;
    int         elem_count;
    StringInfoData result;
    int         i;

    deconstruct_array(arr, arr_typeid, -1, false, 'i',
                      &elem_values, &elem_nulls, &elem_count);

    if (elem_count % 2 != 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("array must have even number of elements")));

    initStringInfo(&result);
    appendStringInfoChar(&result, '{');

    for (i = 0; i < elem_count; i += 2)
    {
        if (elem_nulls[i])
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("null value not allowed for object key")));

        if (i > 0)
            appendStringInfoChar(&result, ',');

        appendStringInfoChar(&result, '"');
        escape_json(&result, TextDatumGetCString(elem_values[i]));
        appendStringInfoChar(&result, '"');
        appendStringInfoString(&result, ":");

        if (!elem_nulls[i + 1])
        {
            appendStringInfoChar(&result, '"');
            escape_json(&result, TextDatumGetCString(elem_values[i + 1]));
            appendStringInfoChar(&result, '"');
        }
        else
            appendStringInfoString(&result, "null");
    }

    appendStringInfoChar(&result, '}');
    PG_RETURN_TEXT_P(cstring_to_text(result.data));
}

