#include "utils/jsonb.h"
#include "utils/jsonapi.h"

PG_FUNCTION_INFO_V1(json_in);

Datum
json_in(PG_FUNCTION_ARGS)
{
    text       *json_text = PG_GETARG_TEXT_PP(0);
    JsonParseErrorType error;
    JsonLexContext *lex;
    JsonSemAction sem;
    bool        unique_keys = false;

    if (PG_NARGS() > 1 && PG_GETARG_BOOL(1))
        unique_keys = true;

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    lex = makeJsonLexContext(json_text, false);

    memset(&sem, 0, sizeof(sem));
    sem.semstate = (void *) &unique_keys;
    sem.object_start = NULL;
    sem.array_start = NULL;
    sem.scalar = NULL;
    sem.object_field_start = NULL;
    sem.array_element_start = NULL;
    sem.object_end = NULL;
    sem.array_end = NULL;

    if (unique_keys)
        sem.object_field_start = check_duplicate_keys;

    pg_parse_json(lex, &sem);

    PG_RETURN_TEXT_P(PG_GETARG_TEXT_PP(0));
}

static void
check_duplicate_keys(void *state, char *fname, bool isnull)
{
    bool       *unique_keys = (bool *) state;
    static HTAB *seen_keys = NULL;
    bool        found;
    char       *key;

    if (!*unique_keys)
        return;

    if (seen_keys == NULL)
    {
        HASHCTL     hash_ctl;

        memset(&hash_ctl, 0, sizeof(hash_ctl));
        hash_ctl.keysize = NAMEDATALEN;
        hash_ctl.entrysize = NAMEDATALEN;
        hash_ctl.hcxt = CurrentMemoryContext;

        seen_keys = hash_create("JSON key hashtable",
                               16,
                               &hash_ctl,
                               HASH_ELEM | HASH_CONTEXT);
    }

    key = pstrdup(fname);
    (void) hash_search(seen_keys, key, HASH_ENTER, &found);

    if (found)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("duplicate JSON object key value: %s", key)));
}

