        result = cstring_to_text_with_len(json_str, json_len);
        PG_RETURN_BYTEA_P(result);
    }
    else
    {
        /* For text output, just return the JSON as text */
        JsonLexContext *lex = makeJsonLexContext(json_datum, true);
        char *json_str = lex->input;
        size_t json_len = strlen(json_str);

        result = cstring_to_text_with_len(json_str, json_len);
        PG_RETURN_TEXT_P(result);
    }
}

