    JsonbValue *jbv;
    JsonbIterator *it;
    JsonbParseState *state = NULL;
    JsonbIteratorToken type;

    if (SRF_IS_FIRSTCALL())
    {
        MemoryContext oldcontext;
        Jsonb       *jb;
