        it = JsonbIteratorInit(&jb->root);

        funcctx->user_fctx = it;
        MemoryContextSwitchTo(oldcontext);
    }

    funcctx = SRF_PERCALL_SETUP();
    it = (JsonbIterator *) funcctx->user_fctx;

    if ((type = JsonbIteratorNext(&it, &jbv, true)) != WJB_DONE)
    {
        if (type == WJB_ELEM && jbv->type == jbvString)
        {
            text *result = cstring_to_text_with_len(jbv->val.string.val, jbv->val.string.len);
            SRF_RETURN_NEXT(funcctx, PointerGetDatum(result));
        }
        else
        {
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("input JSON must be an array")));
        }
    }

    SRF_RETURN_DONE(funcctx);
}

#include "postgres.h"
#include "utils/jsonapi.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(json_array_length);

Datum
json_array_length(PG_FUNCTION_ARGS)
{
    text *json_text = PG_GETARG_TEXT_PP(0);
    JsonLexContext *lex;
    JsonTokenType tok;
    int array_length = 0;
    bool is_array = false;

    lex = makeJsonLexContext(json_text, false);

    json_lex(lex);
    tok = lex->token_type;

    if (tok != JSON_TOKEN_ARRAY_START)
        PG_RETURN_NULL();

    is_array = true;

    while (true)
    {
        json_lex(lex);
        tok = lex->token_type;

        if (tok == JSON_TOKEN_ARRAY_END)
            break;

        if (tok == JSON_TOKEN_ARRAY_START)
        {
            /* Skip nested arrays */
            int nest_level = 1;
            while (nest_level > 0)
            {
                json_lex(lex);
                tok = lex->token_type;

                if (tok == JSON_TOKEN_ARRAY_START)
                    nest_level++;
                else if (tok == JSON_TOKEN_ARRAY_END)
                    nest_level--;
            }
        }
        else if (tok == JSON_TOKEN_OBJECT_START)
        {
            /* Skip nested objects */
            int nest_level = 1;
            while (nest_level > 0)
            {
                json_lex(lex);
                tok = lex->token_type;

                if (tok == JSON_TOKEN_OBJECT_START)
                    nest_level++;
                else if (tok == JSON_TOKEN_OBJECT_END)
                    nest_level--;
            }
        }

        array_length++;
    }

    PG_RETURN_INT32(array_length);
}

PG_FUNCTION_INFO_V1(jsonb_array_length);

Datum
jsonb_array_length(PG_FUNCTION_ARGS)
{
    Jsonb *jb = PG_GETARG_JSONB_P(0);
    JsonbIterator *it;
    JsonbValue v;
    int array_length = 0;
    bool is_array = false;

    it = JsonbIteratorInit(&jb->root);

    while ((it = JsonbIteratorNext(&it, &v, false)) != NULL)
    {
        if (v.type == jbvArray)
        {
            is_array = true;
            array_length = v.val.array.nElems;
            break;
        }
    }

    if (!is_array)
        PG_RETURN_NULL();

    PG_RETURN_INT32(array_length);
}

