#include "postgres.h"
#include "utils/jsonapi.h"
#include "utils/builtins.h"
#include "funcapi.h"

PG_FUNCTION_INFO_V1(json_each_text);

Datum
json_each_text(PG_FUNCTION_ARGS)
{
    FuncCallContext *funcctx;
    JsonLexContext *lex;
    JsonTokenType tok;
    text *json;

    if (SRF_IS_FIRSTCALL())
    {
        MemoryContext oldcontext;
        TupleDesc tupdesc;

        funcctx = SRF_FIRSTCALL_INIT();
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

        /* Build a tuple descriptor for our result type */
        if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
            ereport(ERROR,
                    (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                     errmsg("function returning record called in context "
                            "that cannot accept type record")));

        funcctx->tuple_desc = BlessTupleDesc(tupdesc);

        json = PG_GETARG_TEXT_PP(0);
        lex = makeJsonLexContext(json, false);

        /* Initialize lexer to first token */
        json_lex(lex);

        /* Check we have a valid object */
        if (lex->token_type != JSON_TOKEN_OBJECT_START)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("cannot call json_each_text on a non-object"));

        funcctx->user_fctx = lex;
        MemoryContextSwitchTo(oldcontext);
    }

    funcctx = SRF_PERCALL_SETUP();
    lex = (JsonLexContext *) funcctx->user_fctx;

    /* Get next token */
    json_lex(lex);
    tok = lex->token_type;

    if (tok == JSON_TOKEN_OBJECT_END)
    {
        /* End of object */
        SRF_RETURN_DONE(funcctx);
    }

    if (tok != JSON_TOKEN_STRING)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("expected string key in JSON object"));

    /* Store key */
    Datum values[2];
    bool nulls[2] = {false, false};

    values[0] = CStringGetTextDatum(lex->token);

    /* Get value */
    json_lex(lex);

    if (lex->token_type == JSON_TOKEN_STRING)
    {
        values[1] = CStringGetTextDatum(lex->token);
    }
    else
    {
        /* Non-string values are returned as their text representation */
        StringInfoData str;
        initStringInfo(&str);
        json_lex_to_string(&str, lex);
        values[1] = CStringGetTextDatum(str.data);
        pfree(str.data);
    }

    HeapTuple tuple = heap_form_tuple(funcctx->tuple_desc, values, nulls);
    SRF_RETURN_NEXT(funcctx, HeapTupleGetDatum(tuple));
}

