#include "miscadmin.h"

PG_FUNCTION_INFO_V1(json_extract_path);

Datum
json_extract_path(PG_FUNCTION_ARGS)
{
    text       *json = PG_GETARG_TEXT_PP(0);
    int         nargs = PG_NARGS() - 1;
    JsonLexContext *lex;
    JsonSemAction sem;
    JsonParseErrorType result;
    char       *path_expr;
    text       *result_text;
    Datum      *path_elems;
    bool       *path_nulls;
    int         i;

    if (nargs <= 0)
        PG_RETURN_NULL();

    /* Extract path elements from variadic arguments */
    path_elems = (Datum *) palloc(nargs * sizeof(Datum));
    path_nulls = (bool *) palloc(nargs * sizeof(bool));

    for (i = 0; i < nargs; i++)
    {
        path_elems[i] = PG_GETARG_DATUM(i + 1);
        path_nulls[i] = PG_ARGISNULL(i + 1);
    }

    /* Initialize JSON lexer */
    lex = makeJsonLexContext(json, true);

    /* Set up semantic action */
    memset(&sem, 0, sizeof(sem));
    sem.semstate = (void *) path_elems;
    sem.object_start = NULL;
    sem.array_start = NULL;
    sem.object_end = NULL;
    sem.array_end = NULL;
    sem.scalar = NULL;
    sem.object_field_start = NULL;

    /* Parse JSON and extract the specified path */
    result = pg_parse_json(lex, &sem);

    if (result != JSON_SUCCESS)
        PG_RETURN_NULL();

    /* If we got here, the path was found */
    result_text = cstring_to_text(lex->token_type == JSON_TOKEN_STRING ?
                                 lex->token_value.str : lex->token_value.num.str);

    PG_RETURN_TEXT_P(result_text);
}

