#include "utils/jsonapi.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(json_object_keys);

Datum
json_object_keys(PG_FUNCTION_ARGS)
{
    text       *json = PG_GETARG_TEXT_PP(0);
    JsonLexContext *lex;
    JsonTokenType tok;
    bool        skip_nested = false;
    int         r;

    lex = makeJsonLexContext(json, true);

    /* The first token must be an object start */
    r = json_lex(lex);
    if (r != JSON_TOKEN_OBJECT_START)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("cannot call json_object_keys on a non-object")));

    /* Initialize the function return context as a SRF */
    ReturnSetInfo *rsinfo = (ReturnSetInfo *) fcinfo->resultinfo;
    MemoryContext oldcontext;
    Tuplestorestate *tupstore;
    TupleDesc   tupdesc;

    rsinfo->returnMode = SFRM_Materialize;
    rsinfo->setResult = NULL;
    rsinfo->setDesc = NULL;

    /* Build a tuple descriptor for our result type */
    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    oldcontext = MemoryContextSwitchTo(rsinfo->econtext->ecxt_per_query_memory);
    tupstore = tuplestore_begin_heap(true, false, work_mem);
    rsinfo->setResult = tupstore;
    rsinfo->setDesc = tupdesc;
    MemoryContextSwitchTo(oldcontext);

    /* Loop through the object keys */
    while ((r = json_lex(lex)) != JSON_TOKEN_OBJECT_END)
    {
        if (r == JSON_TOKEN_STRING)
        {
            /* We found a key */
            char       *key = pnstrdup(lex->token_start, lex->token_len);
            Datum       values[1];
            bool        nulls[1] = {false};

            values[0] = CStringGetTextDatum(key);
            pfree(key);

            tuplestore_putvalues(tupstore, tupdesc, values, nulls);

            /* Skip the corresponding value */
            r = json_lex(lex);
            if (r == JSON_TOKEN_OBJECT_START || r == JSON_TOKEN_ARRAY_START)
                skipNested(lex);
        }
        else if (r == JSON_TOKEN_OBJECT_END)
        {
            break;
        }
        else
        {
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("invalid json structure")));
        }
    }

    /* clean up and return the tuplestore */
    tuplestore_donestoring(tupstore);

    PG_RETURN_NULL();
}

