Datum
json_populate_record(PG_FUNCTION_ARGS)
{
    HeapTuple    base_tuple = NULL;
    TupleDesc    tupdesc;
    Oid            tupType;
    int32        tupTypmod;
    Datum       *values;
    bool       *nulls;
    Jsonb       *jsonb;
    JsonbIterator *it;
    JsonbValue  *v;
    JsonbValue    jbv;
    JsonbIteratorToken type;

    if (!PG_ARGISNULL(0))
    {
        base_tuple = PG_GETARG_HEAPTUPLEHEADER(0);
        tupType = HeapTupleHeaderGetTypeId(base_tuple);
        tupTypmod = HeapTupleHeaderGetTypMod(base_tuple);
    }
    else
    {
        tupType = get_fn_expr_argtype(fcinfo->flinfo, 0);
        tupTypmod = -1;
    }

    tupdesc = lookup_rowtype_tupdesc(tupType, tupTypmod);

    if (PG_ARGISNULL(1))
        PG_RETURN_NULL();

    jsonb = PG_GETARG_JSONB_P(1);

    it = JsonbIteratorInit(&jsonb->root);

    values = (Datum *) palloc0(tupdesc->natts * sizeof(Datum));
    nulls = (bool *) palloc0(tupdesc->natts * sizeof(bool));

    if (base_tuple != NULL)
    {
        heap_deform_tuple(base_tuple, tupdesc, values, nulls);
    }
    else
    {
        for (int i = 0; i < tupdesc->natts; i++)
            nulls[i] = true;
    }

    while ((type = JsonbIteratorNext(&it, &v, false)) != WJB_DONE)
    {
        if (type == WJB_KEY)
        {
            char       *field_name = pnstrdup(v->val.string.val, v->val.string.len);
            int            attnum = -1;

            for (int i = 0; i < tupdesc->natts; i++)
            {
                if (namestrcmp(&tupdesc->attrs[i]->attname, field_name) == 0)
                {
                    attnum = i;
                    break;
                }
            }

            pfree(field_name);

            if (attnum < 0)
                continue;

            type = JsonbIteratorNext(&it, &v, false);
            Assert(type == WJB_VALUE);

            if (v->type == jbvNull)
            {
                nulls[attnum] = true;
                continue;
            }

            if (tupdesc->attrs[attnum]->atttypid == JSONBOID ||
                tupdesc->attrs[attnum]->atttypid == JSONOID)
            {
                Jsonb       *j = JsonbValueToJsonb(v);
                values[attnum] = PointerGetDatum(j);
                nulls[attnum] = false;
                continue;
            }

            if (v->type == jbvString)
            {
                char       *str = pnstrdup(v->val.string.val, v->val.string.len);
                Oid            typinput;
                Oid            typioparam;
                char       *str_out;

                getTypeInputInfo(tupdesc->attrs[attnum]->atttypid,
                                &typinput, &typioparam);

                str_out = OidInputFunctionCall(typinput, str, typioparam, -1);
                values[attnum] = PointerGetDatum(str_out);
                nulls[attnum] = false;
                pfree(str);
                continue;
            }

            {
                char       *str = JsonbToCString(NULL, &jbv, v->estSize);
                Oid            typinput;
                Oid            typioparam;
                char       *str_out;

                getTypeInputInfo(tupdesc->attrs[attnum]->atttypid,
                                &typinput, &typioparam);

                str_out = OidInputFunctionCall(typinput, str, typioparam, -1);
                values[attnum] = PointerGetDatum(str_out);
                nulls[attnum] = false;
                pfree(str);
            }
        }
    }

    HeapTuple    tuple = heap_form_tuple(tupdesc, values, nulls);
    ReleaseTupleDesc(tupdesc);

    pfree(values);
    pfree(nulls);

    PG_RETURN_DATUM(HeapTupleGetDatum(tuple));
}

