static Datum
populate_recordset_worker(FunctionCallInfo fcinfo, bool is_jsonb)
{
    ReturnSetInfo *rsi;
    MemoryContext old_cxt;
    TupleDesc    tupdesc;
    Datum       *values;
    bool        *nulls;
    JsonLexContext *lex = NULL;
    Jsonb       *jb = NULL;
    JsonbIterator *it = NULL;
    JsonbValue  *jval = NULL;
    JsonbValue  jv;
    int            i;
    bool        skip_nested = false;

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    if (PG_ARGISNULL(1))
        PG_RETURN_NULL();

    tupdesc = lookup_rowtype_tupdesc_copy(get_fn_expr_argtype(fcinfo->flinfo, 0), -1);

    rsi = (ReturnSetInfo *) fcinfo->resultinfo;
    if (!rsi || !IsA(rsi, ReturnSetInfo) ||
        (rsi->allowedModes & SFRM_Materialize) == 0)
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                 errmsg("set-valued function called in context that cannot accept a set")));

    rsi->returnMode = SFRM_Materialize;
    rsi->setResult = NULL;
    rsi->setDesc = NULL;

    old_cxt = MemoryContextSwitchTo(rsi->econtext->ecxt_per_query_memory);

    if (is_jsonb)
    {
        jb = PG_GETARG_JSONB(1);
        if (JB_ROOT_IS_SCALAR(jb))
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("cannot populate record set from a scalar")));
        if (!JB_ROOT_IS_ARRAY(jb))
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("cannot populate record set from a non-array")));

        it = JsonbIteratorInit(&jb->root);
    }
    else
    {
        text       *json = PG_GETARG_TEXT_PP(1);
        lex = makeJsonLexContext(json, false);

        pg_parse_json(lex, &nullSemAction);

        if (lex->token_type != JSON_TOKEN_ARRAY_START)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("cannot populate record set from a non-array")));
    }

    values = (Datum *) palloc0(tupdesc->natts * sizeof(Datum));
    nulls = (bool *) palloc0(tupdesc->natts * sizeof(bool));

    rsi->setResult = tuplestore_begin_heap(true, false, work_mem);
    rsi->setDesc = CreateTupleDescCopy(tupdesc);

    for (;;)
    {
        bool        found = false;

        if (is_jsonb)
        {
            JsonbIteratorToken type = JsonbIteratorNext(&it, &jv, skip_nested);

            if (type == WJB_DONE)
                break;

            if (type != WJB_BEGIN_ARRAY && type != WJB_BEGIN_OBJECT)
                continue;

            jval = &jv;
        }
        else
        {
            JsonTokenType type = lex_peek(lex);

            if (type == JSON_TOKEN_ARRAY_END)
                break;

            if (type != JSON_TOKEN_OBJECT_START)
                continue;
        }

        populate_record(tupdesc, values, nulls,
                       is_jsonb ? (Node *) jval : (Node *) lex,
                       fcinfo->flinfo->fn_expr,
                       fcinfo->flinfo->fn_mcxt,
                       is_jsonb);

        tuplestore_putvalues(rsi->setResult, tupdesc, values, nulls);
        found = true;

        if (is_jsonb)
        {
            skip_nested = true;
            while (JsonbIteratorNext(&it, &jv, skip_nested) != WJB_END_OBJECT)
                 /* skip */ ;
            skip_nested = false;
        }
        else
        {
            lex_expect(JSON_PARSE_OBJECT_NEXT, lex, JSON_TOKEN_OBJECT_END);
        }

        if (!found)
            break;
    }

    if (is_jsonb)
        JsonbIteratorFree(it);

    MemoryContextSwitchTo(old_cxt);

    ReleaseTupleDesc(tupdesc);
    pfree(values);
    pfree(nulls);

    PG_RETURN_NULL();
}

