PG_FUNCTION_INFO_V1(jsonb_set);

Datum
jsonb_set(PG_FUNCTION_ARGS)
{
    Jsonb       *target = PG_GETARG_JSONB(0);
    ArrayType   *path = PG_GETARG_ARRAYTYPE_P(1);
    Jsonb       *new_value = PG_GETARG_JSONB(2);
    bool        create_if_missing = true;
    JsonbValue *result;
    JsonbIterator *it;
    JsonbParseState *state = NULL;
    int         i;
    int         nelems;
    int         *path_elems;
    int         path_len;
    bool        path_nulls;
    bool        replaced = false;
    bool        skip = false;

    if (PG_NARGS() > 3)
        create_if_missing = PG_GETARG_BOOL(3);

    if (ARR_NDIM(path) != 1)
        ereport(ERROR,
                (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                 errmsg("path must be one-dimensional array")));

    if (ARR_HASNULL(path))
        ereport(ERROR,
                (errcode(ERRCODE_NULL_VALUE_NOT_ALLOWED),
                 errmsg("path array must not contain nulls")));

    deconstruct_array(path, TEXTOID, -1, false, 'i',
                      &path_elems, &path_nulls, &nelems);

    path_len = nelems;

    it = JsonbIteratorInit(&target->root);

    result = setPath(&it, path_elems, path_len, new_value, create_if_missing, &replaced);

    if (!replaced)
        PG_RETURN_JSONB(target);

    PG_RETURN_JSONB(JsonbValueToJsonb(result));
}

static JsonbValue *
setPath(JsonbIterator **it, int *path_elems, int path_len, Jsonb *new_value, bool create_if_missing, bool *replaced)
{
    JsonbValue  v;
    JsonbValue *result = NULL;
    JsonbParseState *state = NULL;
    int         level = 0;
    int         path_pos = 0;
    bool        done = false;

    while (!done)
    {
        JsonbIteratorToken type = JsonbIteratorNext(it, &v, false);

        switch (type)
        {
            case WJB_BEGIN_ARRAY:
            case WJB_BEGIN_OBJECT:
                if (level == path_pos)
                {
                    if (path_pos == path_len)
                    {
                        *replaced = true;
                        return new_value;
                    }
                    else
                    {
                        if (type == WJB_BEGIN_ARRAY)
                        {
                            int idx = path_elems[path_pos];
                            if (idx < 0)
                                idx += v.val.array.nElems;
                            if (idx < 0 || idx >= v.val.array.nElems)
                            {
                                if (create_if_missing && path_pos == path_len - 1)
                                {
                                    *replaced = true;
                                    return new_value;
                                }
                                else
                                {
                                    *replaced = false;
                                    return NULL;
                                }
                            }
                        }
                        path_pos++;
                    }
                }
                level++;
                break;
            case WJB_END_ARRAY:
            case WJB_END_OBJECT:
                level--;
                if (level < path_pos)
                    path_pos--;
                break;
            case WJB_ELEM:
            case WJB_VALUE:
                if (level == path_pos)
                {
                    if (path_pos == path_len)
                    {
                        *replaced = true;
                        return new_value;
                    }
                    else
                    {
                        if (type == WJB_ELEM && path_pos < path_len)
                        {
                            int idx = path_elems[path_pos];
                            if (idx < 0)
                                idx += v.val.array.nElems;
                            if (idx < 0 || idx >= v.val.array.nElems)
                            {
                                if (create_if_missing && path_pos == path_len - 1)
                                {
                                    *replaced = true;
                                    return new_value;
                                }
                                else
                                {
                                    *replaced = false;
                                    return NULL;
                                }
                            }
                        }
                        path_pos++;
                    }
                }
                break;
            case WJB_DONE:
                done = true;
                break;
        }
    }

    *replaced = false;
    return NULL;
}

