Datum
jsonb_set_lax(PG_FUNCTION_ARGS)
{
    Jsonb       *target = PG_GETARG_JSONB_P(0);
    ArrayType   *path = PG_GETARG_ARRAYTYPE_P(1);
    Jsonb       *new_value = PG_ARGISNULL(2) ? NULL : PG_GETARG_JSONB_P(2);
    bool        create_missing = PG_GETARG_BOOL(3);
    text        *null_value_treatment_text = PG_ARGISNULL(4) ? NULL : PG_GETARG_TEXT_PP(4);
    Jsonb       *result;
    char        *null_value_treatment = "use_json_null";

    if (null_value_treatment_text != NULL)
        null_value_treatment = text_to_cstring(null_value_treatment_text);

    if (new_value != NULL)
    {
        result = jsonb_set(target, path, new_value, create_missing);
    }
    else
    {
        if (strcmp(null_value_treatment, "raise_exception") == 0)
        {
            ereport(ERROR,
                    (errcode(ERRCODE_NULL_VALUE_NOT_ALLOWED),
                     errmsg("null value not allowed for jsonb_set_lax with null_value_treatment = 'raise_exception'")));
        }
        else if (strcmp(null_value_treatment, "use_json_null") == 0)
        {
            JsonbValue null_value;
            null_value.type = jbvNull;
            result = jsonb_set(target, path, JsonbValueToJsonb(&null_value), create_missing);
        }
        else if (strcmp(null_value_treatment, "delete_key") == 0)
        {
            result = jsonb_delete_path(target, path);
        }
        else if (strcmp(null_value_treatment, "return_target") == 0)
        {
            result = target;
        }
        else
        {
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("invalid null_value_treatment value"),
                     errhint("null_value_treatment must be one of 'raise_exception', 'use_json_null', 'delete_key', or 'return_target'.")));
        }
    }

    PG_RETURN_JSONB(result);
}

