        vars = PG_GETARG_JSONB(2);

    if (PG_NARGS() > 3)
        silent = PG_GETARG_BOOL(3);

    res = execute_jsonb_path(path, jb, vars, silent, "jsonb_path_query_first");

    if (!res)
        PG_RETURN_NULL();

    /* We only want the first result */
    it = JsonbIteratorInit(&res->val.jsonb.cont);
    if (JsonbIteratorNext(&it, &res, true) == WJB_BEGIN_ARRAY)
    {
        if (JsonbIteratorNext(&it, &res, true) != WJB_DONE)
        {
            Jsonb       *out = JsonbValueToJsonb(res);
            PG_RETURN_JSONB(out);
        }
    }

    PG_RETURN_NULL();
}

