Datum
json_typeof(PG_FUNCTION_ARGS)
{
    Jsonb       *jb = PG_GETARG_JSONB_P(0);
    JsonbIterator *it;
    JsonbValue  v;
    int         type;
    const char *result;

    it = JsonbIteratorInit(&jb->root);
    type = JsonbIteratorNext(&it, &v, false);

    switch (type)
    {
        case WJB_BEGIN_ARRAY:
            result = "array";
            break;
        case WJB_BEGIN_OBJECT:
            result = "object";
            break;
        case WJB_VALUE:
            switch (v.type)
            {
                case jbvString:
                    result = "string";
                    break;
                case jbvNumeric:
                    result = "number";
                    break;
                case jbvBool:
                    result = "boolean";
                    break;
                case jbvNull:
                    result = "null";
                    break;
                default:
                    elog(ERROR, "unrecognized jsonb value type: %d", v.type);
                    result = NULL; /* keep compiler quiet */
            }
            break;
        default:
            elog(ERROR, "unrecognized jsonb iterator token: %d", type);
            result = NULL; /* keep compiler quiet */
    }

    PG_RETURN_TEXT_P(cstring_to_text(result));
}

