Datum
nextval_oid(PG_FUNCTION_ARGS)
{
    Oid         seqoid = PG_GETARG_OID(0);
    SeqTable    elm;
    Relation    seqrel;
    Buffer      buf;
    HeapTuple   seqtuple;
    Form_pg_sequence seq;
    int64       result;
    bool        is_called;

    /* open and AccessShareLock sequence */
    init_sequence(seqoid, &elm, &seqrel);

    /* read and lock page */
    seqtuple = read_seq_tuple(elm, seqrel, &buf);
    seq = (Form_pg_sequence) GETSTRUCT(seqtuple);

    /* reserve the next number */
    result = seq->last_value;
    is_called = seq->is_called;

    if (is_called)
    {
        result += seq->increment_by;
        /* check for overflow */
        if (seq->increment_by > 0)
        {
            if (result < seq->min_value || result > seq->max_value)
            {
                if (seq->cycle)
                    result = (seq->increment_by > 0) ? seq->min_value : seq->max_value;
                else
                    ereport(ERROR,
                            (errcode(ERRCODE_SEQUENCE_GENERATOR_LIMIT_EXCEEDED),
                             errmsg("nextval: reached maximum value of sequence \"%s\" (%s)",
                                    NameStr(seq->sequence_name),
                                    (seq->increment_by > 0) ? "MAXVALUE" : "MINVALUE")));
            }
        }
        else
        {
            if (result > seq->max_value || result < seq->min_value)
            {
                if (seq->cycle)
                    result = (seq->increment_by > 0) ? seq->min_value : seq->max_value;
                else
                    ereport(ERROR,
                            (errcode(ERRCODE_SEQUENCE_GENERATOR_LIMIT_EXCEEDED),
                             errmsg("nextval: reached minimum value of sequence \"%s\" (%s)",
                                    NameStr(seq->sequence_name),
                                    (seq->increment_by > 0) ? "MAXVALUE" : "MINVALUE")));
            }
        }
    }

    /* save info in local cache */
    elm->last = result;
    elm->cached = result;

    /* Now okay to update the on-disk tuple */
    START_CRIT_SECTION();

    seq->last_value = result;
    seq->is_called = true;
    seq->log_cnt = 0;

    MarkBufferDirty(buf);

    END_CRIT_SECTION();

    UnlockReleaseBuffer(buf);
    relation_close(seqrel, AccessShareLock);

    PG_RETURN_INT64(result);
}

