/*
 * setval_oid: set the sequence's value with given OID
 */
Datum
setval_oid(PG_FUNCTION_ARGS)
{
    Oid             seqoid = PG_GETARG_OID(0);
    int64           next = PG_GETARG_INT64(1);
    bool            iscalled = true;
    Relation        seqrel;
    SeqTable        elm;
    SequenceData   *seq;
    int64           result;

    seqrel = open_share_lock(seqoid);
    elm = init_sequence(seqoid);
    seq = &elm->seqdata;

    /* lock page' buffer and update sequence */
    (void) read_seq_tuple(seqrel, elm, seq);

    result = next;
    seq->last_value = next;
    seq->is_called = iscalled;

    /* In any case, forget any future cached numbers */
    elm->cached = elm->last;

    /* Mark the sequence as needing to be fsync'ed */
    seq_mark_dirty(seqrel, elm);

    relation_close(seqrel, NoLock);

    PG_RETURN_INT64(result);
}

