PG_FUNCTION_INFO_V1(currval_oid);

Datum
currval_oid(PG_FUNCTION_ARGS)
{
    Oid             relid = PG_GETARG_OID(0);
    SeqTable        elm = NULL;
    Relation        seqrel;
    Buffer          buf;
    HeapTuple       seqtuple;
    Form_pg_sequence seq;
    int64           result;

    /* open and AccessShareLock sequence */
    seqrel = relation_open(relid, AccessShareLock);

    if (seqrel->rd_rel->relkind != RELKIND_SEQUENCE)
        ereport(ERROR,
                (errcode(ERRCODE_WRONG_OBJECT_TYPE),
                 errmsg("%s is not a sequence",
                        RelationGetRelationName(seqrel))));

    /* Check sequence permissions */
    AclResult      aclresult = pg_class_aclcheck(relid, GetUserId(), ACL_SELECT);
    if (aclresult != ACLCHECK_OK && !pg_class_ownercheck(relid, GetUserId()))
        aclcheck_error(aclresult, OBJECT_SEQUENCE, RelationGetRelationName(seqrel));

    /* find sequence in current session */
    for (elm = seqtab; elm != NULL; elm = elm->next)
    {
        if (elm->relid == relid)
            break;
    }

    if (elm == NULL || elm->last == 0)
        ereport(ERROR,
                (errcode(ERRCODE_OBJECT_NOT_IN_PREREQUISITE_STATE),
                 errmsg("currval of sequence "%s" is not yet defined in this session",
                        RelationGetRelationName(seqrel))));

    /* read the sequence tuple */
    seqtuple = SearchSysCache1(SEQRELID, ObjectIdGetDatum(relid));
    if (!HeapTupleIsValid(seqtuple))
        elog(ERROR, "cache lookup failed for sequence %u", relid);
    seq = (Form_pg_sequence) GETSTRUCT(seqtuple);

    /* return the last value */
    result = elm->last;

    /* check for sequence overflow */
    if (seq->seqincrement > 0)
    {
        if (result > seq->seqmax)
            ereport(ERROR,
                    (errcode(ERRCODE_SEQUENCE_GENERATOR_LIMIT_EXCEEDED),
                     errmsg("sequence "%s" has reached its maximum value and cannot be incremented",
                            RelationGetRelationName(seqrel))));
    }
    else
    {
        if (result < seq->seqmin)
            ereport(ERROR,
                    (errcode(ERRCODE_SEQUENCE_GENERATOR_LIMIT_EXCEEDED),
                     errmsg("sequence "%s" has reached its minimum value and cannot be decremented",
                            RelationGetRelationName(seqrel))));
    }

    ReleaseSysCache(seqtuple);
    relation_close(seqrel, AccessShareLock);

    PG_RETURN_INT64(result);
}

