Datum
array_append(PG_FUNCTION_ARGS)
{
    ArrayType  *v = PG_GETARG_ARRAYTYPE_P(0);
    Datum       element = PG_GETARG_DATUM(1);
    Oid         element_type = get_fn_expr_argtype(fcinfo->flinfo, 1);
    int16       typlen;
    bool        typbyval;
    char        typalign;
    ArrayType  *result;
    Datum      *values;
    bool       *nulls;
    int         nitems;
    int         ndims;
    int         *dims;
    int         *lbs;

    if (element_type == InvalidOid)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("could not determine input data type")));

    if (ARR_HASNULL(v) && array_contains_nulls(v))
        ereport(ERROR,
                (errcode(ERRCODE_NULL_VALUE_NOT_ALLOWED),
                 errmsg("array must not contain nulls"));

    get_typlenbyvalalign(element_type, &typlen, &typbyval, &typalign);

    ndims = ARR_NDIM(v);
    if (ndims == 0)
    {
        dims = (int[1]) {1};
        lbs = (int[1]) {1};
        nitems = 1;
    }
    else if (ndims == 1)
    {
        dims = (int[1]) {ARR_DIMS(v)[0] + 1};
        lbs = (int[1]) {ARR_LBOUND(v)[0]};
        nitems = dims[0];
    }
    else
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("argument must be empty or one-dimensional array"));

    deconstruct_array(v, element_type, typlen, typbyval, typalign,
                      &values, &nulls, &nitems);

    values = (Datum *) repalloc(values, sizeof(Datum) * nitems);
    nulls = (bool *) repalloc(nulls, sizeof(bool) * nitems);

    values[nitems - 1] = element;
    nulls[nitems - 1] = false;

    result = construct_md_array(values, nulls, ndims, dims, lbs,
                               element_type, typlen, typbyval, typalign);

    pfree(values);
    pfree(nulls);

    PG_RETURN_ARRAYTYPE_P(result);
}

