/*
 * array_fill - fill an array with copies of a given value
 *
 * array_fill(value anyelement, dims integer[], lbs integer[] DEFAULT NULL)
 *
 * The dims argument is an array specifying the dimensions of the result.
 * The optional lbs argument supplies lower-bound values for each dimension.
 */
Datum
array_fill(PG_FUNCTION_ARGS)
{
    return array_fill_with_lower_bounds(fcinfo);
}

Datum
array_fill_with_lower_bounds(PG_FUNCTION_ARGS)
{
    Oid            element_type = get_fn_expr_argtype(fcinfo->flinfo, 0);
    int            ndims;
    int           *dims;
    int           *lbs;
    int            nitems;
    ArrayType     *result;
    Datum          value;
    bool           isnull;
    int16          typlen;
    bool           typbyval;
    char           typalign;
    int            i;

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    value = PG_GETARG_DATUM(0);
    isnull = PG_ARGISNULL(0);

    if (PG_ARGISNULL(1))
        PG_RETURN_NULL();

    /* Get and validate the dimensions array */
    ArrayType  *dims_array = PG_GETARG_ARRAYTYPE_P(1);
    ndims = ARR_DIMS(dims_array)[0];
    if (ndims <= 0 || ndims > MAXDIM)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid number of dimensions: %d", ndims)));

    dims = (int *) palloc(ndims * sizeof(int));
    lbs = (int *) palloc(ndims * sizeof(int));

    /* Extract dimension values */
    deconstruct_array(dims_array,
                     INT4OID,
                     4, /* int4 size */
                     true, /* pass by value */
                     'i', /* alignment */
                     (Datum **) &dims, NULL, &ndims);

    /* Check dimensions are positive */
    nitems = 1;
    for (i = 0; i < ndims; i++)
    {
        if (dims[i] <= 0)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("dimension size must be positive")));
        nitems *= dims[i];
    }

    /* Process lower bounds if provided */
    if (PG_NARGS() > 2 && !PG_ARGISNULL(2))
    {
        ArrayType  *lbs_array = PG_GETARG_ARRAYTYPE_P(2);
        int         lbs_ndims;

        if (ARR_DIMS(lbs_array)[0] != ndims)
            ereport(ERROR,
                    (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                     errmsg("number of lower bounds does not match number of dimensions")));

        deconstruct_array(lbs_array,
                         INT4OID,
                         4,
                         true,
                         'i',
                         (Datum **) &lbs, NULL, &lbs_ndims);
    }
    else
    {
        /* Default lower bounds to 1 */
        for (i = 0; i < ndims; i++)
            lbs[i] = 1;
    }

    /* Get array element properties */
    get_typlenbyvalalign(element_type, &typlen, &typbyval, &typalign);

    /* Create the array */
    result = construct_md_array(&value, &isnull,
                               ndims, dims, lbs,
                               element_type,
                               typlen, typbyval, typalign);

    pfree(dims);
    pfree(lbs);

    PG_RETURN_ARRAYTYPE_P(result);
}

