Datum
array_positions(PG_FUNCTION_ARGS)
{
    ArrayType  *array;
    Datum       value;
    bool        isnull;
    Oid         element_type;
    int16       typlen;
    bool        typbyval;
    char        typalign;
    int         ndims,
                nitems,
                *dims,
                *lbs;
    Datum      *elements;
    bool       *nulls;
    ArrayMetaState *my_extra;
    int         i;
    int         count = 0;
    Datum      *result_elems;
    bool       *result_nulls;
    ArrayType  *result;

    array = PG_GETARG_ARRAYTYPE_P(0);
    if (PG_ARGISNULL(1))
    {
        value = (Datum) 0;
        isnull = true;
    }
    else
    {
        value = PG_GETARG_DATUM(1);
        isnull = false;
    }

    if (ARR_NDIM(array) != 1)
        ereport(ERROR,
                (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                 errmsg("array must be one-dimensional")));

    element_type = ARR_ELEMTYPE(array);
    my_extra = (ArrayMetaState *) fcinfo->flinfo->fn_extra;

    if (my_extra == NULL)
    {
        fcinfo->flinfo->fn_extra = MemoryContextAlloc(fcinfo->flinfo->fn_mcxt,
                                                     sizeof(ArrayMetaState));
        my_extra = (ArrayMetaState *) fcinfo->flinfo->fn_extra;
        my_extra->element_type = ~element_type;
    }

    if (my_extra->element_type != element_type)
    {
        get_typlenbyvalalign(element_type,
                             &typlen,
                             &typbyval,
                             &typalign);
        my_extra->element_type = element_type;
        my_extra->typlen = typlen;
        my_extra->typbyval = typbyval;
        my_extra->typalign = typalign;
    }
    else
    {
        typlen = my_extra->typlen;
        typbyval = my_extra->typbyval;
        typalign = my_extra->typalign;
    }

    ndims = ARR_NDIM(array);
    dims = ARR_DIMS(array);
    lbs = ARR_LBOUND(array);
    nitems = ArrayGetNItems(ndims, dims);

    deconstruct_array(array, element_type, typlen, typbyval, typalign,
                      &elements, &nulls, &nitems);

    /* Count matching elements */
    for (i = 0; i < nitems; i++)
    {
        if (isnull && nulls[i])
            count++;
        else if (!isnull && !nulls[i] && DatumGetBool(FunctionCall2(&array_eq_oid_finfo,
                                                                   elements[i], value)))
            count++;
    }

    /* Create result array */
    result_elems = (Datum *) palloc(sizeof(Datum) * count);
    result_nulls = (bool *) palloc(sizeof(bool) * count);

    count = 0;
    for (i = 0; i < nitems; i++)
    {
        if ((isnull && nulls[i]) ||
            (!isnull && !nulls[i] && DatumGetBool(FunctionCall2(&array_eq_oid_finfo,
                                                               elements[i], value))))
        {
            result_elems[count] = Int32GetDatum(i + lbs[0]);
            result_nulls[count] = false;
            count++;
        }
    }

    result = construct_array(result_elems, count, INT4OID, 4, true, 'i');

    pfree(elements);
    pfree(nulls);
    pfree(result_elems);
    pfree(result_nulls);

    PG_RETURN_ARRAYTYPE_P(result);
}

