Datum
array_prepend(PG_FUNCTION_ARGS)
{
    Datum        element = PG_GETARG_DATUM(0);
    ArrayType  *array = PG_GETARG_ARRAYTYPE_P(1);
    Oid            element_type = get_fn_expr_argtype(fcinfo->flinfo, 0);
    Oid            array_type = get_fn_expr_argtype(fcinfo->flinfo, 1);
    Oid            element_type_input;
    Oid            element_type_receive;
    bool        typbyval;
    char        typalign;
    int16        typlen;
    ArrayType  *result;
    Datum       *values;
    bool       *nulls;
    int            ndims;
    int           *dims;
    int            nitems;
    int            i;

    if (array_type == InvalidOid)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("could not determine input data type")));

    if (element_type == InvalidOid)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("could not determine input data type")));

    get_type_io_data(element_type, IOFunc_input,
                     &typlen, &typbyval, &typalign,
                     &element_type_input, &element_type_receive);

    ndims = ARR_NDIM(array);
    dims = ARR_DIMS(array);
    nitems = ArrayGetNItems(ndims, dims);

    deconstruct_array(array, element_type, typlen, typbyval, typalign,
                      &values, &nulls, &nitems);

    /* Prepend the element */
    values = (Datum *) repalloc(values, (nitems + 1) * sizeof(Datum));
    nulls = (bool *) repalloc(nulls, (nitems + 1) * sizeof(bool));

    for (i = nitems; i > 0; i--)
    {
        values[i] = values[i-1];
        nulls[i] = nulls[i-1];
    }

    values[0] = element;
    nulls[0] = PG_ARGISNULL(0);

    /* Construct and return the result array */
    result = construct_md_array(values, nulls, 1, &nitems, dims,
                               element_type, typlen, typbyval, typalign);

    PG_RETURN_ARRAYTYPE_P(result);
}

