Datum
array_remove(PG_FUNCTION_ARGS)
{
    ArrayType  *v,
               *result;
    Oid         element_type;
    int16       typlen;
    bool        typbyval;
    char        typalign;
    int         nitems,
                i,
                j;
    Datum      *values;
    bool       *nulls;
    Datum       elem;
    bool        elem_is_null;
    Datum      *new_values;
    bool       *new_nulls;
    int         new_nitems = 0;
    int         ndims;
    int        *dims;
    int16       typlen_new;
    bool        typbyval_new;
    char        typalign_new;

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();
    v = PG_GETARG_ARRAYTYPE_P(0);
    element_type = ARR_ELEMTYPE(v);
    get_typlenbyvalalign(element_type, &typlen, &typbyval, &typalign);

    if (PG_ARGISNULL(1))
    {
        elem = (Datum) 0;
        elem_is_null = true;
    }
    else
    {
        elem = PG_GETARG_DATUM(1);
        elem_is_null = false;
    }

    deconstruct_array(v, element_type, typlen, typbyval, typalign,
                      &values, &nulls, &nitems);

    new_values = (Datum *) palloc(sizeof(Datum) * nitems);
    new_nulls = (bool *) palloc(sizeof(bool) * nitems);

    for (i = 0, j = 0; i < nitems; i++)
    {
        if (elem_is_null && nulls[i])
            continue;
        if (!elem_is_null && !nulls[i] && DatumGetBool(DirectFunctionCall2(equal, values[i], elem)))
            continue;
        if (nulls[i])
            new_nulls[j] = true;
        else
        {
            new_values[j] = values[i];
            new_nulls[j] = false;
        }
        j++;
    }
    new_nitems = j;

    ndims = ARR_NDIM(v);
    dims = ARR_DIMS(v);
    if (ndims != 1)
        ereport(ERROR,
                (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                 errmsg("array must be one-dimensional")));

    get_typlenbyvalalign(element_type, &typlen_new, &typbyval_new, &typalign_new);
    result = construct_md_array(new_values, new_nulls, ndims, dims,
                               element_type, typlen_new, typbyval_new, typalign_new);

    pfree(values);
    pfree(nulls);
    pfree(new_values);
    pfree(new_nulls);

    PG_RETURN_ARRAYTYPE_P(result);
}

