Datum
array_sample(PG_FUNCTION_ARGS)
{
    ArrayType  *v = PG_GETARG_ARRAYTYPE_P(0);
    int32       n = PG_GETARG_INT32(1);
    Oid         element_type = ARR_ELEMTYPE(v);
    int16       elmlen;
    bool        elmbyval;
    char        elmalign;
    int         ndims = ARR_NDIM(v);
    int        *dims = ARR_DIMS(v);
    int         nitems;
    Datum      *elements;
    bool       *nulls;
    ArrayType  *result;
    Datum      *sample_elements;
    bool       *sample_nulls;
    int         i;
    int         j;
    int        *selected_indices;

    if (ndims == 0)
        PG_RETURN_NULL();

    nitems = ArrayGetNItems(ndims, dims);
    if (n < 0 || n > nitems)
        ereport(ERROR,
                (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                errmsg("number of requested samples exceeds array size"));

    get_typlenbyvalalign(element_type, &elmlen, &elmbyval, &elmalign);

    deconstruct_array(v, element_type, elmlen, elmbyval, elmalign,
                      &elements, &nulls, &nitems);

    selected_indices = (int *) palloc(n * sizeof(int));
    sample_elements = (Datum *) palloc(n * sizeof(Datum));
    sample_nulls = (bool *) palloc(n * sizeof(bool));

    /* Use Knuth's algorithm S for reservoir sampling */
    for (i = 0; i < n; i++)
    {
        selected_indices[i] = i;
        sample_elements[i] = elements[i];
        sample_nulls[i] = nulls[i];
    }

    for (; i < nitems; i++)
    {
        int j = random() % (i + 1);

        if (j < n)
        {
            selected_indices[j] = i;
            sample_elements[j] = elements[i];
            sample_nulls[j] = nulls[i];
        }
    }

    /* Construct the result array */
    result = construct_md_array(sample_elements, sample_nulls,
                               ndims, &n, NULL,
                               element_type, elmlen, elmbyval, elmalign);

    pfree(elements);
    pfree(nulls);
    pfree(selected_indices);
    pfree(sample_elements);
    pfree(sample_nulls);

    PG_RETURN_ARRAYTYPE_P(result);
}

