Datum
array_shuffle(PG_FUNCTION_ARGS)
{
    ArrayType  *v;
    int         ndims,
               *dims,
               nitems;
    Datum      *values;
    bool       *nulls;
    Oid         element_type;
    int16       typlen;
    bool        typbyval;
    char        typalign;
    int         i;
    ArrayType  *result;

    v = PG_GETARG_ARRAYTYPE_P(0);

    ndims = ARR_NDIM(v);
    dims = ARR_DIMS(v);

    if (ndims != 2)
        ereport(ERROR,
                (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                 errmsg("array must be two-dimensional")));

    nitems = ArrayGetNItems(ndims, dims);
    if (nitems <= 0)
        PG_RETURN_ARRAYTYPE_P(v);

    deconstruct_array(v, ARR_ELEMTYPE(v),
                      ARR_TYPELEN(v), ARR_TYPBYVAL(v), ARR_TYPALIGN(v),
                      &values, &nulls, &nitems);

    element_type = ARR_ELEMTYPE(v);
    get_typlenbyvalalign(element_type, &typlen, &typbyval, &typalign);

    /* Fisher-Yates shuffle algorithm */
    for (i = nitems - 1; i > 0; i--)
    {
        int         j = (int) (random() % (i + 1));
        Datum       tmp_val;
        bool        tmp_null;

        tmp_val = values[i];
        tmp_null = nulls[i];
        values[i] = values[j];
        nulls[i] = nulls[j];
        values[j] = tmp_val;
        nulls[j] = tmp_null;
    }

    result = construct_md_array(values, nulls, ndims, dims, ARR_LBOUND(v),
                               element_type, typlen, typbyval, typalign);

    pfree(values);
    if (nulls)
        pfree(nulls);

    PG_RETURN_ARRAYTYPE_P(result);
}

