static Datum
array_to_string_internal(PG_FUNCTION_ARGS, bool null_as_null)
{
    ArrayType  *v = PG_GETARG_ARRAYTYPE_P(0);
    text       *delim_text = PG_GETARG_TEXT_PP(1);
    text       *null_string = null_as_null ? PG_GETARG_TEXT_PP(2) : NULL;
    char       *delim;
    char       *nullstr = NULL;
    int         ndim;
    int        *dims;
    int         nitems;
    Oid         element_type;
    int         typlen;
    bool        typbyval;
    char        typalign;
    Datum      *values;
    bool       *nulls;
    ArrayMetaState *my_extra;
    StringInfoData str;
    int         i;

    ndim = ARR_NDIM(v);
    dims = ARR_DIMS(v);
    nitems = ArrayGetNItems(ndim, dims);

    if (nitems == 0)
        PG_RETURN_TEXT_P(cstring_to_text(""));

    element_type = ARR_ELEMTYPE(v);
    my_extra = (ArrayMetaState *) fcinfo->flinfo->fn_extra;

    if (my_extra == NULL)
    {
        fcinfo->flinfo->fn_extra = MemoryContextAlloc(fcinfo->flinfo->fn_mcxt,
                                                     sizeof(ArrayMetaState));
        my_extra = (ArrayMetaState *) fcinfo->flinfo->fn_extra;
        my_extra->element_type = ~element_type;
    }

    if (my_extra->element_type != element_type)
    {
        get_typlenbyvalalign(element_type,
                             &my_extra->typlen,
                             &my_extra->typbyval,
                             &my_extra->typalign);
        my_extra->element_type = element_type;
    }
    typlen = my_extra->typlen;
    typbyval = my_extra->typbyval;
    typalign = my_extra->typalign;

    deconstruct_array(v, element_type, typlen, typbyval, typalign,
                      &values, &nulls, &nitems);

    delim = text_to_cstring(delim_text);
    if (null_string)
        nullstr = text_to_cstring(null_string);

    initStringInfo(&str);

    for (i = 0; i < nitems; i++)
    {
        if (i > 0)
            appendStringInfo(&str, "%s", delim);

        if (nulls[i])
        {
            if (nullstr)
                appendStringInfo(&str, "%s", nullstr);
        }
        else
        {
            char       *value;

            value = OutputFunctionCall(&my_extra->proc, values[i]);
            appendStringInfo(&str, "%s", value);
            pfree(value);
        }
    }

    PG_RETURN_TEXT_P(cstring_to_text(str.data));
}

