Datum
trim_array(PG_FUNCTION_ARGS)
{
    ArrayType  *v = PG_GETARG_ARRAYTYPE_P(0);
    int32       n = PG_GETARG_INT32(1);
    ArrayType  *result;
    int         ndims,
                *dims,
                *lbs;
    int         nitems;
    int         trim_len;

    ndims = ARR_NDIM(v);
    dims = ARR_DIMS(v);
    lbs = ARR_LBOUND(v);

    if (ndims == 0)
        PG_RETURN_ARRAYTYPE_P(v);

    nitems = ArrayGetNItems(ndims, dims);
    if (n < 0 || n > nitems)
        ereport(ERROR,
                (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                 errmsg("trim size must be between 0 and %d", nitems)));

    trim_len = dims[0] - n;
    if (trim_len <= 0)
        PG_RETURN_ARRAYTYPE_P(construct_empty_array(ARR_ELEMTYPE(v)));

    if (ndims == 1)
    {
        /* For 1-D arrays, we can just adjust the dimensions */
        dims[0] = trim_len;
        result = construct_md_array(ARR_DATA_PTR(v),
                                   ndims,
                                   dims,
                                   lbs,
                                   ARR_ELEMTYPE(v),
                                   ARR_ELMSIZE(v),
                                   ARR_TYPBYVAL(v),
                                   ARR_TYPALIGN(v));
    }
    else
    {
        /* For multi-D arrays, we need to copy only the first dimension elements */
        int         i;
        int         new_size;
        int         element_size = ARR_ELMSIZE(v);
        char       *data = ARR_DATA_PTR(v);
        char       *new_data;
        int         elements_per_slice;

        elements_per_slice = ArrayGetNItems(ndims - 1, dims + 1);
        new_size = trim_len * elements_per_slice * element_size;
        new_data = (char *) palloc(new_size);
        memcpy(new_data, data, new_size);

        dims[0] = trim_len;
        result = construct_md_array(new_data,
                                   ndims,
                                   dims,
                                   lbs,
                                   ARR_ELEMTYPE(v),
                                   element_size,
                                   ARR_TYPBYVAL(v),
                                   ARR_TYPALIGN(v));
    }

    PG_RETURN_ARRAYTYPE_P(result);
}

