        if (state->lex == NULL)
        {
            state->lex = makeJsonLexContext(state->res, false);
        }

        lex = state->lex;
        tokentype = lex_peek(lex);

        if (tokentype != JSON_TOKEN_ARRAY_START)
        {
            JsonbValue *jbv = (JsonbValue *) palloc(sizeof(JsonbValue));
            *jbv = JsonbValueToJsonb(makeJsonbValue(value, isnull));
            pushJsonbValue(&state->res, WJB_ELEM, jbv);
        }
        else
        {
            JsonbValue *jbv = (JsonbValue *) palloc(sizeof(JsonbValue));
            *jbv = JsonbValueToJsonb(makeJsonbValue(value, isnull));
            pushJsonbValue(&state->res, WJB_VALUE, jbv);
        }
    }

    SRF_RETURN_DONE(funcctx);
}

