    bool        first;      /* is this the first value? */
} JsonArrayAggState;

PG_FUNCTION_INFO_V1(json_arrayagg_transfn);
PG_FUNCTION_INFO_V1(json_arrayagg_finalfn);

Datum
json_arrayagg_transfn(PG_FUNCTION_ARGS)
{
    MemoryContext aggcontext;
    JsonArrayAggState *state;
    Datum       value;
    bool        isnull;

    if (!AggCheckCallContext(fcinfo, &aggcontext))
        elog(ERROR, "json_arrayagg_transfn called in non-aggregate context");

    if (PG_ARGISNULL(0))
    {
        /* first call - initialize state */
        state = (JsonArrayAggState *) MemoryContextAllocZero(aggcontext,
                                                            sizeof(JsonArrayAggState));
        state->skip_null = PG_GETARG_BOOL(1);
        state->first = true;
        json_in_array_start(&state->json);
    }
    else
        state = (JsonArrayAggState *) PG_GETARG_POINTER(0);

    value = PG_GETARG_DATUM(2);
    isnull = PG_ARGISNULL(2);

    if (isnull && state->skip_null)
        PG_RETURN_POINTER(state);

    if (!state->first)
        json_in_array_separator(&state->json);
    else
        state->first = false;

    if (isnull)
        json_in_null(&state->json);
    else
        datum_to_json_internal(value, PG_ARGISNULL(2), &state->json, false);

    PG_RETURN_POINTER(state);
}

