Datum
aggregate_dummy(PG_FUNCTION_ARGS)
{
    JsonbParseState *state = NULL;
    JsonbValue *result;
    JsonbIterator *it;
    JsonbValue  v;
    JsonbValue  *o;
    Oid         key_type;
    Oid         val_type;
    Datum       key;
    Datum       val;
    bool        isnull;

    if (PG_ARGISNULL(0) {
        PG_RETURN_NULL();
    }

    key = PG_GETARG_DATUM(0);
    key_type = get_fn_expr_argtype(fcinfo->flinfo, 0);

    if (PG_ARGISNULL(1)) {
        isnull = true;
        val = (Datum) 0;
    } else {
        isnull = false;
        val = PG_GETARG_DATUM(1);
        val_type = get_fn_expr_argtype(fcinfo->flinfo, 1);
    }

    if (PG_ARGISNULL(2)) {
        /* init state */
        pushJsonbValue(&state, WJB_BEGIN_OBJECT, NULL);
    } else {
        /* get current state */
        it = JsonbIteratorInit(VARDATA(PG_GETARG_JSONB_P(2)));
        while ((o = JsonbIteratorNext(&it, &v, true)) != NULL)
        {
            pushJsonbValue(&state, o->type, o);
        }
    }

    /* add new key-value pair */
    pushJsonbValue(&state, WJB_KEY, 
        &(JsonbValue) {.type = jbvString, 
                       .val.string.len = VARSIZE_ANY_EXHDR(key), 
                       .val.string.val = VARDATA_ANY(key)});

    if (isnull) {
        pushJsonbValue(&state, WJB_VALUE, 
            &(JsonbValue) {.type = jbvNull});
    } else {
        JsonbValue *jval = NULL;
        if (val_type == JSONBOID || val_type == JSONOID) {
            jval = JsonbValueToJsonb(val);
        } else {
            jval = datum_to_jsonb(val, val_type, false);
        }
        pushJsonbValue(&state, WJB_VALUE, jval);
    }

    result = pushJsonbValue(&state, WJB_END_OBJECT, NULL);
    PG_RETURN_POINTER(JsonbValueToJsonb(result));
}

