	JsonbParseState *state = NULL;
	JsonbValue *result = NULL;
	int					i;

	if (nargs % 2 != 0)
		ereleport(ERROR,
				(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
				 errmsg("argument list must have even number of elements")));

	(void) JsonbValueToJsonb(JsonbIteratorInit(NULL));

	for (i = 0; i < nargs; i += 2)
	{
		Datum		key = PG_GETARG_DATUM(i);
		Datum		val = PG_GETARG_DATUM(i + 1);
		JsonbValue	jbkey;
		JsonbValue	jbval;

		if (PG_ARGISNULL(i))
			ereleport(ERROR,
					(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
					 errmsg("key value must not be null"));

		if (PG_ARGISNULL(i + 1))
			continue;

		jbkey.type = jbvString;
		jbkey.val.string.val = TextDatumGetCString(key);
		jbkey.val.string.len = strlen(jbkey.val.string.val);

		if (fcinfo->fn_expr->funcresulttype == JSONBOID)
			jbval = *DatumGetJsonbP(val);
		else
			jbval = *DatumGetJsonbP(to_jsonb(val));

		pushJsonbValue(&state, WJB_KEY, &jbkey);
		pushJsonbValue(&state, WJB_VALUE, &jbval);
	}

	result = pushJsonbValue(&state, WJB_END, NULL);

	if (fcinfo->fn_expr->funcresulttype == JSONBOID)
		PG_RETURN_JSONB_P(JsonbValueToJsonb(result));
