Datum
json_build_object(PG_FUNCTION_ARGS)
{
    int         nargs = PG_NARGS();
    JsonParseState *state = NULL;
    JsonLexContext *lex = NULL;
    JsonValue    *result = NULL;
    int            i;

    if (nargs % 2 != 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("number of arguments must be even")));

    lex = makeJsonLexContext(NULL, false);
    state = makeJsonParseState(lex);
    state->startObject(state);

    for (i = 0; i < nargs; i += 2)
    {
        Datum        key_datum = PG_GETARG_DATUM(i);
        Datum        val_datum = PG_GETARG_DATUM(i + 1);
        text       *key_text;
        JsonValue    key_json;
        JsonValue    val_json;

        if (PG_ARGISNULL(i))
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("key argument cannot be null")));

        if (PG_ARGISNULL(i + 1))
            continue;

        key_text = DatumGetTextPP(key_datum);
        key_json.type = jvString;
        key_json.val.string.len = VARSIZE_ANY_EXHDR(key_text);
        key_json.val.string.val = VARDATA_ANY(key_text);

        val_json = transformJsonValue(val_datum, PG_GETARG_OID(i + 1));

        state->addKey(state, &key_json);
        state->addValue(state, &val_json);
    }

    result = state->getJsonValue(state);
    PG_RETURN_JSONB_P(JsonValueToJsonb(result));
}

static JsonValue
transformJsonValue(Datum val_datum, Oid val_type)
{
    JsonValue    result;
    JsonLexContext *lex;
    JsonParseState *state;

    if (val_type == JSONBOID || val_type == JSONB_ARRAY_OID)
    {
        result.type = jvBinary;
        result.val.binary.data = DatumGetJsonbP(val_datum);
        result.val.binary.len = VARSIZE(result.val.binary.data);
    }
    else
    {
        text       *val_text = DatumGetTextPP(OidFunctionCall1(F_JSON_BUILD_SCALAR, val_datum));

        lex = makeJsonLexContext(NULL, false);
        state = makeJsonParseState(lex);
        state->startArray(state);
        state->addValue(state, &(JsonValue) {jvString,
                                          {.string = {
                                              .len = VARSIZE_ANY_EXHDR(val_text),
                                              .val = VARDATA_ANY(val_text)
                                          }}});
        result = *state->getJsonValue(state);
    }

    return result;
}

