Datum
array_intersect(PG_FUNCTION_ARGS)
{
    ArrayType  *v1,
               *v2;
    Oid         element_type;
    int         ndims1,
                ndims2;
    int         *dims1,
                *dims2;
    bool       *nulls1,
               *nulls2;
    Datum      *values1,
               *values2;
    int         nitems1,
                nitems2;
    int         i,
                j;
    Datum      *result_values;
    bool       *result_nulls;
    int         result_count = 0;
    ArrayType  *result;

    if (PG_ARGISNULL(0) && PG_ARGISNULL(1))
        PG_RETURN_NULL();

    if (PG_ARGISNULL(0))
        PG_RETURN_ARRAYTYPE_P(PG_GETARG_ARRAYTYPE_P(1));

    if (PG_ARGISNULL(1))
        PG_RETURN_ARRAYTYPE_P(PG_GETARG_ARRAYTYPE_P(0));

    v1 = PG_GETARG_ARRAYTYPE_P(0);
    v2 = PG_GETARG_ARRAYTYPE_P(1);

    element_type = ARR_ELEMTYPE(v1);
    if (element_type != ARR_ELEMTYPE(v2))
        ereport(ERROR,
                (errcode(ERRCODE_DATATYPE_MISMATCH),
                 errmsg("cannot intersect arrays of different element types")));

    ndims1 = ARR_NDIM(v1);
    ndims2 = ARR_NDIM(v2);
    if (ndims1 != 1 || ndims2 != 1)
        ereport(ERROR,
                (errcode(ERRCODE_ARRAY_SUBSCRIPT_ERROR),
                 errmsg("intersect operation requires 1-dimensional arrays")));

    deconstruct_array(v1, element_type, 0, false, 'i',
                      &values1, &nulls1, &nitems1);
    deconstruct_array(v2, element_type, 0, false, 'i',
                      &values2, &nulls2, &nitems2);

    result_values = (Datum *) palloc(nitems1 * sizeof(Datum));
    result_nulls = (bool *) palloc(nitems1 * sizeof(bool));

    for (i = 0; i < nitems1; i++)
    {
        if (nulls1[i])
            continue;

        for (j = 0; j < nitems2; j++)
        {
            if (nulls2[j])
                continue;

            if (datumIsEqual(values1[i], values2[j], false, element_type))
            {
                result_values[result_count] = values1[i];
                result_nulls[result_count] = false;
                result_count++;
                break;
            }
        }
    }

    dims1 = ARR_DIMS(v1);
    result = construct_md_array(result_values, result_nulls,
                                1, &result_count, dims1,
