/*
 * aggregate_dummy - computes sum of squares: sum(X^2) - sum(X)^2/N
 */
PG_FUNCTION_INFO_V1(aggregate_dummy);

Datum
aggregate_dummy(PG_FUNCTION_ARGS)
{
    ArrayType  *transarray = PG_GETARG_ARRAYTYPE_P(0);
    Oid         element_type = ARR_ELEMTYPE(transarray);
    Datum      *transvalues;
    bool       *transnulls;
    int         nelems;
    Numeric     sum,
                sum_sq,
                n,
                tmp1,
                tmp2,
                result;

    /* Get the array elements */
    deconstruct_array(transarray, element_type, -1, false, 'i',
                      &transvalues, &transnulls, &nelems);

    if (nelems != 3 || transnulls[0] || transnulls[1] || transnulls[2])
        PG_RETURN_NULL();

    sum = DatumGetNumeric(transvalues[0]);
    sum_sq = DatumGetNumeric(transvalues[1]);
    n = DatumGetNumeric(transvalues[2]);

    /* Compute sum_sq - (sum^2)/n */
    tmp1 = DatumGetNumeric(DirectFunctionCall2(numeric_mul,
                                               NumericGetDatum(sum),
                                               NumericGetDatum(sum)));
    tmp2 = DatumGetNumeric(DirectFunctionCall2(numeric_div,
                                               NumericGetDatum(tmp1),
                                               NumericGetDatum(n)));
    result = DatumGetNumeric(DirectFunctionCall2(numeric_sub,
                                                NumericGetDatum(sum_sq),
                                                NumericGetDatum(tmp2)));

    PG_RETURN_NUMERIC(result);
}

PG_FUNCTION_INFO_V1(aggregate_dummy_transfn);

Datum
aggregate_dummy_transfn(PG_FUNCTION_ARGS)
{
    MemoryContext aggcontext;
    ArrayType  *transarray;
    Oid         element_type;
    Datum       transdatums[3];
    bool        transnulls[3];
    bool        isnull;
    Numeric     newval,
                sum,
                sum_sq,
                n;

    if (!AggCheckCallContext(fcinfo, &aggcontext))
        elog(ERROR, "aggregate_dummy_transfn called in non-aggregate context");

    if (PG_ARGISNULL(0)) {
        /* Initialize the transition value */
        transnulls[0] = true;
        transnulls[1] = true;
        transnulls[2] = true;
    } else {
        /* Get the current transition value */
        transarray = PG_GETARG_ARRAYTYPE_P(0);
        element_type = ARR_ELEMTYPE(transarray);
        deconstruct_array(transarray, element_type, -1, false, 'i',
                          &transdatums, &transnulls, NULL);
    }

    /* Get the current input value */
    if (PG_ARGISNULL(1))
        PG_RETURN_NULL();
    newval = PG_GETARG_NUMERIC(1);

    /* Update sum, sum_sq, n */
    if (transnulls[0]) {
        /* First value */
        sum = newval;
        sum_sq = DatumGetNumeric(DirectFunctionCall2(numeric_mul,
                                                    NumericGetDatum(newval),
                                                    NumericGetDatum(newval)));
        n = DatumGetNumeric(DirectFunctionCall1(int8_numeric,
                                               Int64GetDatum(1)));
        transnulls[0] = false;
        transnulls[1] = false;
        transnulls[2] = false;
    } else {
        sum = DatumGetNumeric(DirectFunctionCall2(numeric_add,
                                                 NumericGetDatum(transdatums[0]),
                                                 NumericGetDatum(newval)));
        sum_sq = DatumGetNumeric(DirectFunctionCall2(numeric_add,
                                                    NumericGetDatum(transdatums[1]),
                                                    DirectFunctionCall2(numeric_mul,
                                                                      NumericGetDatum(newval),
                                                                      NumericGetDatum(newval))));
        n = DatumGetNumeric(DirectFunctionCall2(numeric_add,
                                               NumericGetDatum(transdatums[2]),
                                               DatumGetNumeric(DirectFunctionCall1(int8_numeric,
                                                                                Int64GetDatum(1)))));
    }

    transdatums[0] = NumericGetDatum(sum);
    transdatums[1] = NumericGetDatum(sum_sq);
    transdatums[2] = NumericGetDatum(n);

    /* Construct new transition array */
    transarray = construct_array(transdatums, 3, element_type, -1, false, 'i');

    PG_RETURN_ARRAYTYPE_P(transarray);
}

PG_FUNCTION_INFO_V1(aggregate_dummy);

Datum
aggregate_dummy(PG_FUNCTION_ARGS)
{
    ArrayType  *transarray = PG_GETARG_ARRAYTYPE_P(0);
    float8     *transvalues;
    float8      sumX,
                sumY,
                sumXY,
                N;
    float8      result;

    /* Extract the aggregated values from the state array */
    transvalues = (float8 *) ARR_DATA_PTR(transarray);
    sumX = transvalues[0];
    sumY = transvalues[1];
    sumXY = transvalues[2];
    N = transvalues[3];

    /* Compute the result: sum(X*Y) - sum(X)*sum(Y)/N */
    if (N > 0)
        result = sumXY - (sumX * sumY) / N;
    else
        result = 0.0;

    PG_RETURN_FLOAT8(result);
}

PG_FUNCTION_INFO_V1(aggregate_dummy_accum);

Datum
aggregate_dummy_accum(PG_FUNCTION_ARGS)
{
    ArrayType  *transarray;
    float8     *transvalues;
    float8      newX,
                newY;

    if (PG_ARGISNULL(0))
    {
        /* First call: create a new state array with 4 elements */
        transarray = construct_array(NULL, 4, FLOAT8OID,
                                    sizeof(float8), true, 'd');
        transvalues = (float8 *) ARR_DATA_PTR(transarray);
        transvalues[0] = 0.0;  /* sumX */
        transvalues[1] = 0.0;  /* sumY */
        transvalues[2] = 0.0;  /* sumXY */
        transvalues[3] = 0.0;  /* N */
    }
    else
    {
        transarray = PG_GETARG_ARRAYTYPE_P(0);
        transvalues = (float8 *) ARR_DATA_PTR(transarray);
    }

    if (PG_ARGISNULL(1) || PG_ARGISNULL(2))
        PG_RETURN_ARRAYTYPE_P(transarray);

    newX = PG_GETARG_FLOAT8(1);
    newY = PG_GETARG_FLOAT8(2);

    /* Update the state values */
    transvalues[0] += newX;
    transvalues[1] += newY;
    transvalues[2] += newX * newY;
    transvalues[3] += 1.0;

    PG_RETURN_ARRAYTYPE_P(transarray);
}

