/*
 * window_cume_dist
 * Returns the cumulative distribution, that is (number of partition rows
 * preceding or peers with current row) / (total partition rows).
 * The value thus ranges from 1/N to 1.
 */
Datum
window_cume_dist(PG_FUNCTION_ARGS)
{
    WindowObject winobj = PG_WINDOW_OBJECT();
    int64        row_count;
    int64        rank;
    float8       result;

    /* Get total number of rows in partition */
    row_count = WinGetPartitionRowCount(winobj);

    /* Get number of rows preceding or peers with current row */
    rank = WinGetCurrentRank(winobj);

    /* Calculate cumulative distribution */
    result = (float8) rank / (float8) row_count;

    PG_RETURN_FLOAT8(result);
}

