#include "postgres.h"
#include "fmgr.h"
#include "windowapi.h"
#include "utils/builtins.h"

PG_MODULE_MAGIC;

PG_FUNCTION_INFO_V1(window_last_value);

Datum
window_last_value(PG_FUNCTION_ARGS)
{
    WindowObject winobj = PG_WINDOW_OBJECT();
    int64 frameOptions = WinGetCurrentFrameOptions(winobj);
    bool frameHasLast = (frameOptions & FRAMEOPTION_LAST_VALUE) != 0;

    if (!frameHasLast)
        PG_RETURN_NULL();

    int frameLength = WinGetFrameCount(winobj);
    if (frameLength <= 0)
        PG_RETURN_NULL();

    int currentPos = WinGetCurrentPosition(winobj);
    int frameEndPos = WinGetFrameLastPosition(winobj);

    if (frameEndPos < 0 || frameEndPos >= frameLength)
        PG_RETURN_NULL();

    bool isNull;
    Datum value = WinGetFuncArgCurrent(winobj, 0, &isNull);

    if (isNull)
        PG_RETURN_NULL();

    PG_RETURN_DATUM(value);
}

