#include "postgres.h"
#include "fmgr.h"
#include "windowapi.h"
#include "utils/builtins.h"

PG_MODULE_MAGIC;

PG_FUNCTION_INFO_V1(window_nth_value);

Datum
window_nth_value(PG_FUNCTION_ARGS)
{
    WindowObject winobj = PG_WINDOW_OBJECT();
    int64 n = PG_GETARG_INT64(1);
    bool strict = PG_GETARG_BOOL(2);
    bool isnull;
    Datum result;
    int64 row;

    if (n < 1)
        PG_RETURN_NULL();

    row = WinGetCurrentPosition(winobj) + n - 1;

    if (row < 0 || row >= WinGetPartitionRowCount(winobj))
    {
        if (strict)
            PG_RETURN_NULL();
        else
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("argument of nth_value must be between 1 and the number of rows in the window frame")));
    }

    result = WinGetFuncArgInPartition(winobj, 0, row, WINDOW_SEEK_HEAD, false, &isnull);

    if (isnull)
        PG_RETURN_NULL();

    PG_RETURN_DATUM(result);
}

