Datum
generate_series_step_int4(PG_FUNCTION_ARGS)
{
    int32        start = PG_GETARG_INT32(0);
    int32        stop = PG_GETARG_INT32(1);
    int32        step = PG_GETARG_INT32(2);
    FuncCallContext *funcctx;
    int32       *result;

    if (SRF_IS_FIRSTCALL())
    {
        MemoryContext oldcontext;
        funcctx = SRF_FIRSTCALL_INIT();
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);
        funcctx->user_fctx = palloc(sizeof(int32));
        result = (int32 *) funcctx->user_fctx;
        *result = start;
        MemoryContextSwitchTo(oldcontext);
    }

    funcctx = SRF_PERCALL_SETUP();
    result = (int32 *) funcctx->user_fctx;

    if ((step > 0 && *result <= stop) || (step < 0 && *result >= stop))
    {
        int32        curr = *result;
        *result += step;
        SRF_RETURN_NEXT(funcctx, Int32GetDatum(curr));
    }
    else
        SRF_RETURN_DONE(funcctx);
}

