#include "postgres.h"

#include "catalog/pg_type.h"
#include "utils/array.h"
#include "utils/builtins.h"
#include "utils/lsyscache.h"
#include "utils/memutils.h"


/*
 * generate_subscripts - generate a series of subscripts for an array dimension
 */
Datum
generate_subscripts(PG_FUNCTION_ARGS)
{
    ArrayType  *v = PG_GETARG_ARRAYTYPE_P(0);
    int         dim = PG_GETARG_INT32(1);
    bool        reverse = PG_GETARG_BOOL(2);
    ReturnSetInfo *rsinfo = (ReturnSetInfo *) fcinfo->resultinfo;
    ArrayMetaState *my_extra;
    int16       typlen;
    bool        typbyval;
    char        typalign;
    int         ndim,
               *dimv,
               *lbv;
    int         start,
               end,
               step,
               i;
    int         j;

    /* check to see if caller supports us returning a tuplestore */
    if (rsinfo == NULL || !IsA(rsinfo, ReturnSetInfo))
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                 errmsg("set-valued function called in context that cannot accept a set")));
    if (!(rsinfo->allowedModes & SFRM_Materialize))
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                 errmsg("materialize mode required, but it is not allowed in this context")));

    rsinfo->returnMode = SFRM_Materialize;
    rsinfo->setResult = NULL;
    rsinfo->setDesc = NULL;

    /* get array information */
    ndim = ARR_NDIM(v);
    if (ndim <= 0 || dim <= 0 || dim > ndim)
        PG_RETURN_NULL();

    dimv = ARR_DIMS(v);
    lbv = ARR_LBOUND(v);

    /* setup iteration parameters */
    if (reverse)
    {
        start = lbv[dim - 1] + dimv[dim - 1] - 1;
        end = lbv[dim - 1];
        step = -1;
    }
    else
    {
        start = lbv[dim - 1];
        end = lbv[dim - 1] + dimv[dim - 1] - 1;
        step = 1;
    }

    /* create tuplestore */
    my_extra = (ArrayMetaState *) fcinfo->flinfo->fn_extra;
    if (my_extra == NULL)
    {
        fcinfo->flinfo->fn_extra = MemoryContextAlloc(fcinfo->flinfo->fn_mcxt,
                                                     sizeof(ArrayMetaState));
        my_extra = (ArrayMetaState *) fcinfo->flinfo->fn_extra;
        my_extra->element_type = INT4OID;
        get_typlenbyvalalign(my_extra->element_type,
                            &my_extra->typlen,
                            &my_extra->typbyval,
                            &my_extra->typalign);
    }
    typlen = my_extra->typlen;
    typbyval = my_extra->typbyval;
    typalign = my_extra->typalign;

    rsinfo->setResult = tuplestore_begin_heap(true, false, work_mem);
    rsinfo->setDesc = CreateTemplateTupleDesc(1);
    TupleDescInitEntry(rsinfo->setDesc, 1, "generate_subscripts",
                      INT4OID, -1, 0);

    /* generate subscripts */
    for (i = start; (step > 0) ? (i <= end) : (i >= end); i += step)
    {
        Datum       values[1];
        bool        nulls[1] = {false};

        values[0] = Int32GetDatum(i);
        tuplestore_putvalues(rsinfo->setResult, rsinfo->setDesc, values, nulls);
    }

    /* clean up and return */
    tuplestore_donestoring(rsinfo->setResult);

    PG_RETURN_NULL();
}

/*
 * generate_subscripts_nodir - same as generate_subscripts but without reverse option
 */
Datum
generate_subscripts_nodir(PG_FUNCTION_ARGS)
{
    return generate_subscripts(fcinfo);
}

