PG_FUNCTION_INFO_V1(current_schema);

Datum
current_schema(PG_FUNCTION_ARGS)
{
    List       *search_path;
    ListCell   *l;
    Oid            namespaceId;

    /* Get the search path */
    search_path = fetch_search_path(false);

    /* The first valid entry in the search path is the current schema */
    foreach(l, search_path)
    {
        namespaceId = lfirst_oid(l);
        if (namespaceId != PG_CATALOG_NAMESPACE)
        {
            char       *nspname;

            nspname = get_namespace_name(namespaceId);
            if (nspname == NULL)
                continue;    /* recently-deleted namespace? skip it */

            PG_RETURN_TEXT_P(cstring_to_text(nspname));
        }
    }

    /* If we get here, the search path is empty */
    PG_RETURN_NULL();
}

