Datum
current_schemas(PG_FUNCTION_ARGS)
{
    bool        include_implicit = PG_GETARG_BOOL(0);
    List       *search_path = fetch_search_path(include_implicit);
    ListCell   *l;
    ArrayBuildState *astate = NULL;

    foreach(l, search_path)
    {
        Oid            namespaceId = lfirst_oid(l);
        char       *nspname = get_namespace_name(namespaceId);

        if (nspname == NULL)
            continue;        /* ignore deleted namespaces */

        astate = accumArrayResult(astate,
                                 CStringGetTextDatum(nspname),
                                 false,
                                 TEXTOID,
