#include "postgres.h"
#include "libpq/libpq.h"
#include "utils/builtins.h"
#include "utils/inet.h"

PG_FUNCTION_INFO_V1(inet_client_addr);

Datum
inet_client_addr(PG_FUNCTION_ARGS)
{
    Port       *port = MyProcPort;

    if (port == NULL || port->raddr.addr.ss_family == AF_UNIX)
        PG_RETURN_NULL();

    switch (port->raddr.addr.ss_family)
    {
        case AF_INET:
        {
            struct sockaddr_in *addr = (struct sockaddr_in *) &port->raddr.addr;
            inet_datagram *result = (inet_datagram *) palloc0(sizeof(inet_datagram));

            result->family = PGSQL_AF_INET;
            result->bits = 32;
            result->ipaddr = addr->sin_addr.s_addr;

            PG_RETURN_INET_P(result);
        }
        case AF_INET6:
        {
            struct sockaddr_in6 *addr = (struct sockaddr_in6 *) &port->raddr.addr;
            inet_datagram *result = (inet_datagram *) palloc0(sizeof(inet_datagram));

            result->family = PGSQL_AF_INET6;
            result->bits = 128;
            memcpy(&result->ipaddr6, &addr->sin6_addr, sizeof(result->ipaddr6));

            PG_RETURN_INET_P(result);
        }
        default:
            PG_RETURN_NULL();
    }
}

