#include "postgres.h"
#include "funcapi.h"
#include "miscadmin.h"
#include "storage/lmgr.h"
#include "storage/proc.h"
#include "utils/array.h"
#include "utils/builtins.h"

PG_FUNCTION_INFO_V1(pg_blocking_pids);

Datum
pg_blocking_pids(PG_FUNCTION_ARGS)
{
    int         blocked_pid = PG_GETARG_INT32(0);
    ArrayBuildState *astate = NULL;
    ProcNumber blocked_procnum;
    LockInstanceData *lockData;
    int         numLocks;
    int         i;

    /* Check if the input PID is valid */
    if (blocked_pid <= 0)
        PG_RETURN_ARRAYTYPE_P(construct_empty_array(INT4OID));

    /* Get the proc number for the given PID */
    blocked_procnum = GetProcNumberByPid(blocked_pid);
    if (blocked_procnum == INVALID_PROC_NUMBER)
        PG_RETURN_ARRAYTYPE_P(construct_empty_array(INT4OID));

    /* Get lock manager data */
    lockData = GetLockStatusData(&numLocks);

    /* Scan the lock data to find blocking processes */
    for (i = 0; i < numLocks; i++)
    {
        LockInstanceData *lock = &lockData[i];

        /* Skip if not the blocked process we're interested in */
        if (lock->pid != blocked_pid)
            continue;

        /* Check for hard blocks (conflicting locks held by others) */
        if (lock->holdMask != 0)
        {
            int         j;

            for (j = 0; j < numLocks; j++)
            {
                LockInstanceData *otherLock = &lockData[j];

                if (otherLock->tag.locktag_field1 == lock->tag.locktag_field1 &&
                    otherLock->tag.locktag_field2 == lock->tag.locktag_field2 &&
                    otherLock->tag.locktag_field3 == lock->tag.locktag_field3 &&
                    otherLock->tag.locktag_field4 == lock->tag.locktag_field4 &&
                    otherLock->tag.locktag_type == lock->tag.locktag_type &&
                    otherLock->tag.locktag_lockmethodid == lock->tag.locktag_lockmethodid &&
                    otherLock->pid != blocked_pid &&
                    (otherLock->holdMask & lock->waitMask) != 0)
                {
                    /* Found a blocking process */
                    astate = accumArrayResult(astate, Int32GetDatum(otherLock->pid),
                                              false, INT4OID, CurrentMemoryContext);
                }
            }
        }

        /* Check for soft blocks (processes ahead in wait queue) */
        if (lock->waitLock != NULL)
        {
            PGPROC     *blocked_proc = BackendPidGetProc(blocked_pid);
            LOCK       *waitLock = lock->waitLock;
            PROCLOCK   *proclock;
            SHM_QUEUE  *procLocks = &(waitLock->procLocks);
            SHMEM_OFFSET end = procLocks->prev;

            for (proclock = (PROCLOCK *) SHMQueueNext(procLocks, procLocks, offsetof(PROCLOCK, lockLink));
                 proclock != NULL;
                 proclock = (PROCLOCK *) SHMQueueNext(procLocks, &proclock->lockLink, offsetof(PROCLOCK, lockLink)))
            {
                PGPROC     *blocker = proclock->groupLeader;

                if (blocker == NULL)
                    blocker = proclock->proc;

                if (blocker != blocked_proc &&
                    (proclock->holdMask & lock->waitMask) != 0)
                {
                    /* Found a blocking process */
                    astate = accumArrayResult(astate, Int32GetDatum(blocker->pid),
                                              false, INT4OID, CurrentMemoryContext);
                }

                /* Stop if we've looped back to the start */
                if (SHMQueuePrev(procLocks, &proclock->lockLink, offsetof(PROCLOCK, lockLink)) == end)
                    break;
            }
        }
    }

    if (astate == NULL)
        PG_RETURN_ARRAYTYPE_P(construct_empty_array(INT4OID));
    else
        PG_RETURN_ARRAYTYPE_P(makeArrayResult(astate, CurrentMemoryContext));
}

