PG_FUNCTION_INFO_V1(pg_current_logfile);

Datum
pg_current_logfile(PG_FUNCTION_ARGS)
{
    char       *log_format = NULL;
    char       *log_filename = NULL;
    FILE       *fp;
    char        current_logfiles_path[MAXPGPATH];
    char        line[MAXPGPATH];
    char        format[32];
    char        path[MAXPGPATH];
    bool        found = false;

    if (!PG_ARGISNULL(0))
        log_format = text_to_cstring(PG_GETARG_TEXT_PP(0));

    /* Check privileges */
    if (!superuser() && !has_rolreplication(GetUserId()))
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                 errmsg("must be superuser or replication role to use this function")));

    /* Get the path to the current_logfiles file */
    snprintf(current_logfiles_path, sizeof(current_logfiles_path), "%s/current_logfiles",
             Log_directory);

    /* Open the current_logfiles file */
    fp = AllocateFile(current_logfiles_path, "r");
    if (fp == NULL)
        PG_RETURN_NULL();

    /* Read each line of the file */
    while (fgets(line, sizeof(line), fp) != NULL)
    {
        if (sscanf(line, "%31s %1023s", format, path) == 2)
        {
            if (log_format == NULL)
            {
                /* No format specified, return the first matching known format */
                if (strcmp(format, "stderr") == 0 ||
                    strcmp(format, "csvlog") == 0 ||
                    strcmp(format, "jsonlog") == 0)
                {
                    log_filename = pstrdup(path);
                    found = true;
                    break;
                }
            }
            else if (strcmp(format, log_format) == 0)
            {
                /* Specific format requested */
                log_filename = pstrdup(path);
                found = true;
                break;
            }
        }
    }

    FreeFile(fp);

    if (!found)
        PG_RETURN_NULL();

    PG_RETURN_TEXT_P(cstring_to_text(log_filename));
}

