Datum
pg_blocking_session_ids(PG_FUNCTION_ARGS)
{
    int32        pid = PG_GETARG_INT32(0);
    ArrayBuildState *astate = NULL;
    int         *blockers;
    int            nblockers;
    int            i;

    /* Check permissions */
    if (!superuser())
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                 errmsg("must be superuser to use pg_blocking_session_ids")));

    /* Get the list of blocking PIDs */
    blockers = GetBlockingSessionIds(pid, &nblockers);

    /* Build the result array */
    for (i = 0; i < nblockers; i++)
    {
        astate = accumArrayResult(astate,
                                 Int32GetDatum(blockers[i]),
                                 false,
                                 INT4OID,
                                 CurrentMemoryContext);
    }

    if (astate == NULL)
        PG_RETURN_ARRAYTYPE_P(construct_empty_array(INT4OID));
    else
        PG_RETURN_ARRAYTYPE_P(makeArrayResult(astate, CurrentMemoryContext));
}

