/*
 * has_column_privilege variants
 * These functions check whether a user can access a particular column
 * in a particular way.  The variants are:
 *
 * name_name_name: user name, table name, column name
 * name_name_attnum: user name, table name, column attnum
 * name_id_name: user name, table oid, column name
 * name_id_attnum: user name, table oid, column attnum
 * id_name_name: user oid, table name, column name
 * id_name_attnum: user oid, table name, column attnum
 * id_id_name: user oid, table oid, column name
 * id_id_attnum: user oid, table oid, column attnum
 * name_name: user name inferred, table name, column name
 * name_attnum: user name inferred, table name, column attnum
 * id_name: user oid inferred, table name, column name
 * id_attnum: user oid inferred, table name, column attnum
 */

#include "postgres.h"
#include "access/htup_details.h"
#include "catalog/namespace.h"
#include "catalog/pg_attribute.h"
#include "catalog/pg_class.h"
#include "catalog/pg_type.h"
#include "miscadmin.h"
#include "utils/acl.h"
#include "utils/builtins.h"
#include "utils/lsyscache.h"
#include "utils/syscache.h"
#include "utils/varlena.h"


static bool
column_privilege_check(Oid tableoid, AttrNumber attnum,
                      Oid roleid, AclMode mode)
{
    AclMode       remaining;
    AclResult    aclresult;
    HeapTuple    attTuple;
    Form_pg_attribute attribute;

    /* First check at table level */
    aclresult = pg_class_aclcheck(tableoid, roleid, mode);
    if (aclresult == ACLCHECK_OK)
        return true;

    /* If we have column-level privileges, check those too */
    attTuple = SearchSysCache2(ATTNUM,
                               ObjectIdGetDatum(tableoid),
                               Int16GetDatum(attnum));
    if (!HeapTupleIsValid(attTuple))
        return false;

    attribute = (Form_pg_attribute) GETSTRUCT(attTuple);

    /* Check column-level privileges */
    aclresult = pg_attribute_aclcheck(tableoid, attnum, roleid, mode);

    ReleaseSysCache(attTuple);

    return (aclresult == ACLCHECK_OK);
}

/* Common logic for all has_column_privilege functions */
static Datum
has_column_privilege_common(Oid roleid, Oid tableoid, Datum colarg, bool is_attnum, text *priv_type)
{
    AttrNumber    attnum;
    AclMode        mode;
    char       *colname;

    /* Parse the privilege type */
    mode = convert_column_priv_string(priv_type);

    if (is_attnum)
        attnum = DatumGetInt16(colarg);
    else
    {
        colname = TextDatumGetCString(colarg);
        attnum = get_attnum(tableoid, colname);
        if (attnum == InvalidAttrNumber)
            PG_RETURN_NULL();
    }

    if (column_privilege_check(tableoid, attnum, roleid, mode))
        PG_RETURN_BOOL(true);
    else
        PG_RETURN_BOOL(false);
}

