/*
 * convert_function_priv_string
 *        Convert text string to AclMode value.
 *
 * We use EXECUTE as the only allowed privilege type for functions.
 */
static AclMode
convert_function_priv_string(text *priv_type_text)
{
    char       *priv_type = text_to_cstring(priv_type_text);

    if (pg_strcasecmp(priv_type, "EXECUTE") == 0)
        return ACL_EXECUTE;
    if (pg_strcasecmp(priv_type, "EXECUTE WITH GRANT OPTION") == 0)
        return ACL_EXECUTE | ACL_GRANT_OPTION_FOR(ACL_EXECUTE);

    ereport(ERROR,
            (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
             errmsg("unrecognized privilege type: \"%s\"", priv_type)));
    return ACL_NO_RIGHTS;        /* keep compiler quiet */
}

/*
 * convert_function_name
 *        Convert text function name to OID.
 *
 * The text argument is parsed as a regprocedure.
 */
static Oid
convert_function_name(text *functionname)
{
    char       *funcname = text_to_cstring(functionname);
    Oid            oid;

    oid = parse_fn_identifier(funcname);
    if (!OidIsValid(oid))
        ereport(ERROR,
                (errcode(ERRCODE_UNDEFINED_FUNCTION),
                 errmsg("function \"%s\" does not exist", funcname)));

    return oid;
}

