has_table_privilege_name_name(PG_FUNCTION_ARGS)
{
    Name        username = PG_GETARG_NAME(0);
    Name        table = PG_GETARG_NAME(1);
    text       *priv_type = PG_GETARG_TEXT_PP(2);
    Oid            userid;
    Oid            tableoid;
    AclMode        mode;
    Oid            ownerId;
    Acl           *acl;
    bool        result;

    userid = get_role_oid(NameStr(*username), false);
    tableoid = convert_table_name(table);
    mode = convert_table_priv_string(priv_type);

    /* First check at table level */
    acl = get_user_table_acl(tableoid, userid, &ownerId);
    result = aclcheck(acl, userid, ownerId, mode) == ACLCHECK_OK;

    if (!result)
    {
        /* If no privileges at table level, try at schema level */
        Oid            schemaoid = get_rel_namespace(tableoid);
        acl = get_user_namespace_acl(schemaoid, userid, &ownerId);
        result = aclcheck(acl, userid, ownerId, mode) == ACLCHECK_OK;
    }

    PG_RETURN_BOOL(result);
}

