/*
 * row_security_active
 *		Check if row-level security is active for the specified table OID
 *
 * Returns true if RLS is active for the table and the current user has
 * permission to bypass RLS, false otherwise.
 */
Datum
row_security_active(PG_FUNCTION_ARGS)
{
	Oid			tableoid = PG_GETARG_OID(0);
	Relation	rel;
	bool		result;

	rel = relation_open(tableoid, AccessShareLock);

	result = relation_has_row_security(rel) &&
			 !has_bypassrls_privilege(GetUserId());

	relation_close(rel, AccessShareLock);

	PG_RETURN_BOOL(result);
}

/*
 * row_security_active_name
 *		Check if row-level security is active for the specified table name
 *
 * This is the name-based version of row_security_active.
 */
Datum
row_security_active_name(PG_FUNCTION_ARGS)
{
	text	*tablename = PG_GETARG_TEXT_PP(0);
	RangeVar *relrv;
	Relation	rel;
	bool		result;
	Oid			reloid;

	relrv = makeRangeVarFromNameList(textToQualifiedNameList(tablename));
	reloid = RangeVarGetRelid(relrv, AccessShareLock, false);
	rel = relation_open(reloid, AccessShareLock);

	result = relation_has_row_security(rel) &&
			 !has_bypassrls_privilege(GetUserId());

	relation_close(rel, AccessShareLock);

	PG_RETURN_BOOL(result);
}

