/*
 * aclexplode
 *    Returns the aclitem array as a set of rows.
 */
Datum
aclexplode(PG_FUNCTION_ARGS)
{
    FuncCallContext *funcctx;
    AclExplodeState *state;
    MemoryContext oldcontext;
    Datum        result;

    if (SRF_IS_FIRSTCALL())
    {
        ArrayType  *aclarray;
        AclItem    *aclitems;
        int            nitems;
        int            i;

        funcctx = SRF_FIRSTCALL_INIT();
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

        aclarray = PG_GETARG_ARRAYTYPE_P(0);
        deconstruct_array(aclarray, ACLITEMOID, sizeof(AclItem), false, 'i',
                         &aclitems, NULL, &nitems);

        state = (AclExplodeState *) palloc(sizeof(AclExplodeState));
        state->items = aclitems;
        state->nitems = nitems;
        state->next = 0;

        funcctx->user_fctx = state;

        MemoryContextSwitchTo(oldcontext);
    }

    funcctx = SRF_PERCALL_SETUP();
    state = (AclExplodeState *) funcctx->user_fctx;

    while (state->next < state->nitems)
    {
        AclItem    *item = &state->items[state->next];
        char       *privtype;
        Oid            grantee = item->ai_grantee;
        HeapTuple    tuple;
        Datum        values[3];
        bool        nulls[3] = {false, false, false};

        switch (item->ai_privs)
        {
            case ACL_SELECT:
                privtype = "SELECT";
                break;
            case ACL_INSERT:
                privtype = "INSERT";
                break;
            case ACL_UPDATE:
                privtype = "UPDATE";
                break;
            case ACL_DELETE:
                privtype = "DELETE";
                break;
            case ACL_TRUNCATE:
                privtype = "TRUNCATE";
                break;
            case ACL_REFERENCES:
                privtype = "REFERENCES";
                break;
            case ACL_TRIGGER:
                privtype = "TRIGGER";
                break;
            case ACL_EXECUTE:
                privtype = "EXECUTE";
                break;
            case ACL_USAGE:
                privtype = "USAGE";
                break;
            case ACL_CREATE:
                privtype = "CREATE";
                break;
            case ACL_CREATE_TEMP:
                privtype = "CREATE TEMP";
                break;
            case ACL_CONNECT:
                privtype = "CONNECT";
                break;
            default:
                elog(ERROR, "unrecognized privilege: %d", item->ai_privs);
                privtype = NULL;    /* keep compiler quiet */
                break;
        }

        if (grantee == ACL_ID_PUBLIC)
            grantee = InvalidOid;

        values[0] = ObjectIdGetDatum(grantee);
        values[1] = CStringGetTextDatum(privtype);
        values[2] = BoolGetDatum(item->ai_grantable);

        tuple = heap_form_tuple(funcctx->tuple_desc, values, nulls);
        result = HeapTupleGetDatum(tuple);

        state->next++;
        SRF_RETURN_NEXT(funcctx, result);
    }

    SRF_RETURN_DONE(funcctx);
}

