#include "postgres.h"
#include "utils/acl.h"
#include "utils/builtins.h"
#include "utils/lsyscache.h"
#include "catalog/pg_authid.h"
#include "miscadmin.h"

/*
 * makeaclitem
 *    Constructs an aclitem with the given properties.
 *    privileges is a comma-separated list of privilege names.
 */
Datum
makeaclitem(PG_FUNCTION_ARGS)
{
    Oid            grantee = PG_GETARG_OID(0);
    Oid            grantor = PG_GETARG_OID(1);
    text       *privs_text = PG_GETARG_TEXT_PP(2);
    bool        is_grant = PG_GETARG_BOOL(3);
    AclItem    *result;
    AclMode    privs;
    char       *privs_str;
    char       *nextp;
    char       *token;

    /* Convert text to C string */
    privs_str = text_to_cstring(privs_text);

    /* Parse privilege string */
    privs = ACL_NO_RIGHTS;
    nextp = privs_str;
    while ((token = strtok(nextp, ",")) != NULL)
    {
        AclMode    priv;

        nextp = NULL;

        /* Remove leading/trailing whitespace */
        while (*token && isspace((unsigned char) *token))
            token++;
        if (*token == '\0')
            continue;

        /* Parse privilege name */
        priv = convert_priv_string(token);
        if (priv == ACL_NO_RIGHTS)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("unrecognized privilege type: \"%s\"", token)));

        privs |= priv;
    }

    pfree(privs_str);

    /* Construct the aclitem */
    result = (AclItem *) palloc(sizeof(AclItem));
    ACLITEM_SET(*result, grantee, grantor, privs);
    if (!is_grant)
        ACLITEM_CLEAR_RIGHTS(*result, privs);

    PG_RETURN_ACLITEM_P(result);
}

