#include "catalog/namespace.h"
#include "utils/builtins.h"
#include "utils/syscache.h"

/*
 * pg_conversion_is_visible
 *		Determine whether a conversion (identified by OID) is visible in the
 *		current search path. Visible means "would be found by searching for the
 *		unqualified conversion name".
 */
bool
pg_conversion_is_visible(Oid conid)
{
	HeapTuple	convtup;
	Form_pg_conversion convform;
	Oid			connamespace;
	bool		visible;

	convtup = SearchSysCache1(CONVOID, ObjectIdGetDatum(conid));
	if (!HeapTupleIsValid(convtup))
		elog(ERROR, "cache lookup failed for conversion %u", conid);
	convform = (Form_pg_conversion) GETSTRUCT(convtup);
	connamespace = convform->connamespace;

	visible = ConversionIsVisible(conid);

	ReleaseSysCache(convtup);

	return visible;
}

/*
 * ConversionIsVisible
 *		Determine whether a conversion is visible in the current search path.
 *
 * This is the same as pg_conversion_is_visible() except it's intended to be
 * called when we already have the conversion's pg_conversion tuple.
 */
static bool
ConversionIsVisible(Oid conid)
{
	HeapTuple	convtup;
	Form_pg_conversion convform;
	Oid			connamespace;
	char	   *conname;
	ListCell   *l;

	convtup = SearchSysCache1(CONVOID, ObjectIdGetDatum(conid));
	if (!HeapTupleIsValid(convtup))
		elog(ERROR, "cache lookup failed for conversion %u", conid);
	convform = (Form_pg_conversion) GETSTRUCT(convtup);
	connamespace = convform->connamespace;
	conname = NameStr(convform->conname);

	/*
	 * If it's in the system namespace, it's visible if the system namespace
	 * is first in the search path.
	 */
	if (connamespace == PG_CATALOG_NAMESPACE)
	{
		List *activeSearchPath = fetch_search_path(false);
		bool visible = (activeSearchPath != NIL && 
						linitial_oid(activeSearchPath) == PG_CATALOG_NAMESPACE);
		list_free(activeSearchPath);
		ReleaseSysCache(convtup);
		return visible;
	}

	/* Else, check for exact match to any path element */
	foreach(l, activeSearchPath)
	{
		Oid namespaceId = lfirst_oid(l);

		if (namespaceId == connamespace)
		{
			ReleaseSysCache(convtup);
			return true;
		}
		if (namespaceId == PG_CATALOG_NAMESPACE)
			break;				/* don't look past pg_catalog */
	}

	ReleaseSysCache(convtup);
	return false;
}

