Datum
pg_basetype(PG_FUNCTION_ARGS)
{
    Oid         typid = PG_GETARG_OID(0);
    TypeCacheEntry *typentry;
    Oid         base_type;

    if (!OidIsValid(typid))
        PG_RETURN_NULL();

    typentry = lookup_type_cache(typid, TYPECACHE_DOMAIN_BASE_INFO);

    if (typentry->typtype != TYPTYPE_DOMAIN)
        PG_RETURN_OID(typid);

    base_type = typentry->domainBaseType;
    while (true)
    {
        typentry = lookup_type_cache(base_type, TYPECACHE_DOMAIN_BASE_INFO);
        if (typentry->typtype != TYPTYPE_DOMAIN)
            break;
        base_type = typentry->domainBaseType;
    }

    PG_RETURN_OID(base_type);
}

