Datum
pg_get_constraintdef(PG_FUNCTION_ARGS)
{
    Oid            constraintId = PG_GETARG_OID(0);
    char       *res;

    res = pg_get_constraintdef_worker(constraintId, false);

    if (res == NULL)
        PG_RETURN_NULL();

    PG_RETURN_TEXT_P(cstring_to_text(res));
}

Datum
pg_get_constraintdef_ext(PG_FUNCTION_ARGS)
{
    Oid            constraintId = PG_GETARG_OID(0);
    bool        pretty = PG_GETARG_BOOL(1);
    char       *res;

    res = pg_get_constraintdef_worker(constraintId, pretty);

    if (res == NULL)
        PG_RETURN_NULL();

    PG_RETURN_TEXT_P(cstring_to_text(res));
}

char *
pg_get_constraintdef_worker(Oid constraintId, bool pretty)
{
    HeapTuple    tup;
    Form_pg_constraint conForm;
    char       *condef;

    tup = SearchSysCache1(CONSTROID, ObjectIdGetDatum(constraintId));
    if (!HeapTupleIsValid(tup))
        return NULL;

    conForm = (Form_pg_constraint) GETSTRUCT(tup);

    switch (conForm->contype)
    {
        case CONSTRAINT_FOREIGN:
            condef = pg_get_constraintdef_foreign(tup, pretty);
            break;
        case CONSTRAINT_PRIMARY:
        case CONSTRAINT_UNIQUE:
            condef = pg_get_constraintdef_index(tup, pretty);
            break;
        case CONSTRAINT_CHECK:
            condef = pg_get_constraintdef_check(tup, pretty);
            break;
        case CONSTRAINT_EXCLUSION:
            condef = pg_get_constraintdef_exclusion(tup, pretty);
            break;
        case CONSTRAINT_TRIGGER:
            condef = pg_get_constraintdef_trigger(tup, pretty);
            break;
        default:
            elog(ERROR, "unrecognized constraint type: %c", conForm->contype);
            condef = NULL;        /* keep compiler quiet */
    }

    ReleaseSysCache(tup);

    return condef;
}

