#include "postgres.h"
#include "access/htup_details.h"
#include "catalog/pg_type.h"
#include "nodes/nodeFuncs.h"
#include "parser/parser.h"
#include "utils/builtins.h"
#include "utils/lsyscache.h"
#include "utils/ruleutils.h"
#include "utils/syscache.h"

/*
 * pg_get_expr - decompile an expression stored in system catalogs
 *
 * Input is a text string containing the expression in pg_node_tree format,
 * and optionally a relation OID to use for Vars in the expression.
 */
Datum
pg_get_expr(PG_FUNCTION_ARGS)
{
    text       *expr = PG_GETARG_TEXT_PP(0);
    Oid            relid = PG_GETARG_OID(1);
    bool        pretty = false;
    int            prettyFlags;
    char       *res;

    if (PG_NARGS() > 2)
        pretty = PG_GETARG_BOOL(2);

    prettyFlags = pretty ? (PRETTYFLAG_PAREN | PRETTYFLAG_INDENT) : PRETTYFLAG_PAREN;

    res = pg_get_expr_ext(expr, relid, prettyFlags);

    if (res == NULL)
        PG_RETURN_NULL();

    PG_RETURN_TEXT_P(cstring_to_text(res));
}

/*
 * pg_get_expr_ext - workhorse for pg_get_expr with extended options
 *
 * expr: text string containing the expression in pg_node_tree format
 * relid: OID of relation to use for Vars, or InvalidOid if none
 * prettyFlags: flags to control pretty-printing
 *
 * Returns a palloc'd string, or NULL if the expression is NULL.
 */
char *
pg_get_expr_ext(text *expr, Oid relid, int prettyFlags)
{
    Node       *node;
    char       *exprstr;
    char       *res;

    if (expr == NULL)
        return NULL;

    exprstr = text_to_cstring(expr);

    node = stringToNode(exprstr);
    if (node == NULL)
        return NULL;

    res = deparse_expression(node, NIL, false, false, relid, prettyFlags);

    pfree(exprstr);

    return res;
}

