Datum
pg_get_function_arguments(PG_FUNCTION_ARGS)
{
    Oid            funcid = PG_GETARG_OID(0);
    HeapTuple    proctup;
    Form_pg_proc proc;
    char       *result;

    proctup = SearchSysCache1(PROCOID, ObjectIdGetDatum(funcid));
    if (!HeapTupleIsValid(proctup))
        PG_RETURN_NULL();

    proc = (Form_pg_proc) GETSTRUCT(proctup);

    result = pg_get_function_arguments_worker(funcid, proc->proargtypes,
                                             proc->proallargtypes,
                                             proc->proargmodes,
                                             proc->proargnames,
                                             proc->proargdefaults,
                                             proc->pronargs,
                                             proc->prokind);

    ReleaseSysCache(proctup);

    if (result == NULL)
        PG_RETURN_NULL();

    PG_RETURN_TEXT_P(cstring_to_text(result));
}

char *
pg_get_function_arguments_worker(Oid funcid, oidvector *proargtypes,
                                ArrayType *proallargtypes,
                                ArrayType *proargmodes,
                                ArrayType *proargnames,
                                char *proargdefaults,
                                int pronargs, char prokind)
{
    StringInfoData buf;
    int            numargs;
    Oid           *argtypes = NULL;
    char       *argmodes = NULL;
    char      **argnames = NULL;
    int            i;
    List       *argdefaults = NIL;
    int            ndefaults = 0;

    initStringInfo(&buf);

    /* Extract argument types and modes */
    numargs = get_func_arg_info(funcid, &argtypes, &argmodes, &argnames);

    /* Parse default expressions if any */
    if (proargdefaults)
    {
        Node       *expr;
        List       *defaults;
        int            j = 0;

        defaults = (List *) stringToNode(proargdefaults);
        ndefaults = list_length(defaults);

        foreach(lc, defaults)
        {
            expr = (Node *) lfirst(lc);
            argdefaults = lappend(argdefaults, expr);
        }
    }

    /* Reconstruct argument list */
    for (i = 0; i < numargs; i++)
    {
        char       *argname = NULL;
        char       *modestr = NULL;
        Oid            argtype;
        bool        hasdefault = false;
        Node       *defexpr = NULL;

        if (argnames && argnames[i])
            argname = argnames[i];

        if (argmodes)
        {
            switch (argmodes[i])
            {
                case PROARGMODE_IN:
                    modestr = "";
                    break;
                case PROARGMODE_OUT:
                    modestr = "OUT ";
                    break;
                case PROARGMODE_INOUT:
                    modestr = "INOUT ";
                    break;
                case PROARGMODE_VARIADIC:
                    modestr = "VARIADIC ";
                    break;
                case PROARGMODE_TABLE:
                    modestr = "TABLE ";
                    break;
                default:
                    modestr = "";
                    break;
            }
        }

        argtype = argtypes[i];

        /* Check if this argument has a default */
        if (i >= (numargs - ndefaults))
        {
            hasdefault = true;
            defexpr = (Node *) list_nth(argdefaults, j);
            j++;
        }

        if (i > 0)
            appendStringInfoString(&buf, ", ");

        if (modestr)
            appendStringInfoString(&buf, modestr);

        if (argname)
            appendStringInfo(&buf, "%s ", quote_identifier(argname));

        appendStringInfoString(&buf, format_type_be(argtype));

        if (hasdefault)
        {
            char       *defstr;

            defstr = deparse_expression(defexpr, NIL, false, false);
            appendStringInfo(&buf, " DEFAULT %s", defstr);
        }
    }

    return buf.data;
}

