/*
 * pg_get_function_identity_arguments
 *    Reconstructs the argument list necessary to identify a function or procedure,
 *    in the form it would need to appear in within commands such as ALTER FUNCTION.
 *    This form omits default values.
 */
Datum
pg_get_function_identity_arguments(PG_FUNCTION_ARGS)
{
    Oid            funcid = PG_GETARG_OID(0);
    HeapTuple    proctup;
    Form_pg_proc proc;
    char       *result;

    proctup = SearchSysCache1(PROCOID, ObjectIdGetDatum(funcid));
    if (!HeapTupleIsValid(proctup))
        PG_RETURN_NULL();

    proc = (Form_pg_proc) GETSTRUCT(proctup);

    result = pg_get_function_identity_arguments_worker(funcid, proc);

    ReleaseSysCache(proctup);

    if (result == NULL)
        PG_RETURN_NULL();

    PG_RETURN_TEXT_P(cstring_to_text(result));
}

/*
 * Worker function for pg_get_function_identity_arguments
 */
char *
pg_get_function_identity_arguments_worker(Oid funcid, Form_pg_proc proc)
{
    StringInfoData buf;
    Oid            *argtypes;
    char       **argnames;
    char       *argmodes;
    int            numargs;
    int            i;

    initStringInfo(&buf);

    /* Get the function's argument list */
    numargs = get_func_arg_info(proc, &argtypes, &argnames, &argmodes);

    for (i = 0; i < numargs; i++)
    {
        char       *typename;
        char       *argname;
        char        argmode;

        if (argmodes)
            argmode = argmodes[i];
        else
            argmode = PROARGMODE_IN;

        /* Skip OUT parameters */
        if (argmode == PROARGMODE_OUT || argmode == PROARGMODE_TABLE)
            continue;

        if (i > 0)
            appendStringInfoChar(&buf, ',');

        /* Add IN/INOUT/VARIADIC marker if needed */
        if (argmode == PROARGMODE_INOUT)
            appendStringInfoString(&buf, "INOUT ");
        else if (argmode == PROARGMODE_VARIADIC)
            appendStringInfoString(&buf, "VARIADIC ");

        /* Argument name if available */
        if (argnames && argnames[i])
        {
            appendStringInfoString(&buf, quote_identifier(argnames[i]));
            appendStringInfoChar(&buf, ' ');
        }

        /* Argument type */
        typename = format_type_be(argtypes[i]);
        appendStringInfoString(&buf, typename);
    }

    return buf.data;
}

