/*
 * pg_get_indexdef - reconstruct the creating command for an index
 *
 * Returns a string that could be used to recreate the index.
 */
Datum
pg_get_indexdef(PG_FUNCTION_ARGS)
{
    Oid         indexrelid = PG_GETARG_OID(0);
    int         colno = PG_GETARG_INT32(1);
    bool        pretty = PG_GETARG_BOOL(2);
    StringInfoData buf;

    initStringInfo(&buf);

    if (colno == 0)
        get_indexdef(indexrelid, &buf, pretty);
    else
        get_index_column_def(indexrelid, colno, &buf, pretty);

    PG_RETURN_TEXT_P(cstring_to_text(buf.data));
}

/*
 * pg_get_indexdef_ext - extended version with more options
 */
Datum
pg_get_indexdef_ext(PG_FUNCTION_ARGS)
{
    Oid         indexrelid = PG_GETARG_OID(0);
    int         colno = PG_GETARG_INT32(1);
    bool        pretty = PG_GETARG_BOOL(2);
    bool        showTblSpc = PG_GETARG_BOOL(3);
    StringInfoData buf;

    initStringInfo(&buf);

    if (colno == 0)
        get_indexdef_ext(indexrelid, &buf, pretty, showTblSpc);
    else
        get_index_column_def(indexrelid, colno, &buf, pretty);

    PG_RETURN_TEXT_P(cstring_to_text(buf.data));
}

/*
 * Common code for both pg_get_indexdef and pg_get_indexdef_ext
 */
static void
get_indexdef(Oid indexrelid, StringInfo buf, bool pretty)
{
    get_indexdef_ext(indexrelid, buf, pretty, false);
}

static void
get_indexdef_ext(Oid indexrelid, StringInfo buf, bool pretty, bool showTblSpc)
{
    HeapTuple   ht_idx;
    Form_pg_index idxrec;
    HeapTuple   ht_idxrel;
    Form_pg_class idxrelrec;
    Oid         indrelid;
    List       *indexprs;
    ListCell   *indexpr_item;
    Oid         indcollation[INDEX_MAX_KEYS];
    Oid         indclass[INDEX_MAX_KEYS];
    int         indnkeyatts;
    int         i;

    /* Get pg_index info */
    ht_idx = SearchSysCache1(INDEXRELID, ObjectIdGetDatum(indexrelid));
    if (!HeapTupleIsValid(ht_idx))
        elog(ERROR, "cache lookup failed for index %u", indexrelid);
    idxrec = (Form_pg_index) GETSTRUCT(ht_idx);

    indrelid = idxrec->indrelid;
    indnkeyatts = idxrec->indnkeyatts;

    /* Get pg_class info for the index */
    ht_idxrel = SearchSysCache1(RELOID, ObjectIdGetDatum(indexrelid));
    if (!HeapTupleIsValid(ht_idxrel))
        elog(ERROR, "cache lookup failed for relation %u", indexrelid);
    idxrelrec = (Form_pg_class) GETSTRUCT(ht_idxrel);

    /* Get index expressions, if any */
    indexprs = NIL;
    if (!heap_attisnull(ht_idx, Anum_pg_index_indexprs, NULL))
    {
        Datum       exprsDatum;
        bool        isnull;
        char       *exprsString;

        exprsDatum = SysCacheGetAttr(INDEXRELID, ht_idx,
                                    Anum_pg_index_indexprs, &isnull);
        Assert(!isnull);
        exprsString = TextDatumGetCString(exprsDatum);
        indexprs = (List *) stringToNode(exprsString);
        pfree(exprsString);
    }

    /* Get collation and operator classes */
    for (i = 0; i < INDEX_MAX_KEYS; i++)
    {
        indcollation[i] = idxrec->indcollation[i];
        indclass[i] = idxrec->indclass[i];
    }

    /* Start building the command */
    appendStringInfo(buf, "CREATE %sINDEX %s ON %s ",
                     idxrec->indisunique ? "UNIQUE " : "",
                     quote_identifier(NameStr(idxrelrec->relname)),
                     generate_relation_name(indrelid, NIL));

    /* Add the column definitions */
    appendStringInfoChar(buf, '(');

    indexpr_item = list_head(indexprs);
    for (i = 0; i < indnkeyatts; i++)
    {
        AttrNumber  attnum = idxrec->indkey.values[i];

        if (i > 0)
            appendStringInfoString(buf, ", ");

        if (attnum != 0)
        {
            /* Simple index column */
            char       *attname;

            attname = get_attname(indrelid, attnum, false);
            appendStringInfoString(buf, quote_identifier(attname));
        }
        else
        {
            /* Expressional index */
            Node       *indexkey;

            if (indexpr_item == NULL)
                elog(ERROR, "too few entries in indexprs list");
            indexkey = (Node *) lfirst(indexpr_item);
            indexpr_item = lnext(indexpr_item);

            appendStringInfoString(buf, "(");
            get_rule_expr(indexkey, buf, NIL, pretty, false);
            appendStringInfoString(buf, ")");
        }

        /* Add collation if not default */
        if (OidIsValid(indcollation[i]) && indcollation[i] != DEFAULT_COLLATION_OID)
            appendStringInfo(buf, " COLLATE %s",
                             generate_collation_name(indcollation[i]));

        /* Add operator class if not default */
        if (indclass[i] != InvalidOid)
        {
            char       *opclassname;

            opclassname = get_opclass_name(indclass[i]);
            appendStringInfo(buf, " %s", opclassname);
        }
    }

    appendStringInfoChar(buf, ')');

    /* Add tablespace if requested */
    if (showTblSpc && OidIsValid(idxrelrec->reltablespace))
        appendStringInfo(buf, " TABLESPACE %s",
                         quote_identifier(get_tablespace_name(idxrelrec->reltablespace)));

    /* Clean up */
    ReleaseSysCache(ht_idxrel);
    ReleaseSysCache(ht_idx);
}

/*
 * Generate the definition of a single index column
 */
static void
get_index_column_def(Oid indexrelid, int colno, StringInfo buf, bool pretty)
{
    HeapTuple   ht_idx;
    Form_pg_index idxrec;
    AttrNumber  attnum;
    Oid         indcollation;
    Oid         indclass;
    List       *indexprs;
    ListCell   *indexpr_item;
    int         i;

    /* Get pg_index info */
    ht_idx = SearchSysCache1(INDEXRELID, ObjectIdGetDatum(indexrelid));
    if (!HeapTupleIsValid(ht_idx))
        elog(ERROR, "cache lookup failed for index %u", indexrelid);
    idxrec = (Form_pg_index) GETSTRUCT(ht_idx);

    /* Check colno is valid */
    if (colno <= 0 || colno > idxrec->indnkeyatts)
        elog(ERROR, "invalid column number %d for index %u", colno, indexrelid);

    /* Get the column's info */
    attnum = idxrec->indkey.values[colno - 1];
    indcollation = idxrec->indcollation[colno - 1];
    indclass = idxrec->indclass[colno - 1];

    /* Get index expressions, if any */
    indexprs = NIL;
    if (!heap_attisnull(ht_idx, Anum_pg_index_indexprs, NULL))
    {
        Datum       exprsDatum;
        bool        isnull;
        char       *exprsString;

        exprsDatum = SysCacheGetAttr(INDEXRELID, ht_idx,
                                    Anum_pg_index_indexprs, &isnull);
        Assert(!isnull);
        exprsString = TextDatumGetCString(exprsDatum);
        indexprs = (List *) stringToNode(exprsString);
        pfree(exprsString);
    }

    /* Find the right expression for this column */
    indexpr_item = list_head(indexprs);
    for (i = 1; i < colno; i++)
    {
        if (idxrec->indkey.values[i - 1] == 0)
        {
            if (indexpr_item == NULL)
                elog(ERROR, "too few entries in indexprs list");
            indexpr_item = lnext(indexpr_item);
        }
    }

    /* Print the column definition */
    if (attnum != 0)
    {
        /* Simple index column */
        char       *attname;

        attname = get_attname(idxrec->indrelid, attnum, false);
        appendStringInfoString(buf, quote_identifier(attname));
    }
    else
    {
        /* Expressional index */
        Node       *indexkey;

        if (indexpr_item == NULL)
            elog(ERROR, "too few entries in indexprs list");
        indexkey = (Node *) lfirst(indexpr_item);

        appendStringInfoString(buf, "(");
        get_rule_expr(indexkey, buf, NIL, pretty, false);
        appendStringInfoString(buf, ")");
    }

    /* Add collation if not default */
    if (OidIsValid(indcollation) && indcollation != DEFAULT_COLLATION_OID)
        appendStringInfo(buf, " COLLATE %s",
                         generate_collation_name(indcollation));

    /* Add operator class if not default */
    if (indclass != InvalidOid)
    {
        char       *opclassname;

        opclassname = get_opclass_name(indclass);
        appendStringInfo(buf, " %s", opclassname);
    }

    /* Clean up */
    ReleaseSysCache(ht_idx);
}

