static char *
pg_get_ruledef_worker(Oid ruleoid, bool pretty)
{
    HeapTuple    ruletup;
    Form_pg_rewrite rule;
    char       *ruledef;

    ruletup = SearchSysCache1(RULEROLEID, ObjectIdGetDatum(ruleoid));
    if (!HeapTupleIsValid(ruletup))
        return NULL;

    rule = (Form_pg_rewrite) GETSTRUCT(ruletup);

    ruledef = pg_get_ruledef_extended(ruleoid, pretty, false, false);

    ReleaseSysCache(ruletup);

    return ruledef;
}

