PG_FUNCTION_INFO_V1(pg_get_serial_sequence);

Datum
pg_get_serial_sequence(PG_FUNCTION_ARGS)
{
    text       *tablename = PG_GETARG_TEXT_PP(0);
    text       *columnname = PG_GETARG_TEXT_PP(1);
    RangeVar   *relrv;
    Oid            relid;
    AttrNumber    attnum;
    Oid            seqid = InvalidOid;
    char       *nspname;
    char       *seqname;
    Datum        result;

    /* Parse table name and look up relation */
    relrv = makeRangeVarFromNameList(textToQualifiedNameList(tablename));
    relid = RangeVarGetRelid(relrv, NoLock, true);

    /* Get column number */
    attnum = get_attnum(relid, text_to_cstring(columnname));
    if (attnum == InvalidAttrNumber)
        PG_RETURN_NULL();

    /* Check for identity column first */
    seqid = get_identity_sequence(relid, attnum, false);

    /* If not identity, check for owned sequence (serial column case) */
    if (!OidIsValid(seqid))
        seqid = get_owned_sequence(relid, attnum);

    if (!OidIsValid(seqid))
        PG_RETURN_NULL();

    /* Get sequence name with schema */
    seqname = get_rel_name(seqid);
    nspname = get_namespace_name(get_rel_namespace(seqid));

    /* Return as text in schema-qualified form */
    result = DirectFunctionCall1(textin,
                                CStringGetDatum(quote_qualified_identifier(nspname, seqname)));

    PG_RETURN_DATUM(result);
}

