/* Internal function to get view definition */
static text *
pg_get_viewdef_internal(Oid viewoid, int prettyFlags, int wrapColumn)
{
	HeapTuple	viewtuple;
	Form_pg_class viewclass;
	Oid			rewrite_oid;
	Relation	viewrel;
	Query	   *viewquery;
	ParseState *pstate;
	RangeTblEntry *rte;
	StringInfoData buf;
	text	   *res;

	/* Get view relation */
	viewtuple = SearchSysCache1(RELOID, ObjectIdGetDatum(viewoid));
	if (!HeapTupleIsValid(viewtuple))
		elog(ERROR, "cache lookup failed for relation %u", viewoid);
	viewclass = (Form_pg_class) GETSTRUCT(viewtuple);

	/* Check it's a view or materialized view */
	if (viewclass->relkind != RELKIND_VIEW &&
		viewclass->relkind != RELKIND_MATVIEW)
	{
		ReleaseSysCache(viewtuple);
		ereport(ERROR,
				(errcode(ERRCODE_WRONG_OBJECT_TYPE),
				 errmsg("\"%s\" is not a view or materialized view",
						NameStr(viewclass->relname))));
	}

	/* Get the view's query */
	rewrite_oid = GetViewRuleOid(viewoid);
	if (!OidIsValid(rewrite_oid))
	{
		ReleaseSysCache(viewtuple);
		ereport(ERROR,
				(errcode(ERRCODE_UNDEFINED_OBJECT),
				 errmsg("could not find rewrite rule for view %u", viewoid)));
	}

	viewrel = relation_open(viewoid, AccessShareLock);
	viewquery = get_view_query(viewrel);
	relation_close(viewrel, AccessShareLock);
	ReleaseSysCache(viewtuple);

	/* Set up parse state */
	pstate = make_parsestate(NULL);
	rte = addRangeTableEntryForRelation(pstate, viewrel,
										  NULL, false, false);
	addRTEtoQuery(pstate, rte, false, false, true);

	/* Generate SQL */
	initStringInfo(&buf);
	get_query_def(viewquery, &buf, NIL, NULL, prettyFlags, wrapColumn);

	res = cstring_to_text(buf.data);
	pfree(buf.data);

	free_parsestate(pstate);
	free_parsed_query(viewquery);

	return res;
}

/* Wrapper functions */
Datum
pg_get_viewdef_name(PG_FUNCTION_ARGS)
{
	Name		viewname = PG_GETARG_NAME(0);
