Datum
pg_indexam_has_property(PG_FUNCTION_ARGS)
{
    Oid         amoid = PG_GETARG_OID(0);
    text       *propname = PG_GETARG_TEXT_PP(1);
    char       *propstr;
    bool        result = false;
    IndexAmRoutine *amroutine;

    /* Get the access method's property function */
    amroutine = GetIndexAmRoutineByAmId(amoid, true);
    if (amroutine == NULL)
        PG_RETURN_NULL();

    /* Convert property name to C string */
    propstr = text_to_cstring(propname);

    /* Check property name and get result */
    if (strcmp(propstr, "can_order") == 0)
        result = amroutine->amcanorder;
    else if (strcmp(propstr, "can_unique") == 0)
        result = amroutine->amcanunique;
    else if (strcmp(propstr, "can_multi_col") == 0)
        result = amroutine->amcanmulticol;
    else if (strcmp(propstr, "can_exclude") == 0)
        result = amroutine->amcanexclude;
    else if (strcmp(propstr, "can_include") == 0)
        result = (amroutine->amcaninclude != NIL);
    else if (strcmp(propstr, "can_return") == 0)
        result = (amroutine->amgettuple != NULL);
    else
    {
        /* Unknown property name */
        PG_RETURN_NULL();
    }

    PG_RETURN_BOOL(result);
}

