PG_FUNCTION_INFO_V1(get_guc_flags);

Datum
get_guc_flags(PG_FUNCTION_ARGS)
{
    text *guc_name_text = PG_GETARG_TEXT_PP(0);
    char *guc_name = text_to_cstring(guc_name_text);
    struct config_generic *record;
    int         flags;
    Datum       *elements;
    bool        *nulls;
    int         nelems = 0;
    int         i = 0;
    ArrayType  *result;

    record = find_option(guc_name, false, false, ERROR);
    if (record == NULL)
        PG_RETURN_NULL();

    flags = record->flags;

    /* Allocate space for the maximum possible number of flags */
    elements = (Datum *) palloc(8 * sizeof(Datum));
    nulls = (bool *) palloc(8 * sizeof(bool));
    memset(nulls, 0, 8 * sizeof(bool));

    if (flags & GUC_LIST_INPUT)
        elements[nelems++] = CStringGetTextDatum("list_input");
    if (flags & GUC_LIST_QUOTE)
        elements[nelems++] = CStringGetTextDatum("list_quote");
    if (flags & GUC_NO_SHOW_ALL)
        elements[nelems++] = CStringGetTextDatum("no_show_all");
    if (flags & GUC_NO_RESET_ALL)
        elements[nelems++] = CStringGetTextDatum("no_reset_all");
    if (flags & GUC_REPORT)
        elements[nelems++] = CStringGetTextDatum("report");
    if (flags & GUC_NOT_IN_SAMPLE)
        elements[nelems++] = CStringGetTextDatum("not_in_sample");
    if (flags & GUC_DISALLOW_IN_FILE)
        elements[nelems++] = CStringGetTextDatum("disallow_in_file");
    if (flags & GUC_CUSTOM_PLACEHOLDER)
        elements[nelems++] = CStringGetTextDatum("custom_placeholder");

    if (nelems == 0)
        result = construct_empty_array(TEXTOID);
    else
        result = construct_array(elements, nelems, TEXTOID, -1, false, 'i');

    pfree(elements);
    pfree(nulls);

    PG_RETURN_ARRAYTYPE_P(result);
}

