 * to_regclass - converts text relation name to OID
 *
 * Returns NULL if the name is not found instead of throwing an error.
 */
Datum
to_regclass(PG_FUNCTION_ARGS)
{
    text       *rel_name_text = PG_GETARG_TEXT_PP(0);
    char       *rel_name;
    Oid            rel_oid;

    rel_name = text_to_cstring(rel_name_text);

    /* Look up the relation name in the system catalogs */
    rel_oid = get_relname_relid(rel_name, PG_CATALOG_NAMESPACE);
    if (!OidIsValid(rel_oid))
        rel_oid = get_relname_relid(rel_name, PG_TOAST_NAMESPACE);
    if (!OidIsValid(rel_oid))
        rel_oid = get_relname_relid(rel_name, PG_PUBLIC_NAMESPACE);
    if (!OidIsValid(rel_oid))
        PG_RETURN_NULL();

    PG_RETURN_OID(rel_oid);
}

