{
    text       *typ_name_t = PG_GETARG_TEXT_PP(0);
    char       *typ_name;
    Oid            typoid;
    List       *names;
    TypeName   *typeName;

    /* Convert input text to C string */
    typ_name = text_to_cstring(typ_name_t);

    /* Parse the type name */
    names = stringToQualifiedNameList(typ_name);
    typeName = makeTypeNameFromNameList(names);

    /* Look up the type OID */
    typoid = LookupTypeNameOid(NULL, typeName, true);

    /* Return NULL if type not found */
    if (!OidIsValid(typoid))
        PG_RETURN_NULL();

    PG_RETURN_OID(typoid);
}

#include "postgres.h"
#include "catalog/pg_type.h"
#include "utils/builtins.h"
#include "utils/lsyscache.h"
#include "parser/scansup.h"

Datum
to_regtypemod(PG_FUNCTION_ARGS)
{
    text       *typname = PG_GETARG_TEXT_PP(0);
    char       *str;
    int32       typmod = -1;
    Oid         typid;
    ParseState *pstate;
    TypeName   *typeName;

    /* Convert text to C string */
    str = text_to_cstring(typname);

    /* Set up a dummy ParseState */
    pstate = make_parsestate(NULL);

    /* Parse the type name */
    typeName = parseTypeString(pstate, str, NULL, NULL);

    /* If parsing failed, throw error */
    if (typeName == NULL)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_TEXT_REPRESENTATION),
                errmsg("invalid type name: \"%s\"", str));

    /* Look up the type */
    typid = LookupTypeName(pstate, typeName, NULL, false);

    /* If type exists, get its typmod */
    if (OidIsValid(typid))
    {
        if (typeName->typmods != NIL)
        {
            typmod = typenameTypeMod(pstate, typeName, typid);
        }
    }
    else
    {
        /* For valid but unknown types, return NULL */
        PG_RETURN_NULL();
    }

    /* Clean up */
    free_parsestate(pstate);
    pfree(str);

    PG_RETURN_INT32(typmod);
}

