#include "utils/syscache.h"
#include "utils/ruleutils.h"

Datum
pg_describe_object(PG_FUNCTION_ARGS)
{
    Oid            catalogid = PG_GETARG_OID(0);
    Oid            objid = PG_GETARG_OID(1);
    int32        subid = PG_GETARG_INT32(2);
    char       *description;

    if (!SearchSysCacheExists1(catalogid, ObjectIdGetDatum(objid)))
        PG_RETURN_NULL();

    switch (catalogid)
    {
        case RelationRelationId:
            {
                HeapTuple    tuple;
                Form_pg_class classForm;
                char       *nspname;
                char       *relname;

                tuple = SearchSysCache1(RELOID, ObjectIdGetDatum(objid));
                if (!HeapTupleIsValid(tuple))
                    PG_RETURN_NULL();
                classForm = (Form_pg_class) GETSTRUCT(tuple);

                nspname = get_namespace_name(classForm->relnamespace);
                relname = NameStr(classForm->relname);

                if (subid == 0)
                    description = psprintf(_("table %s.%s"), nspname, relname);
                else
                {
                    char       *attname;

                    attname = get_attname(objid, subid, true);
                    if (attname == NULL)
                        description = psprintf(_("table %s.%s column [%d]"),
                                             nspname, relname, subid);
                    else
                        description = psprintf(_("table %s.%s column %s"),
                                             nspname, relname, attname);
                }

                ReleaseSysCache(tuple);
                break;
            }

        case ProcedureRelationId:
            {
                HeapTuple    tuple;
                Form_pg_proc procForm;
                char       *nspname;
                char       *proname;

                tuple = SearchSysCache1(PROCOID, ObjectIdGetDatum(objid));
                if (!HeapTupleIsValid(tuple))
                    PG_RETURN_NULL();
                procForm = (Form_pg_proc) GETSTRUCT(tuple);

                nspname = get_namespace_name(procForm->pronamespace);
                proname = NameStr(procForm->proname);

                description = psprintf(_("function %s.%s"), nspname, proname);

                ReleaseSysCache(tuple);
                break;
            }

        case TypeRelationId:
            {
                HeapTuple    tuple;
                Form_pg_type typeForm;
                char       *nspname;
                char       *typname;

                tuple = SearchSysCache1(TYPEOID, ObjectIdGetDatum(objid));
                if (!HeapTupleIsValid(tuple))
                    PG_RETURN_NULL();
                typeForm = (Form_pg_type) GETSTRUCT(tuple);

                nspname = get_namespace_name(typeForm->typnamespace);
                typname = NameStr(typeForm->typname);

                description = psprintf(_("type %s.%s"), nspname, typname);

                ReleaseSysCache(tuple);
                break;
            }

        default:
            description = psprintf(_("object %u.%u.%d"), catalogid, objid, subid);
            break;
    }

    PG_RETURN_TEXT_P(cstring_to_text(description));
}

