#include "postgres.h"
#include "access/htup_details.h"
#include "catalog/objectaddress.h"
#include "catalog/pg_class.h"
#include "catalog/pg_namespace.h"
#include "catalog/pg_proc.h"
#include "catalog/pg_type.h"
#include "utils/builtins.h"
#include "utils/syscache.h"
#include "utils/lsyscache.h"

/*
 * pg_identify_object
 *        Returns a row containing information to uniquely identify a database object.
 */
Datum
pg_identify_object(PG_FUNCTION_ARGS)
{
    Oid            catalog = PG_GETARG_OID(0);
    Oid            object = PG_GETARG_OID(1);
    int32        subobject = PG_GETARG_INT32(2);
    HeapTuple    tuple;
    Datum        result;
    Datum        values[4];
    bool        nulls[4] = {false, false, false, false};

    /* Initialize all fields to NULL initially */
    MemSet(nulls, true, sizeof(nulls));

    /* Identify the object type */
    switch (catalog)
    {
        case RelationRelationId:
            values[0] = CStringGetTextDatum("relation");
            nulls[0] = false;
            break;
        case ProcedureRelationId:
            values[0] = CStringGetTextDatum("function");
            nulls[0] = false;
            break;
        case TypeRelationId:
            values[0] = CStringGetTextDatum("type");
            nulls[0] = false;
            break;
        default:
            /* Unrecognized catalog */
            values[0] = CStringGetTextDatum("unknown");
            nulls[0] = false;
            break;
    }

    /* Get schema name if applicable */
    if (catalog == RelationRelationId || catalog == ProcedureRelationId || catalog == TypeRelationId)
    {
        Oid            namespaceId;
        char       *nspname;

        if (catalog == RelationRelationId)
        {
            tuple = SearchSysCache1(RELOID, ObjectIdGetDatum(object));
            if (!HeapTupleIsValid(tuple))
                PG_RETURN_NULL();
            namespaceId = ((Form_pg_class) GETSTRUCT(tuple))->relnamespace;
            ReleaseSysCache(tuple);
        }
        else if (catalog == ProcedureRelationId)
        {
            tuple = SearchSysCache1(PROCOID, ObjectIdGetDatum(object));
            if (!HeapTupleIsValid(tuple))
                PG_RETURN_NULL();
            namespaceId = ((Form_pg_proc) GETSTRUCT(tuple))->pronamespace;
            ReleaseSysCache(tuple);
        }
        else /* TypeRelationId */
        {
            tuple = SearchSysCache1(TYPEOID, ObjectIdGetDatum(object));
            if (!HeapTupleIsValid(tuple))
                PG_RETURN_NULL();
            namespaceId = ((Form_pg_type) GETSTRUCT(tuple))->typnamespace;
            ReleaseSysCache(tuple);
        }

        nspname = get_namespace_name(namespaceId);
        if (nspname)
        {
            values[1] = CStringGetTextDatum(nspname);
            nulls[1] = false;
        }
    }

    /* Get object name if applicable */
    if (catalog == RelationRelationId || catalog == ProcedureRelationId || catalog == TypeRelationId)
    {
        char       *objname;

        if (catalog == RelationRelationId)
            objname = get_rel_name(object);
        else if (catalog == ProcedureRelationId)
            objname = get_func_name(object);
        else /* TypeRelationId */
            objname = get_type_name(object);

        if (objname)
        {
            values[2] = CStringGetTextDatum(quote_identifier(objname));
            nulls[2] = false;
        }
    }

    /* Construct identity string */
    if (!nulls[1] && !nulls[2])
    {
        StringInfoData identity;

        initStringInfo(&identity);
        appendStringInfo(&identity, "%s.%s", 
                         DatumGetCString(values[1]), 
                         DatumGetCString(values[2]));

        if (subobject != 0)
            appendStringInfo(&identity, "(%d)", subobject);

        values[3] = CStringGetTextDatum(identity.data);
        nulls[3] = false;
        pfree(identity.data);
    }

    /* Build and return the result tuple */
    tuple = heap_form_tuple(fcinfo->resultinfo->expectedDesc, values, nulls);
    result = HeapTupleGetDatum(tuple);

    PG_RETURN_DATUM(result);
}

