/*
 * pg_identify_object_as_address - identify object by type, name and args
 *
 * Returns a row containing type, object_names and object_args that uniquely
 * identify the database object specified by catalog OID, object OID and
 * sub-object ID.
 */
Datum
pg_identify_object_as_address(PG_FUNCTION_ARGS)
{
    Oid            classid = PG_GETARG_OID(0);
    Oid            objid = PG_GETARG_OID(1);
    int32        subid = PG_GETARG_INT32(2);
    Datum        result;
    TupleDesc    tupdesc;
    Datum        values[3];
    bool        nulls[3] = {false, false, false};
    ObjectAddress address;
    ObjectAddresses *addrs;
    char       **objnames;
    char       **objargs;
    int            nnames;
    int            nargs;

    /* Build a tuple descriptor for our result type */
    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    address.classId = classid;
    address.objectId = objid;
    address.objectSubId = subid;

    addrs = new_object_addresses();
    add_exact_object_address(&address, addrs);

    get_object_address_components(&address, addrs,
                                &objnames, &nnames,
                                &objargs, &nargs);

    values[0] = ObjectTypeGetDatum(address.classId);
    values[1] = PointerGetDatum(strarray_to_textarray(objnames, nnames));
    values[2] = PointerGetDatum(strarray_to_textarray(objargs, nargs));

    free_object_addresses(addrs);

    result = HeapTupleGetDatum(heap_form_tuple(tupdesc, values, nulls));
    PG_RETURN_DATUM(result);
}

