Datum
pg_get_object_address(PG_FUNCTION_ARGS)
{
    Oid            classid = PG_GETARG_OID(0);
    ArrayType     *objname = PG_GETARG_ARRAYTYPE_P(1);
    ArrayType     *objargs = PG_GETARG_ARRAYTYPE_P(2);
    Datum        *names;
    Datum        *args;
    int            nnames;
    int            nargs;
    ObjectAddress address;
    HeapTuple    tuple;
    Datum        result;
    TupleDesc    tupdesc;
    Datum        values[3];
    bool        nulls[3] = {false, false, false};

    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    deconstruct_array(objname, TEXTOID, -1, false, 'i',
                     &names, NULL, &nnames);
    deconstruct_array(objargs, TEXTOID, -1, false, 'i',
                     &args, NULL, &nargs);

    address = get_object_address(classid, names, nnames, args, nargs,
                                AccessShareLock, false);

    if (!OidIsValid(address.classId))
    {
        nulls[0] = true;
        nulls[1] = true;
        nulls[2] = true;
    }
    else
    {
        values[0] = ObjectIdGetDatum(address.classId);
        values[1] = ObjectIdGetDatum(address.objectId);
        values[2] = Int32GetDatum(address.objectSubId);
    }

    result = HeapTupleGetDatum(heap_form_tuple(tupdesc, values, nulls));
    PG_RETURN_DATUM(result);
}

