/*
 * obj_description - get the comment for a database object
 *
 * Parameters:
 *    object_oid - the OID of the object
 *    catalog_name - the name of the system catalog the object is in
 *
 * Returns the comment (text), or NULL if no comment found.
 */
Datum
obj_description(PG_FUNCTION_ARGS)
{
    Oid         object_oid = PG_GETARG_OID(0);
    text       *catalog_name = PG_GETARG_TEXT_PP(1);
    char       *catalog_name_str;
    Oid         catalog_oid;
    HeapTuple   tuple;
    Datum       result;

    /* Convert catalog name to OID */
    catalog_name_str = text_to_cstring(catalog_name);
    catalog_oid = get_syscache_oid_from_name(catalog_name_str);
    if (!OidIsValid(catalog_oid))
        PG_RETURN_NULL();

    /* Look up the comment in pg_description */
    tuple = SearchSysCache2(DESCRCOID,
                           ObjectIdGetDatum(catalog_oid),
                           ObjectIdGetDatum(object_oid));
    if (!HeapTupleIsValid(tuple))
        PG_RETURN_NULL();

    result = SysCacheGetAttr(DESCRCOID, tuple, Anum_pg_description_description,
                             &isnull);
    if (isnull)
        result = (Datum) 0;
    else
        result = PointerGetDatum(text_copy(DatumGetTextPP(result)));

    ReleaseSysCache(tuple);

    if (DatumGetPointer(result) == NULL)
        PG_RETURN_NULL();
    else
        PG_RETURN_TEXT_P(result);
}

