#include "postgres.h"
#include "utils/builtins.h"
#include "utils/syscache.h"
#include "catalog/pg_shdescription.h"
#include "catalog/pg_database.h"
#include "catalog/pg_authid.h"
#include "catalog/pg_tablespace.h"

Datum
shobj_description(PG_FUNCTION_ARGS)
{
    Oid            objoid = PG_GETARG_OID(0);
    text       *catalogname = PG_GETARG_TEXT_PP(1);
    char       *catalog = text_to_cstring(catalogname);
    Relation    shdescription;
    ScanKeyData skey[2];
    SysScanDesc sd;
    HeapTuple   tuple;
    Datum        comment;
    bool        isnull;
    Oid            classoid;

    /* Look up the appropriate catalog OID based on catalog name */
    if (strcmp(catalog, "pg_database") == 0)
        classoid = DatabaseRelationId;
    else if (strcmp(catalog, "pg_authid") == 0)
        classoid = AuthIdRelationId;
    else if (strcmp(catalog, "pg_tablespace") == 0)
        classoid = TableSpaceRelationId;
    else
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid catalog name: %s", catalog)));

    /* Search shdescription for the object */
    shdescription = table_open(SharedDescriptionRelationId, AccessShareLock);

    ScanKeyInit(&skey[0],
                Anum_pg_shdescription_objoid,
                BTEqualStrategyNumber, F_OIDEQ,
                ObjectIdGetDatum(objoid));
    ScanKeyInit(&skey[1],
                Anum_pg_shdescription_classoid,
                BTEqualStrategyNumber, F_OIDEQ,
                ObjectIdGetDatum(classoid));

    sd = systable_beginscan(shdescription, SharedDescriptionObjIndexId, true,
                            NULL, 2, skey);

    tuple = systable_getnext(sd);
    if (HeapTupleIsValid(tuple))
        comment = heap_getattr(tuple, Anum_pg_shdescription_description,
                               RelationGetDescr(shdescription), &isnull);
    else
        isnull = true;

    systable_endscan(sd);
    table_close(shdescription, AccessShareLock);

    if (isnull)
        PG_RETURN_NULL();
    else
        PG_RETURN_TEXT_P(comment);
}

