PG_FUNCTION_INFO_V1(txid_current_snapshot);

Datum
txid_current_snapshot(PG_FUNCTION_ARGS)
{
    /* Similar to pg_current_snapshot() */
    Snapshot    snapshot = GetActiveSnapshot();
    char       *snap_str;
    Datum       result;

    if (snapshot == NULL)
        PG_RETURN_NULL();

    snap_str = psprintf("%lu:%lu:",
                        snapshot->xmin,
                        snapshot->xmax);

    /* Append xip array */
    if (snapshot->xcnt > 0)
    {
        int         i;
        char       *endp = snap_str + strlen(snap_str);

        for (i = 0; i < snapshot->xcnt; i++)
        {
            if (i > 0)
                *endp++ = ',';
            endp += sprintf(endp, "%lu", snapshot->xip[i]);
        }
    }

    result = DirectFunctionCall1(textin, CStringGetDatum(snap_str));
    pfree(snap_str);

    PG_RETURN_DATUM(result);
}

