Datum
txid_snapshot_xip(PG_FUNCTION_ARGS)
{
    FuncCallContext *funcctx;
    TxidSnapshot *snap;
    int32       count = 0;
    int32       i;

    if (SRF_IS_FIRSTCALL())
    {
        MemoryContext oldcontext;
        TupleDesc    tupdesc;

        funcctx = SRF_FIRSTCALL_INIT();
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

        snap = (TxidSnapshot *) PG_GETARG_VARLENA_P(0);

        /* Build a tuple descriptor for our result type */
        if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_SCALAR)
            ereport(ERROR,
                    (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                     errmsg("function returning record called in context "
                            "that cannot accept type record")));

        funcctx->tuple_desc = BlessTupleDesc(tupdesc);
        funcctx->max_calls = snap->nxip;
        funcctx->user_fctx = snap;

        MemoryContextSwitchTo(oldcontext);
    }

    funcctx = SRF_PERCALL_SETUP();
    snap = (TxidSnapshot *) funcctx->user_fctx;

    if (funcctx->call_cntr < funcctx->max_calls)
    {
        Datum        values[1];
        bool        nulls[1];
        HeapTuple    tuple;
        Datum        result;

        values[0] = Int64GetDatum(snap->xip[funcctx->call_cntr]);
        nulls[0] = false;

        tuple = heap_form_tuple(funcctx->tuple_desc, values, nulls);
        result = HeapTupleGetDatum(tuple);

        SRF_RETURN_NEXT(funcctx, result);
    }

    SRF_RETURN_DONE(funcctx);
}

