Datum
show_config_by_name(PG_FUNCTION_ARGS)
{
    text *setting_name = PG_GETARG_TEXT_PP(0);
    bool missing_ok = false;
    char *result;

    if (PG_NARGS() > 1)
        missing_ok = PG_GETARG_BOOL(1);

    result = GetConfigOptionByName(text_to_cstring(setting_name), NULL, missing_ok);

    if (result == NULL)
        PG_RETURN_NULL();

    PG_RETURN_TEXT_P(cstring_to_text(result));
}

Datum
set_config_by_name(PG_FUNCTION_ARGS)
{
    text *setting_name = PG_GETARG_TEXT_PP(0);
    text *new_value = PG_GETARG_TEXT_PP(1);
    bool is_local = PG_GETARG_BOOL(2);
    char *name;
    char *value;
    char *result;

    name = text_to_cstring(setting_name);
    value = text_to_cstring(new_value);

    result = set_config_option(name, value, PGC_USERSET, PGC_S_SESSION,
                              is_local ? GUC_ACTION_LOCAL : GUC_ACTION_SET,
                              true, 0, false);

    if (result == NULL)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                errmsg("invalid parameter value for \"%s\"", name));

    PG_RETURN_TEXT_P(cstring_to_text(result));
}

