PG_MODULE_MAGIC;

void
RequestMemCxtLogging(int pid)
{
    volatile PROC_HDR *procGlobal = ProcGlobal;
    volatile PGPROC *proc;
    int            i;

    /* Check if the requested PID is valid */
    if (pid <= 0)
        return;

    /* Loop through all backends to find the matching PID */
    for (i = 0; i < procGlobal->allProcCount; i++)
    {
        proc = &procGlobal->allProcs[i];

        if (proc->pid == pid)
        {
            /* Found the target backend, set the flag to request memory context logging */
            SetLatch(&proc->procLatch);
            proc->memCxtLoggingRequested = true;
            break;
        }
    }
}

PG_FUNCTION_INFO_V1(request_memcxt_logging);

Datum
request_memcxt_logging(PG_FUNCTION_ARGS)
{
    int32        pid = PG_GETARG_INT32(0);

    RequestMemCxtLogging(pid);

    PG_RETURN_VOID();
}

