PG_FUNCTION_INFO_V1(pg_terminate_backend);

Datum
pg_terminate_backend(PG_FUNCTION_ARGS)
{
    int32 pid = PG_GETARG_INT32(0);
    int32 timeout = 0;
    bool result = false;

    if (PG_NARGS() > 1)
        timeout = PG_GETARG_INT32(1);

    if (timeout < 0)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("timeout must not be negative")));

    /* Permission checking */
    if (!superuser())
    {
        PGPROC *proc = BackendPidGetProc(pid);

        if (!proc)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("PID %d is not a PostgreSQL server process", pid)));

        if (superuser_arg(proc->roleId))
            ereport(ERROR,
                    (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                     errmsg("must be a superuser to terminate superuser backends")));

        if (!has_privs_of_role(GetUserId(), proc->roleId) &&
            !has_privs_of_role(GetUserId(), ROLE_PG_SIGNAL_BACKEND))
            ereport(ERROR,
                    (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                     errmsg("must be a member of the role whose process is being terminated or have privileges of pg_signal_backend")));
    }

    if (timeout > 0)
    {
        /* With timeout, we wait for the process to terminate */
        result = TerminateBackend(pid, timeout);
        if (!result)
            ereport(WARNING,
                    (errmsg("backend with PID %d did not terminate within %d milliseconds",
                            pid, timeout)));
    }
    else
    {
        /* Without timeout, we just send the signal */
        result = (kill(pid, SIGTERM) == 0);
    }

    PG_RETURN_BOOL(result);
}

