    bool        waitforarchive = true;
    XLogRecPtr    stoppoint;
    char       *labelfile;
    char       *tblspcmapfile;
    char       *histfile = NULL;
    TupleDesc    tupdesc;
    Datum        values[3];
    bool        nulls[3] = {false, false, false};

    if (PG_ARGISNULL(0))
        waitforarchive = PG_GETARG_BOOL(0);

    if (!superuser())
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                (errmsg("must be superuser to run a backup")));

    if (!BackupInProgress())
        ereport(ERROR,
                (errcode(ERRCODE_OBJECT_NOT_IN_PREREQUISITE_STATE),
                 errmsg("a backup is not in progress")));

    stoppoint = do_pg_backup_stop(waitforarchive, &labelfile, &tblspcmapfile, &histfile);

    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    values[0] = LSNGetDatum(stoppoint);
    values[1] = CStringGetTextDatum(labelfile);
    values[2] = CStringGetTextDatum(tblspcmapfile);

    pfree(labelfile);
    pfree(tblspcmapfile);
    if (histfile)
        pfree(histfile);

    PG_RETURN_DATUM(HeapTupleGetDatum(heap_form_tuple(tupdesc, values, nulls)));
}

