/*
 * GetRecoveryPauseState
 * Returns recovery pause state as text.
 *
 * Possible return values:
 * "not paused" - if pause is not requested
 * "pause requested" - if pause is requested but recovery is not yet paused
 * "paused" - if recovery is actually paused
 */
Datum
GetRecoveryPauseState(PG_FUNCTION_ARGS)
{
    char       *state;

    if (!RecoveryInProgress())
        PG_RETURN_TEXT_P(cstring_to_text("not paused"));

    if (GetRecoveryPauseState() == RECOVERY_NOT_PAUSED)
        PG_RETURN_TEXT_P(cstring_to_text("not paused"));
    else if (GetRecoveryPauseState() == RECOVERY_PAUSE_REQUESTED)
        PG_RETURN_TEXT_P(cstring_to_text("pause requested"));
    else if (GetRecoveryPauseState() == RECOVERY_PAUSED)
        PG_RETURN_TEXT_P(cstring_to_text("paused"));

    /* Should never reach here */
    elog(ERROR, "invalid recovery pause state");
    PG_RETURN_NULL();
}

/*
 * GetRecoveryPauseState internal function
 * Returns recovery pause state as enum.
 */
static RecoveryPauseState
GetRecoveryPauseState(void)
{
    if (recoveryPauseState == RECOVERY_PAUSE_REQUESTED &&
        !RecoveryIsPaused())
        return RECOVERY_PAUSE_REQUESTED;
    else if (RecoveryIsPaused())
        return RECOVERY_PAUSED;
    else
        return RECOVERY_NOT_PAUSED;
}

