/*
 * Log a running xacts snapshot to WAL immediately.
 * This is used for logical decoding on standby to advance the slot creation.
 */
void
LogCurrentRunningXacts(void)
{
    XLogRecPtr    ptr;
    RunningTransactions running;
    xl_running_xacts xlrec;
    XLogRecData rdata[1];

    /* Get the current running transactions */
    running = GetRunningTransactionData();

    /* Prepare the WAL record */
    xlrec.xcnt = running->xcnt;
    xlrec.subxid_overflow = running->subxid_overflow;
    xlrec.nextXid = running->nextXid;
    xlrec.oldestRunningXid = running->oldestRunningXid;
    xlrec.latestCompletedXid = running->latestCompletedXid;

    rdata[0].data = (char *) &xlrec;
    rdata[0].len = sizeof(xl_running_xacts);
    rdata[0].buffer = InvalidBuffer;
    rdata[0].next = NULL;

    /* Insert the WAL record */
    ptr = XLogInsert(RM_XACT_ID, XLOG_RUNNING_XACTS, rdata);

    /* Update the replication slot if needed */
    if (MyReplicationSlot != NULL && MyReplicationSlot->data.database != InvalidOid)
        ReplicationSlotMarkDirty();

    /* Free the running transactions data */
    FreeSnapshotBuilderData(running);
}

