PG_FUNCTION_INFO_V1(pg_copy_physical_replication_slot);

Datum
pg_copy_physical_replication_slot(PG_FUNCTION_ARGS)
{
    Name        src_slot_name = PG_GETARG_NAME(0);
    Name        dst_slot_name = PG_GETARG_NAME(1);
    bool        temporary;

    if (PG_NARGS() == 3)
        temporary = PG_GETARG_BOOL(2);
    else
        temporary = false; /* will be set to source slot's value later */

    ReplicationSlot *src_slot;
    ReplicationSlot *dst_slot;
    XLogRecPtr    restart_lsn;
    XLogRecPtr    confirm_lsn;

    /* Look up the source slot */
    (void) ReplicationSlotAcquire(NameStr(*src_slot_name), true);
    src_slot = MyReplicationSlot;

    /* Check if source slot is physical */
    if (!SlotIsPhysical(src_slot))
        ereport(ERROR,
                (errcode(ERRCODE_OBJECT_NOT_IN_PREREQUISITE_STATE),
                 errmsg("source replication slot "%s" is not a physical replication slot",
                        NameStr(*src_slot_name))));

    /* Check if source slot is invalidated */
    if (SlotIsInvalidated(src_slot))
        ereport(ERROR,
                (errcode(ERRCODE_OBJECT_NOT_IN_PREREQUISITE_STATE),
                 errmsg("cannot copy invalidated replication slot "%s"",
                        NameStr(*src_slot_name))));

    /* Use source slot's temporary status if not explicitly specified */
    if (PG_NARGS() < 3)
        temporary = SlotIsTemporary(src_slot);

    /* Get the LSN positions from source slot */
    SpinLockAcquire(&src_slot->mutex);
    restart_lsn = src_slot->data.restart_lsn;
    confirm_lsn = src_slot->data.confirmed_flush;
    SpinLockRelease(&src_slot->mutex);

    /* Create the new slot */
    ReplicationSlotCreate(NameStr(*dst_slot_name), true,
                         temporary, RS_PERSISTENT, false);
    dst_slot = MyReplicationSlot;

    /* Set the LSN positions */
    SpinLockAcquire(&dst_slot->mutex);
    dst_slot->data.restart_lsn = restart_lsn;
    dst_slot->data.confirmed_flush = confirm_lsn;
    SpinLockRelease(&dst_slot->mutex);

    /* Mark slot as dirty and save to disk */
    ReplicationSlotMarkDirty();
    ReplicationSlotSave();

    /* Release both slots */
    ReplicationSlotRelease();
    if (src_slot != dst_slot)
        ReplicationSlotRelease();

    PG_RETURN_VOID();
}

Datum
pg_copy_logical_replication_slot(PG_FUNCTION_ARGS)
{
    Name        src_slot_name = PG_GETARG_NAME(0);
    Name        dst_slot_name = PG_GETARG_NAME(1);
    bool        is_temp = PG_ARGISNULL(2) ? false : PG_GETARG_BOOL(2);
    text       *plugin = PG_ARGISNULL(3) ? NULL : PG_GETARG_TEXT_PP(3);
    bool        failover = false; /* always false as per requirements */
    ReplicationSlot *src_slot;
    ReplicationSlot *dst_slot;
    XLogRecPtr    restart_lsn;
    XLogRecPtr    confirmed_flush;
    char       *plugin_name = NULL;

    /* Check permissions */
    if (!superuser() && !has_rolreplication(GetUserId()))
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                 errmsg("must be superuser or replication role to copy a replication slot")));

    /* Acquire slot mutex to prevent concurrent changes */
    LWLockAcquire(ReplicationSlotControlLock, LW_EXCLUSIVE);

    /* Look up source slot */
    src_slot = SearchNamedReplicationSlot(NameStr(*src_slot_name), true);
    if (!src_slot)
        ereport(ERROR,
                (errcode(ERRCODE_UNDEFINED_OBJECT),
                 errmsg("replication slot \"%s\" does not exist", NameStr(*src_slot_name))));

    /* Check if source slot is logical */
    if (!SlotIsLogical(src_slot))
        ereport(ERROR,
                (errcode(ERRCODE_WRONG_OBJECT_TYPE),
                 errmsg("cannot copy a physical replication slot")));

    /* Check if source slot is invalidated */
    if (src_slot->data.invalid)
        ereport(ERROR,
                (errcode(ERRCODE_OBJECT_NOT_IN_PREREQUISITE_STATE),
                 errmsg("cannot copy an invalidated replication slot")));

    /* Get plugin name - use source's if not specified */
    if (plugin)
        plugin_name = text_to_cstring(plugin);
    else
        plugin_name = pstrdup(NameStr(src_slot->data.plugin));

    /* Get LSN positions from source slot */
    restart_lsn = src_slot->data.restart_lsn;
    confirmed_flush = src_slot->data.confirmed_flush;

    /* Create new slot */
    dst_slot = CreateReplicationSlot(NameStr(*dst_slot_name),
                                    plugin_name,
                                    is_temp,
                                    RS_PERSISTENT,
                                    false, /* not failover */
                                    restart_lsn,
                                    confirmed_flush);

    /* Release resources */
    LWLockRelease(ReplicationSlotControlLock);
    if (plugin_name)
        pfree(plugin_name);

    PG_RETURN_VOID();
}

