#include "postgres.h"
#include "fmgr.h"
#include "access/xact.h"
#include "replication/logical.h"
#include "replication/logicalfuncs.h"
#include "replication/slot.h"
#include "utils/builtins.h"
#include "utils/pg_lsn.h"

PG_FUNCTION_INFO_V1(pg_logical_slot_get_changes);

Datum
pg_logical_slot_get_changes(PG_FUNCTION_ARGS)
{
	Name		slot_name = PG_GETARG_NAME(0);
	PG_LSN		upto_lsn;
	int64		upto_nchanges;
	bool		upto_lsn_null;
	bool		upto_nchanges_null;
	ReturnSetInfo *rsinfo = (ReturnSetInfo *) fcinfo->resultinfo;
	MemoryContext per_query_ctx;
	MemoryContext oldcontext;
	LogicalDecodingContext *ctx;
	XLogRecPtr	start_lsn;
	XLogRecPtr	end_lsn;
	bool		failover_slot = false;

	if (PG_ARGISNULL(1))
	{
		upto_lsn_null = true;
		upto_lsn = InvalidXLogRecPtr;
	}
	else
	{
		upto_lsn_null = false;
		upto_lsn = PG_GETARG_LSN(1);
	}

	if (PG_ARGISNULL(2))
	{
		upto_nchanges_null = true;
		upto_nchanges = 0;
	}
	else
	{
		upto_nchanges_null = false;
		upto_nchanges = PG_GETARG_INT64(2);
	}

	CheckLogicalDecodingRequirements();

	/* check if this is a failover slot */
	if (get_logical_slot_failover(NameStr(*slot_name)))
		failover_slot = true;

	/* failover slots require special handling */
	if (failover_slot)
	{
		if (!upto_lsn_null || !upto_nchanges_null)
			eleog(ERROR, "cannot specify LSN or nchanges limit for failover slots");

		/* wait until all standby slots have caught up */
		logical_slot_wait_failover(NameStr(*slot_name));
	}

	/* Build a tuplestore to hold the result rows */
	per_query_ctx = rsinfo->econtext->ecxt_per_query_memory;
	oldcontext = MemoryContextSwitchTo(per_query_ctx);

	rsinfo->returnMode = SFRM_Materialize;
	rsinfo->setResult = tuplestore_begin_heap(true, false, work_mem);
	rsinfo->setDesc = CreateTemplateTupleDesc(3);
	TupleDescInitEntry(rsinfo->setDesc, 1, "lsn", LSNOID, -1, 0);
	TupleDescInitEntry(rsinfo->setDesc, 2, "xid", XIDOID, -1, 0);
	TupleDescInitEntry(rsinfo->setDesc, 3, "data", TEXTOID, -1, 0);

	MemoryContextSwitchTo(oldcontext);

	/* Start logical decoding */
	ctx = CreateDecodingContext(NameStr(*slot_name),
							   upto_lsn_null ? InvalidXLogRecPtr : upto_lsn,
							   upto_nchanges_null ? -1 : upto_nchanges,
							   false,
							   logical_decode_change,
							   NULL,
							   NULL);

	/* Decode until we reach the end of WAL or the specified LSN */
	start_lsn = ctx->reader->ReadRecPtr;
	while (true)
	{
		XLogRecord *record;
		XLogReaderState *state;

		record = XLogReadRecord(ctx->reader, &end_lsn);
		if (record == NULL)
			break;

		state = ctx->reader;
		LogicalDecodeProcessRecord(ctx, state);

		if (!upto_lsn_null && end_lsn >= upto_lsn)
			break;

		if (!upto_nchanges_null && ctx->nchanges >= upto_nchanges)
			break;
	}

	FreeDecodingContext(ctx);

	PG_RETURN_VOID();
}

