PG_FUNCTION_INFO_V1(pg_logical_slot_get_binary_changes);

Datum
pg_logical_slot_get_binary_changes(PG_FUNCTION_ARGS)
{
    Name        slot_name = PG_GETARG_NAME(0);
    XLogRecPtr  upto_lsn = PG_GETARG_LSN(1);
    int64       upto_nchanges = PG_ARGISNULL(2) ? -1 : PG_GETARG_INT64(2);
    bool        confirm = PG_GETARG_BOOL(3);
    ReturnSetInfo *rsinfo = (ReturnSetInfo *) fcinfo->resultinfo;
    MemoryContext per_query_ctx;
    MemoryContext oldcontext;
    TupleDesc    tupdesc;
    Tuplestorestate *tupstore;
    LogicalDecodingContext *ctx;
    ResourceOwner old_resowner = CurrentResourceOwner;
    ReorderBuffer *rb;
    ReorderBufferTXN *txn;
    ReorderBufferChange *change;
    XLogRecPtr  start_lsn;
    XLogRecPtr  end_lsn;
    XLogRecPtr  prev_lsn = InvalidXLogRecPtr;
    int64       nr_changes = 0;
    bool        need_tuplestore_reset = false;

    check_permissions();

    if (PG_ARGISNULL(0))
        PG_RETURN_NULL();

    if (RS_is_assign_rsinfo(fcinfo->resultinfo))
        rsinfo = (ReturnSetInfo *) fcinfo->resultinfo;

    per_query_ctx = rsinfo->econtext->ecxt_per_query_memory;
    oldcontext = MemoryContextSwitchTo(per_query_ctx);

    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    tupstore = tuplestore_begin_heap(true, false, work_mem);
    rsinfo->returnMode = SFRM_Materialize;
    rsinfo->setResult = tupstore;
    rsinfo->setDesc = tupdesc;

    MemoryContextSwitchTo(oldcontext);

    ctx = CreateDecodingContext(NameStr(*slot_name),
                               upto_lsn,
                               XL_ROUTINE(.page_read = read_local_xlog_page,
                                          .segment_open = wal_segment_open,
                                          .segment_close = wal_segment_close),
                               true, /* binary */
                               LogicalOutputPrepareWrite,
                               LogicalOutputWrite, NULL);

    rb = ctx->reorder;
    start_lsn = ctx->reader->EndRecPtr;

    PG_TRY();
    {
        while ((nr_changes < upto_nchanges || upto_nchanges < 0) &&
               (change = ReorderBufferIterate(rb, &start_lsn, &end_lsn, &txn)))
        {
            bool        isnull;
            Datum       values[4];

            if (change->action == REORDER_BUFFER_CHANGE_INTERNAL_SNAPSHOT)
                continue;

            if (change->action == REORDER_BUFFER_CHANGE_INTERNAL_COMMAND_ID)
                continue;

            if (change->action == REORDER_BUFFER_CHANGE_INTERNAL_TUPLECID)
                continue;

            if (change->action == REORDER_BUFFER_CHANGE_INTERNAL_SPEC_CONFIRM)
                continue;

            if (change->action == REORDER_BUFFER_CHANGE_INTERNAL_SPEC_ABORT)
                continue;

            if (change->lsn <= prev_lsn)
                continue;

            prev_lsn = change->lsn;

            if (change->lsn > upto_lsn)
                break;

            values[0] = LSNGetDatum(change->lsn);
            values[1] = CStringGetTextDatum(timestamptz_to_str(change->xact_time));
            values[2] = CStringGetTextDatum(_LogicalDecodeGetChangeTypeName(change->action));
            values[3] = PointerGetDatum(cstring_to_text_with_len(change->data, change->len));

            isnull = false;

            tuplestore_putvalues(tupstore, tupdesc, values, &isnull);

            nr_changes++;
        }

        if (confirm && nr_changes > 0)
            ReplicationSlotAdvance(ctx->slot, prev_lsn);
    }
    PG_CATCH();
    {
        if (ctx)
            FreeDecodingContext(ctx);
        PG_RE_THROW();
    }
    PG_END_TRY();

    FreeDecodingContext(ctx);

    tuplestore_donestoring(tupstore);

    PG_RETURN_NULL();
}

#include "postgres.h"
#include "fmgr.h"
#include "funcapi.h"
