#include "utils/pg_lsn.h"

PG_FUNCTION_INFO_V1(pg_logical_slot_peek_binary_changes);

Datum
pg_logical_slot_peek_binary_changes(PG_FUNCTION_ARGS)
{
    Name        slot_name = PG_GETARG_NAME(0);
    XLogRecPtr    upto_lsn = InvalidXLogRecPtr;
    int64        upto_nchanges = 0;
    bool        upto_nchanges_given = false;
    bool        confirm = false;
    ReturnSetInfo *rsinfo = (ReturnSetInfo *) fcinfo->resultinfo;
    MemoryContext oldcontext;
    TupleDesc    tupdesc;
    Tuplestorestate *tupstore;
    LogicalDecodingContext *ctx;
    ResourceOwner old_resowner = CurrentResourceOwner;
    ReplicationSlot *slot;

    if (PG_ARGISNULL(1))
        upto_lsn = InvalidXLogRecPtr;
    else
        upto_lsn = PG_GETARG_LSN(1);

    if (PG_NARGS() >= 3 && !PG_ARGISNULL(2))
    {
        upto_nchanges = PG_GETARG_INT64(2);
        upto_nchanges_given = true;
    }

    if (PG_NARGS() >= 4 && !PG_ARGISNULL(3))
    {
        if (PG_GETARG_BOOL(3))
            ereport(ERROR,
                    (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                    errmsg("confirm option is not supported in peek mode"));
    }

    /* check to see if caller supports us returning a tuplestore */
    if (rsinfo == NULL || !IsA(rsinfo, ReturnSetInfo))
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                 errmsg("set-valued function called in context that cannot accept a set")));
    if (!(rsinfo->allowedModes & SFRM_Materialize))
        ereport(ERROR,
                (errcode(ERRCODE_FEATURE_NOT_SUPPORTED),
                 errmsg("materialize mode required, but it is not allowed in this context")));

    /* Build a tuple descriptor for our result type */
    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    /* Build tuplestore to hold the result rows */
    oldcontext = MemoryContextSwitchTo(rsinfo->econtext->ecxt_per_query_memory);
    tupstore = tuplestore_begin_heap(true, false, work_mem);
    rsinfo->returnMode = SFRM_Materialize;
    rsinfo->setResult = tupstore;
    rsinfo->setDesc = tupdesc;
    MemoryContextSwitchTo(oldcontext);

    /* Acquire replication slot */
    slot = SearchNamedReplicationSlot(NameStr(*slot_name), true);

    /* setup decoding context which will do the actual work */
    ctx = CreateDecodingContext(slot->data.database,
                               GetDecodingContextRequirement(),
                               false, /* fast forward */
                               false, /* just catalog changes */
                               LogicalOutputPrepareBinary, NULL, NULL);

    /* register callback for each change */
    ctx->stream_change = pg_logical_slot_peek_binary_cb;
    ctx->stream_wal = true;
    ctx->stream_private = tupstore;

    /* do the actual decoding work */
    DecodingContextFindStartpoint(ctx);
    LogicalDecodingProcessRecord(ctx);

    /* clean up */
    FreeDecodingContext(ctx);
    ReplicationSlotRelease();
    CurrentResourceOwner = old_resowner;

    return (Datum) 0;
}

static void
pg_logical_slot_peek_binary_cb(LogicalDecodingContext *ctx,
                              ReorderBufferTXN *txn,
                              XLogRecPtr lsn,
                              bool last_lsn,
                              bool is_catalog_change,
                              ReorderBufferChange *change)
{
    Tuplestorestate *tupstore = (Tuplestorestate *) ctx->stream_private;
    HeapTuple    tuple;
    Datum        values[3];
    bool        nulls[3] = {false};

    if (is_catalog_change)
        return;

    values[0] = LSNGetDatum(lsn);
    values[1] = TimestampTzGetDatum(change->xact_time);
    values[2] = PointerGetDatum(cstring_to_text_with_len(change->data,
                               change->len));

    tuple = heap_form_tuple(ctx->outdesc, values, nulls);
    tuplestore_puttuple(tupstore, tuple);
}

