Datum
pg_logical_emit_message(PG_FUNCTION_ARGS)
{
    bool        transactional = PG_GETARG_BOOL(0);
    text       *prefix = PG_GETARG_TEXT_PP(1);
    text       *content = PG_GETARG_TEXT_PP(2);
    bool        flush = false;

    if (PG_NARGS() > 3)
        flush = PG_GETARG_BOOL(3);

    if (transactional && flush)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                errmsg("flush has no effect with transactional messages"));

    ReplicationMessage *message = palloc(sizeof(ReplicationMessage));
    message->transactional = transactional;
    message->prefix = text_to_cstring(prefix);
    message->content = VARDATA_ANY(content);
    message->content_size = VARSIZE_ANY_EXHDR(content);

    LogLogicalMessage(message, flush);

    PG_RETURN_VOID();
}

