static int64
database_size(Oid dbOid)
{
    int64        size = 0;
    char       *path;
    struct stat st;

    /* User must have connect privilege or pg_read_all_stats role */
    if (!has_privs_of_role(GetUserId(), ROLE_PG_READ_ALL_STATS) &&
        !has_privs_of_role(GetUserId(), DEFAULT_ROLE_CONN)) {
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                 errmsg("must have CONNECT privilege on the database or be member of pg_read_all_stats role")));
    }

    path = GetDatabasePath(dbOid, InvalidBackendId);

    if (stat(path, &st) == 0)
    {
        if (S_ISDIR(st.st_mode))
            size = db_dir_size(path);
    }
    else
    {
        if (errno != ENOENT)
            ereport(ERROR,
                    (errcode_for_file_access(),
                     errmsg("could not stat database directory \"%s\": %m",
                            path)));
    }

    pfree(path);
    return size;
}

