Datum
pg_relation_size(PG_FUNCTION_ARGS)
{
    Oid            relOid = PG_GETARG_OID(0);
    text       *forkName = NULL;
    ForkNumber    forkNum = MAIN_FORKNUM;
    Relation    rel;
    int64        size;

    if (PG_NARGS() >= 2)
    {
        forkName = PG_GETARG_TEXT_PP(1);
        if (pg_strcasecmp(text_to_cstring(forkName), "main") == 0)
            forkNum = MAIN_FORKNUM;
        else if (pg_strcasecmp(text_to_cstring(forkName), "fsm") == 0)
            forkNum = FSM_FORKNUM;
        else if (pg_strcasecmp(text_to_cstring(forkName), "vm") == 0)
            forkNum = VISIBILITYMAP_FORKNUM;
        else if (pg_strcasecmp(text_to_cstring(forkName), "init") == 0)
            forkNum = INIT_FORKNUM;
        else
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                     errmsg("invalid fork name"),
                     errhint("Valid fork names are \"main\", \"fsm\", \"vm\", and \"init\".")));
    }

    rel = try_relation_open(relOid, AccessShareLock);
    if (rel == NULL)
        PG_RETURN_NULL();

    size = RelationGetNumberOfBlocksInFork(rel, forkNum) * BLCKSZ;

    relation_close(rel, AccessShareLock);

    PG_RETURN_INT64(size);
}

#include "postgres.h"
#include "utils/builtins.h"
#include "utils/numeric.h"
#include "utils/formatting.h"

Datum
pg_size_bytes(PG_FUNCTION_ARGS)
{
    text *size_text = PG_GETARG_TEXT_PP(0);
    char *size_str = text_to_cstring(size_text);
    char *endptr;
    double size;
    int64 result;
    char unit[3] = {0};

    /* Parse the number part */
    size = strtod(size_str, &endptr);
    if (endptr == size_str)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid size: %s", size_str)));

    /* Skip any whitespace between number and unit */
    while (*endptr != '\0' && isspace((unsigned char) *endptr))
        endptr++;

    /* Parse the unit part */
    if (*endptr != '\0')
    {
        if (strlen(endptr) > 2)
            ereport(ERROR,
                    (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                    errmsg("invalid size unit: %s", endptr)));

        strncpy(unit, endptr, 2);
        unit[2] = '\0';
    }

    /* Convert to bytes based on unit */
    if (unit[0] == '\0' || strcmp(unit, "bytes") == 0 || strcmp(unit, "B") == 0)
    {
        result = (int64) size;
    }
    else if (strcmp(unit, "kB") == 0)
    {
        result = (int64) (size * 1024);
    }
    else if (strcmp(unit, "MB") == 0)
    {
        result = (int64) (size * 1024 * 1024);
    }
    else if (strcmp(unit, "GB") == 0)
    {
        result = (int64) (size * 1024 * 1024 * 1024);
    }
    else if (strcmp(unit, "TB") == 0)
    {
        result = (int64) (size * 1024LL * 1024 * 1024 * 1024);
    }
    else if (strcmp(unit, "PB") == 0)
    {
        result = (int64) (size * 1024LL * 1024 * 1024 * 1024 * 1024);
    }
    else
    {
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("invalid size unit: %s", unit)));
    }

    PG_RETURN_INT64(result);
}

#include "postgres.h"
#include "utils/builtins.h"
#include "utils/numeric.h"
#include "utils/int8.h"

#define PG_SIZE_PRETTY_UNITS 6
static const char *const size_units[] = {
	"bytes", "kB", "MB", "GB", "TB", "PB"
};

Datum
pg_size_pretty(PG_FUNCTION_ARGS)
{
	int64		bytes = PG_GETARG_INT64(0);
	int			unit_idx = 0;
	float8		size = bytes;

	while (size >= 1024 && unit_idx < PG_SIZE_PRETTY_UNITS - 1)
	{
		size /= 1024;
		unit_idx++;
	}

	if (unit_idx == 0)
		PG_RETURN_TEXT_P(cstring_to_text(psprintf("%ld bytes", bytes)));
	else
		PG_RETURN_TEXT_P(cstring_to_text(psprintf("%.2f %s", size, size_units[unit_idx])));
}

Datum
pg_size_pretty_numeric(PG_FUNCTION_ARGS)
{
	Numeric bytes = PG_GETARG_NUMERIC(0);
	Numeric size = NumericGetDatum(bytes);
	Numeric divisor = int64_to_numeric(1024);
	int		unit_idx = 0;
	const int max_unit_idx = PG_SIZE_PRETTY_UNITS - 1;

	while (unit_idx < max_unit_idx)
	{
		Numeric new_size = numeric_div_opt_error(size, divisor, NULL);
		if (new_size == NULL || numeric_cmp(new_size, divisor) < 0)
			break;

		size = new_size;
		unit_idx++;
	}

	if (unit_idx == 0)
	{
		char *str = numeric_to_cstring(bytes);
		PG_RETURN_TEXT_P(cstring_to_text(psprintf("%s bytes", str)));
	}
	else
	{
		char *size_str = numeric_to_cstring(size);
		PG_RETURN_TEXT_P(cstring_to_text(psprintf("%s %s", size_str, size_units[unit_idx])));
	}
}

