PG_FUNCTION_INFO_V1(pg_table_size);

Datum
pg_table_size(PG_FUNCTION_ARGS)
{
    Oid            relOid = PG_GETARG_OID(0);
    Relation    rel;
    int64        size = 0;

    rel = try_relation_open(relOid, AccessShareLock);
    if (rel == NULL)
        PG_RETURN_NULL();

    /* Calculate total table size (main fork + toast if any + FSM + VM) */
    size += calculate_table_size(rel);

    relation_close(rel, AccessShareLock);

    PG_RETURN_INT64(size);
}

static int64
calculate_table_size(Relation rel)
{
    int64        size = 0;

    /* Main fork */
    size += RelationGetNumberOfBlocks(rel) * BLCKSZ;

    /* TOAST table if any */
    if (rel->rd_rel->reltoastrelid)
    {
        Relation    toastrel;

        toastrel = relation_open(rel->rd_rel->reltoastrelid, AccessShareLock);
        size += RelationGetNumberOfBlocks(toastrel) * BLCKSZ;
        relation_close(toastrel, AccessShareLock);
    }

    /* Free Space Map */
    size += calculate_relation_fork_size(rel, FSM_FORKNUM);

    /* Visibility Map */
    size += calculate_relation_fork_size(rel, VISIBILITYMAP_FORKNUM);

    return size;
}

static int64
calculate_relation_fork_size(Relation rel, ForkNumber forkNum)
{
    int64        size = 0;
    BlockNumber nblocks;

    nblocks = RelationGetNumberOfBlocksInFork(rel, forkNum);
    if (nblocks > 0)
        size += nblocks * BLCKSZ;

    return size;
}

