static int64
tablespace_size(Oid tblspc_oid)
{
    char       *path;
    int64        size = 0;
    DIR           *dirdesc;
    struct dirent *de;

    /* User must have CREATE privilege or pg_read_all_stats role */
    if (tblspc_oid != MyDatabaseTableSpace &&
        !pg_tablespace_ownercheck(tblspc_oid, GetUserId()) &&
        !has_privs_of_role(GetUserId(), ROLE_PG_READ_ALL_STATS))
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                 errmsg("must be owner of tablespace %u or have privileges of the pg_read_all_stats role",
                        tblspc_oid)));

    path = GetDatabasePath(MyDatabaseId, tblspc_oid);

    dirdesc = AllocateDir(path);
    if (dirdesc == NULL)
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not open directory "%s": %m",
                        path)));

    while ((de = ReadDir(dirdesc, path)) != NULL)
    {
        char       *subpath;
        struct stat fst;

        if (strcmp(de->d_name, ".") == 0 ||
            strcmp(de->d_name, "..") == 0)
            continue;

        subpath = psprintf("%s/%s", path, de->d_name);

        if (lstat(subpath, &fst) < 0)
        {
            FreeDir(dirdesc);
            pfree(subpath);
            pfree(path);
            ereport(ERROR,
                    (errcode_for_file_access(),
                     errmsg("could not stat file "%s": %m",
                            subpath)));
        }

        size += fst.st_size;
        pfree(subpath);
    }

    FreeDir(dirdesc);
    pfree(path);

    return size;
}

Datum
pg_tablespace_size_oid(PG_FUNCTION_ARGS)
{
    Oid            tblspcOid = PG_GETARG_OID(0);
