/*
 * CREATE COLLATION
 */
Datum
pg_import_system_collations(PG_FUNCTION_ARGS)
{
    Oid            schemaoid = PG_GETARG_OID(0);
    int            ncreated = 0;
    char       **locales;
    int            nlocales;
    int            i;

    if (!superuser())
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                 errmsg("must be superuser to import system collations")));

    /* Get the list of locales from the operating system */
    nlocales = pg_get_encoding_locales(PG_SQL_ASCII, &locales);

    /* Add each locale as a collation */
    for (i = 0; i < nlocales; i++)
    {
        char       *locale = locales[i];
        Oid            collid;
        Datum        values[Natts_pg_collation];
        bool        nulls[Natts_pg_collation];
        HeapTuple    tuple;


        /* Skip if already exists */
        collid = GetSysCacheOid3(COLLNAMEENCNSP,
                                 PointerGetDatum(locale),
                                 Int32GetDatum(PG_SQL_ASCII),
                                 ObjectIdGetDatum(schemaoid));
        if (OidIsValid(collid))
            continue;

        /* Prepare the tuple for pg_collation */
        MemSet(values, 0, sizeof(values));
        MemSet(nulls, false, sizeof(nulls));

        values[Anum_pg_collation_collname - 1] = CStringGetTextDatum(locale);
        values[Anum_pg_collation_collnamespace - 1] = ObjectIdGetDatum(schemaoid);
        values[Anum_pg_collation_collowner - 1] = ObjectIdGetDatum(GetUserId());
        values[Anum_pg_collation_collencoding - 1] = Int32GetDatum(PG_SQL_ASCII);
        values[Anum_pg_collation_collcollate - 1] = CStringGetTextDatum(locale);
        values[Anum_pg_collation_collctype - 1] = CStringGetTextDatum(locale);
        nulls[Anum_pg_collation_colliculocale - 1] = true;
        nulls[Anum_pg_collation_collversion - 1] = true;

        tuple = heap_form_tuple(RelationGetDescr(RelationIdGetRelation(PG_COLLATION_OID)),
                               values, nulls);

        /* Insert the tuple */
        collid = CatalogTupleInsert(RelationIdGetRelation(PG_COLLATION_OID), tuple);

        heap_freetuple(tuple);

        /* Make sure the tuple is visible */
        CommandCounterIncrement();

        ncreated++;
    }

    /* Free the locales list */
    for (i = 0; i < nlocales; i++)
        pfree(locales[i]);
    pfree(locales);

    PG_RETURN_INT32(ncreated);
}

