PG_FUNCTION_INFO_V1(brin_summarize_range);

Datum
brin_summarize_range(PG_FUNCTION_ARGS)
{
    Oid         indexOid = PG_GETARG_OID(0);
    BlockNumber heapBlk = PG_GETARG_UINT32(1);
    Relation    indexRel;
    BrinRevmap *revmap;
    BrinDesc   *bdesc;
    BlockNumber pagesPerRange;
    BlockNumber heapRange;
    bool        done = false;
    bool        summarized = false;

    indexRel = index_open(indexOid, AccessShareLock);

    if (!IS_BRIN(indexRel))
        ereport(ERROR,
                (errcode(ERRCODE_WRONG_OBJECT_TYPE),
                 errmsg("relation \"%s\" is not a BRIN index",
                        RelationGetRelationName(indexRel))));

    bdesc = brin_build_desc(indexRel);
    pagesPerRange = BrinGetPagesPerRange(indexRel);
    heapRange = heapBlk / pagesPerRange;

    revmap = brinRevmapInitialize(indexRel, &pagesPerRange, NULL);

    /* Check if the range is already summarized */
    if (!brin_summarize_range_if_needed(indexRel, revmap, bdesc, heapRange, &done))
    {
        /* Summarize the range */
        summarized = brin_do_summarize_range(indexRel, revmap, bdesc, heapRange, &done);
    }

    brinRevmapTerminate(revmap);
    brin_free_desc(bdesc);
    index_close(indexRel, AccessShareLock);

    PG_RETURN_BOOL(summarized);
}

