#include "access/htup_details.h"
#include "access/relscan.h"
#include "miscadmin.h"
#include "utils/rel.h"

void
brin_remove_tuple_for_block(Relation idxrel, BlockNumber heapBlk)
{
    Buffer        buf;
    OffsetNumber off;
    BrinRevmap   *revmap;
    BrinTuple    *tup;
    ItemPointerData tid;

    revmap = brinRevmapInitialize(idxrel, NULL);

    /* Find the BRIN tuple for the given heap block */
    brinRevmapExtend(revmap, heapBlk);
    brinGetTupleForHeapBlock(revmap, heapBlk, &buf, &off, &tid, NULL);

    if (!ItemPointerIsValid(&tid))
    {
        /* No tuple exists for this block range */
        brinRevmapTerminate(revmap);
        return;
    }

    /* Lock the buffer containing the tuple */
    LockBuffer(buf, BUFFER_LOCK_EXCLUSIVE);

    /* Get the tuple */
    tup = (BrinTuple *) PageGetItem(BufferGetPage(buf),
                                  PageGetItemId(BufferGetPage(buf), off));

    /* Mark the tuple as deleted */
    BRIN_TUPLE_MARK_DEAD(tup);

    /* Write WAL record if needed */
    if (RelationNeedsWAL(idxrel))
    {
        xl_brin_delete xlrec;
        XLogRecPtr    recptr;

        xlrec.pagesPerRange = revmap->rm_pagesPerRange;
        xlrec.heapBlk = heapBlk;
        xlrec.offnum = off;

        XLogBeginInsert();
        XLogRegisterData((char *) &xlrec, SizeOfBrinDelete);
        XLogRegisterBuffer(0, buf, REGBUF_STANDARD);

        recptr = XLogInsert(RM_BRIN_ID, XLOG_BRIN_DELETE);
        PageSetLSN(BufferGetPage(buf), recptr);
    }

    MarkBufferDirty(buf);
    UnlockReleaseBuffer(buf);
    brinRevmapTerminate(revmap);
}

