/*
 * ginCleanupPendingList - clean up the pending list of the specified GIN index
 *
 * This function moves entries from the pending list to the main GIN data structure.
 * Returns the number of pages removed from the pending list. If the index was
 * built with fastupdate disabled, returns 0.
 */
int64
ginCleanupPendingList(Relation index)
{
    GinState   ginstate;
    int64        count = 0;

    /* Quick exit if fastupdate is disabled */
    if (!GinGetUseFastUpdate(index))
        return 0;

    initGinState(&ginstate, index);

    /* Lock the index to prevent concurrent inserts */
    LockRelationForExtension(index, ExclusiveLock);
    UnlockRelationForExtension(index, ExclusiveLock);

    /* Do the actual cleanup */
    count = ginInsertCleanup(&ginstate, GIN_CLEANUP, true, NULL, NULL);

    return count;
}

