Datum
pg_ls_dir(PG_FUNCTION_ARGS)
{
    text       *location = PG_GETARG_TEXT_PP(0);
    bool        include_dot_dirs = false;
    bool        missing_ok = false;
    char       *location_str;
    DIR        *dirdesc;
    struct dirent *de;
    FuncCallContext *funcctx;

    if (PG_NARGS() > 1)
        include_dot_dirs = PG_GETARG_BOOL(1);
    if (PG_NARGS() > 2)
        missing_ok = PG_GETARG_BOOL(2);

    location_str = text_to_cstring(location);

    if (!superuser())
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                 errmsg("must be superuser to list directory contents")));

    if (SRF_IS_FIRSTCALL())
    {
        MemoryContext oldcontext;
        TupleDesc    tupdesc;

        funcctx = SRF_FIRSTCALL_INIT();
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

        tupdesc = CreateTemplateTupleDesc(1);
        TupleDescInitEntry(tupdesc, (AttrNumber) 1, "pg_ls_dir",
                          TEXTOID, -1, 0);
        funcctx->tuple_desc = BlessTupleDesc(tupdesc);

        dirdesc = AllocateDir(location_str);
        if (!dirdesc)
        {
            if (missing_ok && errno == ENOENT)
                SRF_RETURN_DONE(funcctx);
            else
                ereport(ERROR,
                        (errcode_for_file_access(),
                         errmsg("could not open directory \"%s\": %m",
                                location_str)));
        }

        funcctx->user_fctx = dirdesc;
        MemoryContextSwitchTo(oldcontext);
    }

    funcctx = SRF_PERCALL_SETUP();
    dirdesc = (DIR *) funcctx->user_fctx;

    while ((de = ReadDir(dirdesc, location_str)) != NULL)
    {
        if (!include_dot_dirs &&
            (strcmp(de->d_name, ".") == 0 ||
             strcmp(de->d_name, "..") == 0))
            continue;

        SRF_RETURN_NEXT(funcctx,
                        CStringGetTextDatum(de->d_name));
    }

    FreeDir(dirdesc);
    SRF_RETURN_DONE(funcctx);
}

