PG_FUNCTION_INFO_V1(pg_logdir_ls);

Datum
pg_logdir_ls(PG_FUNCTION_ARGS)
{
    FuncCallContext *funcctx;
    DIR           *dirdesc;
    struct dirent *de;
    MemoryContext oldcontext;

    if (SRF_IS_FIRSTCALL())
    {
        TupleDesc    tupdesc;

        /* check if we have permission to access log directory */
        if (!superuser() && !has_privs_of_role(GetUserId(), ROLE_PG_MONITOR))
            ereport(ERROR,
                    (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                     errmsg("must be superuser or a member of the pg_monitor role to use this function")));

        /* create a function context for cross-call persistence */
        funcctx = SRF_FIRSTCALL_INIT();

        /* switch to memory context appropriate for multiple function calls */
        oldcontext = MemoryContextSwitchTo(funcctx->multi_call_memory_ctx);

        /* build tupdesc for result tuples */
        tupdesc = CreateTemplateTupleDesc(3);
        TupleDescInitEntry(tupdesc, (AttrNumber) 1, "name",
                           TEXTOID, -1, 0);
        TupleDescInitEntry(tupdesc, (AttrNumber) 2, "size",
                           INT8OID, -1, 0);
        TupleDescInitEntry(tupdesc, (AttrNumber) 3, "modification",
                           TIMESTAMPTZOID, -1, 0);

        funcctx->tuple_desc = BlessTupleDesc(tupdesc);

        /* open the log directory */
        dirdesc = AllocateDir(Log_directory);
        if (dirdesc == NULL)
            ereport(ERROR,
                    (errcode_for_file_access(),
                     errmsg("could not open log directory \"%s\": %m",
                            Log_directory)));

        funcctx->user_fctx = dirdesc;
        MemoryContextSwitchTo(oldcontext);
    }

    /* stuff done on every call of the function */
    funcctx = SRF_PERCALL_SETUP();
    dirdesc = (DIR *) funcctx->user_fctx;

    while ((de = ReadDir(dirdesc, Log_directory)) != NULL)
    {
        char        path[MAXPGPATH];
        struct stat attrib;
        HeapTuple   tuple;
        Datum       values[3];
        bool        nulls[3] = {false, false, false};

        /* skip hidden files, directories and special files */
        if (de->d_name[0] == '.')
            continue;

        snprintf(path, sizeof(path), "%s/%s", Log_directory, de->d_name);

        if (lstat(path, &attrib) < 0)
        {
            /* ignore any files we can't stat */
            continue;
        }

        if (!S_ISREG(attrib.st_mode))
            continue;

        /* build and return the tuple */
        values[0] = CStringGetTextDatum(de->d_name);
        values[1] = Int64GetDatum((int64) attrib.st_size);
        values[2] = TimestampTzGetDatum(time_t_to_timestamptz(attrib.st_mtime));

        tuple = heap_form_tuple(funcctx->tuple_desc, values, nulls);

        SRF_RETURN_NEXT(funcctx, HeapTupleGetDatum(tuple));
    }

    /* close the directory and we're done */
    FreeDir(dirdesc);
    SRF_RETURN_DONE(funcctx);
}

