    if (!superuser())
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                 errmsg("must be superuser to read files")));

    filename = text_to_cstring(filename_t);

    file = AllocateFile(filename, "rb");
    if (file == NULL)
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not open file "%s" for reading: %m",
                        filename)));

    /* Determine file size */
    if (fseeko(file, 0, SEEK_END) != 0)
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not seek to end of file "%s": %m",
                        filename)));

    file_size = ftello(file);
    if (file_size < 0)
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not determine size of file "%s": %m",
                        filename)));

    /* Calculate read offset */
    if (offset < 0)
        read_offset = file_size + offset;
    else
        read_offset = offset;

    if (read_offset < 0)
        read_offset = 0;
    if (read_offset > file_size)
        read_offset = file_size;

    /* Calculate read length */
    if (length < 0 || length > (file_size - read_offset))
        read_length = file_size - read_offset;
    else
        read_length = length;

    /* Return empty string if no bytes to read */
    if (read_length <= 0)
    {
        FreeFile(file);
        pfree(filename);
        PG_RETURN_TEXT_P(cstring_to_text(""));
    }

    /* Allocate buffer and read data */
    buffer = (char *) palloc(read_length + 1);
    if (fseeko(file, read_offset, SEEK_SET) != 0)
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not seek in file "%s": %m",
                        filename)));

    bytes_read = fread(buffer, 1, read_length, file);
    if (bytes_read != read_length && ferror(file))
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not read file "%s": %m",
                        filename)));

    buffer[bytes_read] = '\0';
    FreeFile(file);
    pfree(filename);

    /* Verify the data is valid in the database encoding */
    pg_verifymbstr(buffer, bytes_read, false);

    result = cstring_to_text(buffer);
    pfree(buffer);

    PG_RETURN_TEXT_P(result);
}

