/*
 * Read a section of a file, returning it as bytea
 *
 * We read the whole of the file when bytes_to_read is negative
 */
static bytea *
read_binary_file(const char *filename, int64 seek_offset, int64 bytes_to_read,
               bool missing_ok)
{
    bytea       *result;
    FILE       *file;
    int64       actual_bytes;
    char       *buffer;

    if (bytes_to_read < 0)
    {
        if (seek_offset < 0)
            bytes_to_read = -seek_offset;
        else
        {
            struct stat fst;

            if (stat(filename, &fst) < 0)
            {
                if (missing_ok && errno == ENOENT)
                    return NULL;
                ereport(ERROR,
                        (errcode_for_file_access(),
                         errmsg("could not stat file \"%s\": %m", filename)));
            }

            bytes_to_read = fst.st_size - seek_offset;
        }
    }
    else if (bytes_to_read == 0)
        return NULL;

    if (seek_offset >= 0)
        file = AllocateFile(filename, PG_BINARY_R);
    else
    {
        seek_offset = -seek_offset;
        file = AllocateFile(filename, PG_BINARY_R);
    }

    if (file == NULL)
    {
        if (missing_ok && errno == ENOENT)
            return NULL;
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not open file \"%s\" for reading: %m",
                        filename)));
    }

    if (fseeko(file, (off_t) seek_offset,
               (seek_offset >= 0) ? SEEK_SET : SEEK_END) != 0)
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not seek in file \"%s\": %m", filename)));

    /* check for overflow in buffer size request */
    if (bytes_to_read > (MaxAllocSize - VARHDRSZ))
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("requested length too large")));

    buffer = (char *) palloc((Size) bytes_to_read + VARHDRSZ);
    actual_bytes = fread(VARDATA(buffer), 1, (size_t) bytes_to_read, file);

    /* if we didn't read as much as we expected, check for read error */
    if (actual_bytes < bytes_to_read && ferror(file))
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not read file \"%s\": %m", filename)));

    SET_VARSIZE(buffer, actual_bytes + VARHDRSZ);
    result = (bytea *) buffer;

    FreeFile(file);

    return result;
}


/*
 * Read a section of a file, returning it as bytea
 */
Datum
pg_read_binary_file_off_len(PG_FUNCTION_ARGS)
{
    text       *filename_t = PG_GETARG_TEXT_PP(0);
    int64       seek_offset = PG_GETARG_INT64(1);
    int64       bytes_to_read = PG_GETARG_INT64(2);
    bool        missing_ok = PG_GETARG_BOOL(3);
    char       *filename;
    bytea       *result;

    filename = text_to_cstring(filename_t);

    result = read_binary_file(filename, seek_offset, bytes_to_read, missing_ok);
    if (result == NULL && missing_ok)
        PG_RETURN_NULL();

    PG_RETURN_BYTEA_P(result);
}

/*
 * Read a whole file, returning it as bytea
 */
Datum
pg_read_binary_file_all(PG_FUNCTION_ARGS)
{
    text       *filename_t = PG_GETARG_TEXT_PP(0);
    bool        missing_ok = PG_GETARG_BOOL(1);
    char       *filename;
    bytea       *result;

    filename = text_to_cstring(filename_t);

    result = read_binary_file(filename, 0, -1, missing_ok);
    if (result == NULL && missing_ok)
        PG_RETURN_NULL();

    PG_RETURN_BYTEA_P(result);
}

/*
 * Read a whole file, returning it as bytea (convenience function)
 */
