pg_read_binary_file(PG_FUNCTION_ARGS)
{
    text       *filename_t = PG_GETARG_TEXT_PP(0);
    char       *filename;
    bytea       *result;

    filename = text_to_cstring(filename_t);

    result = read_binary_file(filename, 0, -1, false);

    PG_RETURN_BYTEA_P(result);
}

