Datum
pg_stat_file(PG_FUNCTION_ARGS)
{
    text       *filename_t = PG_GETARG_TEXT_PP(0);
    char       *filename;
    struct stat stat_buf;
    Datum       values[6];
    bool        nulls[6];
    TupleDesc   tupdesc;
    HeapTuple   tuple;
    Datum       result;

    if (!superuser())
        ereport(ERROR,
                (errcode(ERRCODE_INSUFFICIENT_PRIVILEGE),
                (errmsg("must be superuser to use pg_stat_file")));

    filename = text_to_cstring(filename_t);

    if (stat(filename, &stat_buf) < 0)
        ereport(ERROR,
                (errcode_for_file_access(),
                 errmsg("could not stat file \"%s\": %m", filename)));

    MemSet(values, 0, sizeof(values));
    MemSet(nulls, 0, sizeof(nulls));

    values[0] = Int64GetDatum((int64) stat_buf.st_size);
    values[1] = TimestampTzGetDatum(time_t_to_timestamptz(stat_buf.st_atime));
    values[2] = TimestampTzGetDatum(time_t_to_timestamptz(stat_buf.st_mtime));

#ifdef HAVE_STRUCT_STAT_ST_CTIME
    values[3] = TimestampTzGetDatum(time_t_to_timestamptz(stat_buf.st_ctime));
#else
    nulls[3] = true;
#endif

#ifdef WIN32
    values[4] = TimestampTzGetDatum(time_t_to_timestamptz(stat_buf.st_ctime));
#else
    nulls[4] = true;
#endif

    values[5] = BoolGetDatum(S_ISDIR(stat_buf.st_mode));

    if (get_call_result_type(fcinfo, NULL, &tupdesc) != TYPEFUNC_COMPOSITE)
        elog(ERROR, "return type must be a row type");

    tuple = heap_form_tuple(tupdesc, values, nulls);
    result = HeapTupleGetDatum(tuple);

    PG_RETURN_DATUM(result);
}

