/*
 * pg_try_advisory_xact_lock_shared_int8
 *      Acquire a shared transaction-level advisory lock with 64-bit key,
 *      returning true if successful, false if lock not available
 */
Datum
pg_try_advisory_xact_lock_shared_int8(PG_FUNCTION_ARGS)
{
    int64       key = PG_GETARG_INT64(0);
    bool        locked;

    locked = LockAcquireExtended(&(LockTagAdvisoryInt64{key, key}),
                                ShareLock,
                                false,  /* don't wait */
                                true,   /* sessionLock */
                                false,  /* don't check conflicts */
                                NULL);

    PG_RETURN_BOOL(locked);
}

