#include "postgres.h"
#include "fmgr.h"
#include "catalog/pg_type.h"
#include "tsearch/ts_type.h"
#include "tsearch/ts_utils.h"
#include "utils/builtins.h"
#include "utils/rel.h"
#include "commands/trigger.h"

PG_FUNCTION_INFO_V1(tsvector_update_trigger_bycolumn);

Datum
tsvector_update_trigger_bycolumn(PG_FUNCTION_ARGS)
{
    TriggerData *trigdata = (TriggerData *) fcinfo->context;
    Trigger    *trigger;
    Relation    rel;
    HeapTuple   rettuple;
    TupleDesc   tupdesc;
    Datum       values[1];
    bool        nulls[1];
    bool        replaces[1];
    int         tsv_attr;
    int         config_attr;
    int         i;
    List       *text_columns = NIL;
    ListCell   *lc;
    Oid         cfgId;
    text       *cfgt;
    char       *cfgname;

    if (!CALLED_AS_TRIGGER(fcinfo))
        ereport(ERROR,
                (errcode(ERRCODE_E_R_I_E_TRIGGER_PROTOCOL_VIOLATED),
                 errmsg("tsvector_update_trigger_bycolumn: must be called as trigger")));

    trigger = trigdata->tg_trigger;
    rel = trigdata->tg_relation;
    tupdesc = rel->rd_att;

    if (trigger->tgnargs < 3)
        ereport(ERROR,
                (errcode(ERRCODE_INVALID_PARAMETER_VALUE),
                 errmsg("tsvector_update_trigger_bycolumn: must have at least 3 arguments")));

    /* First arg is name of tsvector column to update */
    tsv_attr = SPI_fnumber(tupdesc, trigger->tgargs[0]);
    if (tsv_attr == SPI_ERROR_NOATTRIBUTE)
        ereport(ERROR,
                (errcode(ERRCODE_UNDEFINED_COLUMN),
                 errmsg("tsvector column \"%s\" does not exist",
                        trigger->tgargs[0])));

    if (TupleDescAttr(tupdesc, tsv_attr - 1)->atttypid != TSVECTOROID)
        ereport(ERROR,
                (errcode(ERRCODE_DATATYPE_MISMATCH),
                 errmsg("column \"%s\" is not of tsvector type",
                        trigger->tgargs[0])));

    /* Second arg is name of regconfig column */
    config_attr = SPI_fnumber(tupdesc, trigger->tgargs[1]);
    if (config_attr == SPI_ERROR_NOATTRIBUTE)
        ereport(ERROR,
                (errcode(ERRCODE_UNDEFINED_COLUMN),
                 errmsg("regconfig column \"%s\" does not exist",
                        trigger->tgargs[1])));

    if (TupleDescAttr(tupdesc, config_attr - 1)->atttypid != REGCONFIGOID)
        ereport(ERROR,
                (errcode(ERRCODE_DATATYPE_MISMATCH),
                 errmsg("column \"%s\" is not of regconfig type",
                        trigger->tgargs[1])));

    /* Remaining args are names of text columns */
    for (i = 2; i < trigger->tgnargs; i++)
    {
        int         text_attr;

        text_attr = SPI_fnumber(tupdesc, trigger->tgargs[i]);
        if (text_attr == SPI_ERROR_NOATTRIBUTE)
            ereport(ERROR,
                    (errcode(ERRCODE_UNDEFINED_COLUMN),
                     errmsg("text column \"%s\" does not exist",
                            trigger->tgargs[i])));

        text_columns = lappend_int(text_columns, text_attr);
    }

    /* Get the config OID from the config column */
    cfgt = DatumGetTextP(SPI_getbinval(trigdata->tg_trigtuple, tupdesc, config_attr, &nulls[0]));
    if (nulls[0])
        ereport(ERROR,
                (errcode(ERRCODE_NULL_VALUE_NOT_ALLOWED),
                 errmsg("regconfig column must not be null")));

    cfgname = text_to_cstring(cfgt);
    cfgId = get_ts_config_oid(stringToQualifiedNameList(cfgname), false);

    /* Build concatenated text from all source columns */
    StringInfoData concat_text;
    initStringInfo(&concat_text);

    foreach(lc, text_columns)
    {
        int         text_attr = lfirst_int(lc);
        Datum       text_val;
        bool        isnull;

        text_val = SPI_getbinval(trigdata->tg_trigtuple, tupdesc, text_attr, &isnull);
        if (!isnull)
        {
            text       *t = DatumGetTextP(text_val);

            if (concat_text->len > 0)
                appendStringInfoChar(&concat_text, ' ');

            appendStringInfoText(&concat_text, t);
        }
    }

    /* Generate tsvector from concatenated text */
    values[0] = TSVectorGetDatum(
        make_tsvector(concat_text.data, concat_text.len, cfgId));
    pfree(concat_text.data);

    nulls[0] = false;
    replaces[0] = true;

    /* Build and return modified tuple */
    rettuple = SPI_modifytuple(rel, trigdata->tg_trigtuple, 1, &tsv_attr, values, nulls, replaces);
    if (rettuple == NULL)
        ereport(ERROR,
                (errcode(ERRCODE_TRIGGERED_DATA_CHANGE_VIOLATION),
                 errmsg("failed to modify row in trigger")));

    PG_RETURN_POINTER(rettuple);
}

