#include "postgres.h"
#include "commands/event_trigger.h"
#include "commands/tablecmds.h"

PG_FUNCTION_INFO_V1(pg_event_trigger_table_rewrite_reason);

Datum
pg_event_trigger_table_rewrite_reason(PG_FUNCTION_ARGS)
{
    Oid         event_oid = PG_GETARG_OID(0);
    int32       reason = 0;
    TableRewriteReasonData *rewrite_reasons;

    if (!EventTriggerSupportsObjectClass(OCLASS_REWRITE))
        PG_RETURN_NULL();

    rewrite_reasons = GetTableRewriteReasons(event_oid);
    if (!rewrite_reasons)
        PG_RETURN_NULL();

    if (rewrite_reasons->changed_persistence)
        reason |= 1;
    if (rewrite_reasons->changed_default)
        reason |= 2;
    if (rewrite_reasons->changed_datatype)
        reason |= 4;
    if (rewrite_reasons->changed_access_method)
        reason |= 8;

    PG_RETURN_INT32(reason);
}
